(774617209, (SELECT id FROM brand WHERE name = '11번가 판매자 10421487' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 언더웨어 > 여성 언더웨어' LIMIT 1), '미스터니플 밴드 104매 대용량 남자 가슴 젖꼭지 패치', 11900, 11030, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/774617209/B.jpg?458000000', 0, '얇은 살구색 메쉬 타원형 니플 패치(니플커버) 104매 대용량 구성으로, 여름철 흰 티셔츠나 얇은 상의를 입을 때 도드라지는 니플을 가려주기 위한 언더웨어소품이다. 반투명 필름 재질에 방수·통기 기능을 내세우며 물에 젖어도 잘 붙어 있는 강한 접착력을 강조한다. 배송이 빠르고 가격 대비 매수가 많아 실사용 만족도가 높다는 후기가 많지만, 접착 강도가 약해 시간이 지나면 니플이 다시 튀어나온다는 불만과 스티커가 접히면 그 부분이 도드라져 보인다는 지적, 흰색 얇은 상의에서는 커버력이 약해 비친다는 저평점 리뷰, 제거할 때 통증이 있다는 후기가 함께 확인된다.', '{"상품유형":"언더웨어소품","브랜드":"기타","색상":"살구색","사이즈":"프리사이즈","밴드사이즈":null,"컵사이즈":null,"브라핏":null,"소재":null,"디자인디테일":null,"세트구성":"다매입/벌크","패키지수량":"104매","성별":"여성","제조국":null,"세탁방법":null}', '얇은 살구색 메쉬 타원형 니플 패치(니플커버) 104매 대용량 구성으로, 여름철 흰 티셔츠나 얇은 상의를 입을 때 도드라지는 니플을 가려주기 위한 언더웨어소품이다. 반투명 필름 재질에 방수·통기 기능을 내세우며 물에 젖어도 잘 붙어 있는 강한 접착력을 강조한다. 배송이 빠르고 가격 대비 매수가 많아 실사용 만족도가 높다는 후기가 많지만, 접착 강도가 약해 시간이 지나면 니플이 다시 튀어나온다는 불만과 스티커가 접히면 그 부분이 도드라져 보인다는 지적, 흰색 얇은 상의에서는 커버력이 약해 비친다는 저평점 리뷰, 제거할 때 통증이 있다는 후기가 함께 확인된다.', 'ON_SALE', NOW(), NOW()),
(1714691773, (SELECT id FROM brand WHERE name = '토보샵' LIMIT 1), (SELECT id FROM category WHERE name = '여성의류 > 청바지' LIMIT 1), '부츠컷 청바지 세미 와이드 일자핏 나팔 데님팬츠 빅사이즈', 20000, 19800, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/1714691773/B.webp?473564456', 0, '여성용 하이웨스트 부츠컷/나팔 청바지로 연청, 중청, 진청, 흑청, 블루청, 딥블루, 그레이청, 생지, 크림, 베이지, 블랙, 화이트, 청색, 그레이 등 다양한 워싱과 XS~3XL, 25~34인치까지 폭넓은 사이즈, 숏/기본/롱 기장으로 선택 가능한 빅사이즈 대응 데님 팬츠다. 허벅지에서 무릎까지는 슬림하게 붙고 밑단으로 갈수록 퍼지는 부츠컷·나팔 실루엣이라 다리가 길어 보이고, 하이웨스트 디자인이라 배와 허리 라인을 자연스럽게 커버해 크롭 상의와 매치하기 좋다. 스판(신축성)이 있어 활동하기 편하고 가격 대비 마감이 깔끔하다는 리뷰가 많아 데일리룩·출근룩·데이트룩으로 무난하게 소화된다. 다만 지퍼(자크) 부분이 짧아 수선이 필요했다는 불만, 배송이 늦었다는 후기, 힙 라인이 커서 사이즈 선택에 실패했다는 후기, 옵션에 따라 색상이 화면보다 어둡게 보인다는 후기 등 옵션별 편차에 대한 단점도 함께 보고된다.', '{"색상":["연청","중청","진청","흑청","블루청","딥블루","그레이청","생지","크림","베이지","블랙","화이트","청색","그레이"],"사이즈":["XS","S","M","L","XL","XXL","3XL","25","26","27","28","29","30","31","32","34"],"핏":["부츠컷","나팔","와이드","세미와이드","일자핏"],"기장":["숏","기본","롱","8부"],"소재":null,"신축성":"신축성있음","허리밴딩여부":null,"두께감":"얇음","빅사이즈여부":"빅사이즈","성별":"여성","브랜드":"토보샵","제조국":null,"세탁방법":null,"제조연월":null,"옵션구성":{"axes":["색상","사이즈"],"option_count":49,"source":"smart_option"}}', '여성용 하이웨스트 부츠컷/나팔 청바지로 연청, 중청, 진청, 흑청, 블루청, 딥블루, 그레이청, 생지, 크림, 베이지, 블랙, 화이트, 청색, 그레이 등 다양한 워싱과 XS~3XL, 25~34인치까지 폭넓은 사이즈, 숏/기본/롱 기장으로 선택 가능한 빅사이즈 대응 데님 팬츠다. 허벅지에서 무릎까지는 슬림하게 붙고 밑단으로 갈수록 퍼지는 부츠컷·나팔 실루엣이라 다리가 길어 보이고, 하이웨스트 디자인이라 배와 허리 라인을 자연스럽게 커버해 크롭 상의와 매치하기 좋다. 스판(신축성)이 있어 활동하기 편하고 가격 대비 마감이 깔끔하다는 리뷰가 많아 데일리룩·출근룩·데이트룩으로 무난하게 소화된다. 다만 지퍼(자크) 부분이 짧아 수선이 필요했다는 불만, 배송이 늦었다는 후기, 힙 라인이 커서 사이즈 선택에 실패했다는 후기, 옵션에 따라 색상이 화면보다 어둡게 보인다는 후기 등 옵션별 편차에 대한 단점도 함께 보고된다.', 'ON_SALE', NOW(), NOW()),
(1850027998, (SELECT id FROM brand WHERE name = '폴리몰리' LIMIT 1), (SELECT id FROM category WHERE name = '거실가구 > 소파' LIMIT 1), '폴리몰리 빈백 607C 소파', 209000, 209000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/1850027998/B.jpg?761000000', 0, '폴리몰리 607C 빈백 소파는 대한민국에서 제조된 1인용 라운지체어형 빈백으로, 겉커버는 면 100% 소재에 발포 폴리프로필렌(EPP) 충전재를 사용했으며 소프트그레이·웜그레이·베이지·블루·그린·카멜브라운·옐로우·오렌지·라임 등 13가지 색상 옵션 중 선택할 수 있고 사각형 풋스툴을 세트로 구성할 수 있다. 본체 94x114x73cm, 풋스툴 72x40x32cm 크기에 무게는 각각 약 5.2kg과 1.3kg으로 가벼워 혼자서도 이동이 쉽고, 이중 분리형 커버로 세탁도 간편해 좁은 거실이나 원룸에서 소파 대신 두기 좋으며 영화 감상, 게임, 독서, 육아·수유 공간, 반려동물과 함께하는 용도로도 인기가 많다. 리뷰에서는 몸을 감싸는 편안한 착석감, 고급스러운 원단 질감, 깔끔한 마감, 빠른 배송이 장점으로 꼽히는 반면, 개봉 초기 오징어·꿉꿉한 냄새가 난다는 불만, 실제 색상이 사진보다 어둡거나 다르게 느껴진다는 의견, 충전재가 부족해 시간이 지나면 꺼진다는 지적, 배송 중 포장 파손이', '{"색상":["소프트그레이","소프트베이지","소프트블루","웜그레이","모카토프","말차그린","카멜브라운","토프","클래식옐로우","클래식오렌지","클래식그린","클래식블루","라임"],"소재":"빈백충전재(EPP)","소파형태":"빈백","인용수":"1인용","사이즈":{"본체":"94 x 114 x 73 cm","풋스툴":"72 x 40 x 32 cm"},"브랜드":"폴리몰리","제조국":"대한민국","구성품":["빈백","EPP"],"쿠션충전재":"발포 폴리프로필렌(EPP)","프레임소재":null,"커버분리세탁여부":"가능","난방온열기능":"없음","중량":"본체 약 5.2kg, 풋스툴 약 1.3kg","배송설치방식":"무료배송/설치없음","품질보증기준":"공정거래위원회 고시(소비자분쟁해결기준)에 의거하여 보상해 드립니다."}', '폴리몰리 607C 빈백 소파는 대한민국에서 제조된 1인용 라운지체어형 빈백으로, 겉커버는 면 100% 소재에 발포 폴리프로필렌(EPP) 충전재를 사용했으며 소프트그레이·웜그레이·베이지·블루·그린·카멜브라운·옐로우·오렌지·라임 등 13가지 색상 옵션 중 선택할 수 있고 사각형 풋스툴을 세트로 구성할 수 있다. 본체 94x114x73cm, 풋스툴 72x40x32cm 크기에 무게는 각각 약 5.2kg과 1.3kg으로 가벼워 혼자서도 이동이 쉽고, 이중 분리형 커버로 세탁도 간편해 좁은 거실이나 원룸에서 소파 대신 두기 좋으며 영화 감상, 게임, 독서, 육아·수유 공간, 반려동물과 함께하는 용도로도 인기가 많다. 리뷰에서는 몸을 감싸는 편안한 착석감, 고급스러운 원단 질감, 깔끔한 마감, 빠른 배송이 장점으로 꼽히는 반면, 개봉 초기 오징어·꿉꿉한 냄새가 난다는 불만, 실제 색상이 사진보다 어둡거나 다르게 느껴진다는 의견, 충전재가 부족해 시간이 지나면 꺼진다는 지적, 배송 중 포장 파손이나 본체·풋스툴 색상 불일치 사례, 면 소재라 방수가 안 되고 앉았다 일어날 때 몸이 푹 꺼져 힘들다는 단점도 다수 확인된다.', 'ON_SALE', NOW(), NOW()),
(1924364761, (SELECT id FROM brand WHERE name = '플라워타임' LIMIT 1), (SELECT id FROM category WHERE name = '꽃배달 > 근조화환' LIMIT 1), '창원꽃배달 개업 장례식장 근조화환 결혼식화한배달', 80000, 59000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/1924364761/B.jpg?832000000', 0, '창원 지역 등 경남 권역으로 당일배송 가능한 3단 근조화환으로, 기본형·고급형·특급형 등급과 근조·축하(개업·결혼) 용도를 함께 선택할 수 있는 화환 상품이다. 흰 국화와 백합을 중심으로 한 근조용 화환은 흰 리본에 삼가 故人의 冥福을 빕니다 문구가 들어가며, 축하용은 빨강·분홍·노랑 계열 거베라와 백합으로 화려하게 구성되고 축(祝) 문구의 분홍 리본이 달린다. 상단의 큰 리본 매듭과 양옆 종려잎 장식이 특징인 대형 3단 원뿔형 화환으로, 리본문구(경조사어/보내시는분)와 배송날짜·시간, 주문자 연락처를 주문 시 직접 입력해야 한다. 브랜드는 플라워타임이며 고객센터(1566-7432)를 통한 전화 상담을 강조한다. 리뷰에서는 빠른 배송, 친절한 기사, 신선한 꽃 상태, 만족스러운 디자인이 장점으로 언급되었고, 별도의 단점을 지적한 저평점 리뷰는 확인되지 않았다(수집된 리뷰 2건 모두 5점).', '{"화환종류":"3단화환","등급":["기본형","고급형","특급형"],"용도":["근조","축하"],"색상":"혼합색","사이즈":null,"리본문구":{"좌측(경조사어)":"선택형(경조사어 리본문구, 주문 시 입력)","우측(보내시는분)":"선택형(보내시는분 리본문구, 주문 시 입력)"},"배송일시":{"지정방식":"배송날짜/시간 옵션 선택(주문 시 지정)"},"배송지역":"경남","주문자정보":{"연락처":"주문 시 주문하신분 연락처 입력 필수"},"브랜드":"플라워타임","제조국":null,"판매자AS연락처":"1566-7432","당일배송여부":"당일배송가능","판매상태":"판매중"}', '창원 지역 등 경남 권역으로 당일배송 가능한 3단 근조화환으로, 기본형·고급형·특급형 등급과 근조·축하(개업·결혼) 용도를 함께 선택할 수 있는 화환 상품이다. 흰 국화와 백합을 중심으로 한 근조용 화환은 흰 리본에 삼가 故人의 冥福을 빕니다 문구가 들어가며, 축하용은 빨강·분홍·노랑 계열 거베라와 백합으로 화려하게 구성되고 축(祝) 문구의 분홍 리본이 달린다. 상단의 큰 리본 매듭과 양옆 종려잎 장식이 특징인 대형 3단 원뿔형 화환으로, 리본문구(경조사어/보내시는분)와 배송날짜·시간, 주문자 연락처를 주문 시 직접 입력해야 한다. 브랜드는 플라워타임이며 고객센터(1566-7432)를 통한 전화 상담을 강조한다. 리뷰에서는 빠른 배송, 친절한 기사, 신선한 꽃 상태, 만족스러운 디자인이 장점으로 언급되었고, 별도의 단점을 지적한 저평점 리뷰는 확인되지 않았다(수집된 리뷰 2건 모두 5점).', 'ON_SALE', NOW(), NOW()),
(2137708391, (SELECT id FROM brand WHERE name = '11번가 판매자 44593922' LIMIT 1), (SELECT id FROM category WHERE name = '남성의류 > 셔츠/남방' LIMIT 1), '구제남방  폴로 .빈폴.토미. 버버리.구제 긴팔. 반팔남방', 14900, 14900, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/2137708391/B.jpg?882000000', 0, '빈폴, 타미힐피거, 라코스테, 폴로 랄프로렌, 닥스 등 여러 브랜드가 랜덤으로 섞여 발송되는 남성 구제(빈티지) 셔츠·카라티셔츠 모음전으로, 셔츠칼라의 긴팔·반팔 남방과 카라 넥라인의 폴로형 카라티셔츠 두 옵션 중 선택해 저렴한 가격(14,900원)에 구매할 수 있다. 체크, 스트라이프, 솔리드 등 패턴과 사이즈가 개체마다 다르게 랜덤 발송되어 세컨핸드 빈티지룩이나 캐주얼 일상룩을 저비용으로 완성하려는 구매자, 랜덤 박스 형태의 구제 쇼핑을 즐기는 사람에게 적합하다. 배송이 빠르고 가격 대비 만족도가 높으며 옷 상태가 깔끔하다는 후기가 많지만, 일부 개체는 오염·얼룩이나 목 부분 변색이 있었다는 저평점 후기와 표기보다 사이즈가 작게 오거나 재고 노출 오류로 배송이 지연됐다는 불만도 존재해 구매 전 감안이 필요하다.', '{"색상":null,"사이즈":null,"패턴":null,"소재":null,"핏":null,"소매기장":null,"넥라인":["셔츠칼라","카라(폴로)"],"스타일":"빈티지/구제","브랜드":null,"제조국":null,"세탁방법":null,"제조연월":null,"품질보증기준":null,"AS책임자및전화번호":null,"제조자수입자":null,"모델명":null,"성별":"남성","옵션구성":{"axes":["번호를 적어주세요","선택"],"items":[{"value":"남방","add_price":0,"sold_out":false,"stock_qty":996},{"value":"카라티셔츠","add_price":0,"sold_out":false,"stock_qty":997}]},"제품태그":["구제","빈티지","브랜드구제셔츠","긴팔","반팔","랜덤발송"]}', '빈폴, 타미힐피거, 라코스테, 폴로 랄프로렌, 닥스 등 여러 브랜드가 랜덤으로 섞여 발송되는 남성 구제(빈티지) 셔츠·카라티셔츠 모음전으로, 셔츠칼라의 긴팔·반팔 남방과 카라 넥라인의 폴로형 카라티셔츠 두 옵션 중 선택해 저렴한 가격(14,900원)에 구매할 수 있다. 체크, 스트라이프, 솔리드 등 패턴과 사이즈가 개체마다 다르게 랜덤 발송되어 세컨핸드 빈티지룩이나 캐주얼 일상룩을 저비용으로 완성하려는 구매자, 랜덤 박스 형태의 구제 쇼핑을 즐기는 사람에게 적합하다. 배송이 빠르고 가격 대비 만족도가 높으며 옷 상태가 깔끔하다는 후기가 많지만, 일부 개체는 오염·얼룩이나 목 부분 변색이 있었다는 저평점 후기와 표기보다 사이즈가 작게 오거나 재고 노출 오류로 배송이 지연됐다는 불만도 존재해 구매 전 감안이 필요하다.', 'ON_SALE', NOW(), NOW()),
