(2541075996, (SELECT id FROM brand WHERE name = '피카소' LIMIT 1), (SELECT id FROM category WHERE name = '여성신발 > 펌프스/힐' LIMIT 1), '발편한 여성 소가죽  면접구두 유니화 승무원 펌프스 구두 220부터260', 35000, 31410, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/2541075996/B.webp?291745897', 0, '블랙 소가죽 소재의 라운드토 슬립온 펌프스로, 220mm부터 260mm까지 전 사이즈와 3cm·4cm·5cm 세 가지 굽높이를 선택할 수 있는 발편한 여성 구두다. 스트랩 없이 발등을 감싸는 단순한 디자인에 블록형 낮은 굽을 적용해 승무원, 매장 근무자, 면접, 직장 출근 등 오래 서 있거나 걸어야 하는 상황에 적합하며, 발볼이 넓은 사람도 무난히 신을 수 있다는 후기가 많다. 리뷰에서는 쿠션감과 푹신함, 굽 소리가 나지 않는 정숙성, 깔끔한 마감이 장점으로 꼽히지만, 실제 사이즈보다 크게 나와 헐렁하거나 뒤꿈치가 벗겨진다는 불만이 다수이고 한 치수 작게 주문하라는 조언이 많으며, 오래 신으면 새끼발가락이나 엄지발톱 부위가 눌려 아프다는 저평점 후기와 배송 지연, 다소 평범한 디자인이라는 지적도 함께 존재한다.', '{"색상":["블랙"],"사이즈":["220","225","230","235","240","245","250","255","260"],"굽높이":["3cm","4cm","5cm"],"굽모양":"블록힐","스타일":"펌프스","소재":"소가죽","발볼":"넓음","토모양":"라운드토","브랜드":"피카소","제조국":"중국","세탁방법":"천연 가죽 및 합성피혁 소재로 물세척 시 변형·변색·수축이 발생할 수 있어 전문 세탁점 이용 권장","착용계절":null,"여밈방식":"슬립온","옵션구성":{"axes":["사이즈","색상"],"count":27,"total_stock":489,"color_options":["블랙"],"size_options":["220","225","230","235","240","245","250","255","260"],"heel_options":["3cm","4cm","5cm"]},"특징태그":["발편한","면접용","승무원화","유니화","OEM"]}', '블랙 소가죽 소재의 라운드토 슬립온 펌프스로, 220mm부터 260mm까지 전 사이즈와 3cm·4cm·5cm 세 가지 굽높이를 선택할 수 있는 발편한 여성 구두다. 스트랩 없이 발등을 감싸는 단순한 디자인에 블록형 낮은 굽을 적용해 승무원, 매장 근무자, 면접, 직장 출근 등 오래 서 있거나 걸어야 하는 상황에 적합하며, 발볼이 넓은 사람도 무난히 신을 수 있다는 후기가 많다. 리뷰에서는 쿠션감과 푹신함, 굽 소리가 나지 않는 정숙성, 깔끔한 마감이 장점으로 꼽히지만, 실제 사이즈보다 크게 나와 헐렁하거나 뒤꿈치가 벗겨진다는 불만이 다수이고 한 치수 작게 주문하라는 조언이 많으며, 오래 신으면 새끼발가락이나 엄지발톱 부위가 눌려 아프다는 저평점 후기와 배송 지연, 다소 평범한 디자인이라는 지적도 함께 존재한다.', 'ON_SALE', NOW(), NOW()),
(2595956796, (SELECT id FROM brand WHERE name = '컨바텍(듀오덤)' LIMIT 1), (SELECT id FROM category WHERE name = '가정의료용품 > 밴드' LIMIT 1), '듀오덤 엑스트라씬 습윤밴드 10매 1박스(정품) + 밴드골드1통', 23000, 23000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/2595956796/B.jpg?8000000', 0, '컨바텍 듀오덤 엑스트라씬은 10x10cm 크기의 하이드로콜로이드 습윤밴드로, 10매 1박스 구성에 밴드골드(살구색 격자무늬 일반 접착밴드) 한 통이 함께 증정되는 세트 상품입니다. 상처와 찰과상 부위에 사용하는 살색(베이지) 계열 정사각형 패치로, 개별 파우치에 낱개 포장되어 휴대와 보관이 간편합니다. 아이를 키우는 가정의 상비약, 야외활동이나 작업 중 생긴 상처, 수술 후 상처 관리 등 다양한 상황에서 쓰입니다. 리뷰에서는 접착력이 뛰어나 움직여도 잘 떨어지지 않고, 얇아서 밀착감이 좋으며, 습윤 환경 덕분에 상처가 덜 당기고 흉터가 적게 남는다는 점, 유통기한이 넉넉하고 배송이 빠르며 약국보다 저렴하다는 점이 장점으로 꼽힙니다. 반면 접착력이 강한 만큼 떼어낼 때 잘 떨어지지 않고 피부 주위가 끈적해진다는 점, 오래 보관 시 끈적해질까 우려된다는 의견, 일부는 사용이 다소 번거롭다고 평가한 점이 단점으로 언급됩니다.', '{"브랜드":"컨바텍(듀오덤)","제품유형":"습윤밴드(하이드로콜로이드)","사이즈":"10x10cm","구성수량":"10매","세트구성":["+밴드골드 증정"],"소재":"하이드로콜로이드","사용부위":["상처","찰과상"],"방수여부":null,"제조국":null,"허가인증번호":null,"제조수입사":"컨바텍코리아","색상":"살색","판매단위":"묶음/세트"}', '컨바텍 듀오덤 엑스트라씬은 10x10cm 크기의 하이드로콜로이드 습윤밴드로, 10매 1박스 구성에 밴드골드(살구색 격자무늬 일반 접착밴드) 한 통이 함께 증정되는 세트 상품입니다. 상처와 찰과상 부위에 사용하는 살색(베이지) 계열 정사각형 패치로, 개별 파우치에 낱개 포장되어 휴대와 보관이 간편합니다. 아이를 키우는 가정의 상비약, 야외활동이나 작업 중 생긴 상처, 수술 후 상처 관리 등 다양한 상황에서 쓰입니다. 리뷰에서는 접착력이 뛰어나 움직여도 잘 떨어지지 않고, 얇아서 밀착감이 좋으며, 습윤 환경 덕분에 상처가 덜 당기고 흉터가 적게 남는다는 점, 유통기한이 넉넉하고 배송이 빠르며 약국보다 저렴하다는 점이 장점으로 꼽힙니다. 반면 접착력이 강한 만큼 떼어낼 때 잘 떨어지지 않고 피부 주위가 끈적해진다는 점, 오래 보관 시 끈적해질까 우려된다는 의견, 일부는 사용이 다소 번거롭다고 평가한 점이 단점으로 언급됩니다.', 'ON_SALE', NOW(), NOW()),
(3172014102, (SELECT id FROM brand WHERE name = 'KTEVI' LIMIT 1), (SELECT id FROM category WHERE name = '시계 > 남성시계' LIMIT 1), 'KTEVI 남성 패션 가죽 손목시계 군인', 10000, 9000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/3172014102/B.webp?387905111', 0, 'KTEVI 남성용 가죽밴드 손목시계로, 대형 케이스(41mm 이상)에 아날로그 쿼츠 방식, 생활방수 기능을 갖춘 군인/밀리터리 스타일 캐주얼 워치다. 색상은 브라운 계열(갈색·브라운)과 블랙 중 선택 가능하며, 스테인리스 케이스와 합성가죽(레자) 스트랩, 강화유리를 사용했고 제조국은 중국이다. 다이얼에는 크로노그래프풍 서브다이얼과 날짜창이 있지만 서브다이얼 버튼은 실제로 작동하지 않는 장식 요소다. 구매자들은 빠른 배송과 가격 대비 고급스러워 보이는 디자인, 깔끔한 마감, PU가죽 밴드의 편안한 착용감을 장점으로 꼽지만, 일부 저평점 리뷰에서는 ''장난감 같은 느낌''이라는 혹평과 함께 디자인·마감·재질이 기대에 못 미친다는 지적, 착용 중 시계가 멈추는 작동 불량 사례가 있어 품질 편차에 유의해야 한다.', '{"브랜드":"KTEVI","밴드종류":"가죽밴드","색상":["브라운","블랙"],"사이즈":"케이스지름 대형(41mm 이상)","무브먼트":"쿼츠(아날로그)","디스플레이타입":"아날로그","스타일":"군인/밀리터리","방수기능":"생활방수","케이스소재":"스테인리스스틸","밴드소재":"합성가죽(레자)","성별":"남성용","제조국":"중국","정품여부":null,"부가기능":["달력/날짜창"],"보증서제공여부":null,"품질보증기간":null,"AS연락처":"010-7567-2204"}', 'KTEVI 남성용 가죽밴드 손목시계로, 대형 케이스(41mm 이상)에 아날로그 쿼츠 방식, 생활방수 기능을 갖춘 군인/밀리터리 스타일 캐주얼 워치다. 색상은 브라운 계열(갈색·브라운)과 블랙 중 선택 가능하며, 스테인리스 케이스와 합성가죽(레자) 스트랩, 강화유리를 사용했고 제조국은 중국이다. 다이얼에는 크로노그래프풍 서브다이얼과 날짜창이 있지만 서브다이얼 버튼은 실제로 작동하지 않는 장식 요소다. 구매자들은 빠른 배송과 가격 대비 고급스러워 보이는 디자인, 깔끔한 마감, PU가죽 밴드의 편안한 착용감을 장점으로 꼽지만, 일부 저평점 리뷰에서는 ''장난감 같은 느낌''이라는 혹평과 함께 디자인·마감·재질이 기대에 못 미친다는 지적, 착용 중 시계가 멈추는 작동 불량 사례가 있어 품질 편차에 유의해야 한다.', 'ON_SALE', NOW(), NOW()),
(3610879964, (SELECT id FROM brand WHERE name = '기스모' LIMIT 1), (SELECT id FROM category WHERE name = '패션잡화 > 모자' LIMIT 1), '긴챙 S80 메쉬 캡모자/여름 골프 볼캡/망사 야구모자/시원한 등산 스포츠 매쉬캡', 4900, 4410, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/3610879964/B.jpg?153125348', 0, '블랙·네이비·베이지·화이트·그레이 5색상으로 구성된 남성용 메쉬 캡모자(야구모자/볼캡)로, 사이즈조절형 벨크로 클로저에 무게 68g의 초경량 소재를 사용했다. 10.5cm 롱챙 디자인으로 햇빛 가림 면적이 넓고 얼굴이 작아 보이는 착시 효과가 있으며, 사이드·백 패널이 메쉬(망사) 소재라 가볍고 통풍이 잘 되어 여름용으로 적합하다. 전면에는 필기체 로고 자수 장식이 있고, 골프·등산·낚시·스포츠 등 야외활동과 캐주얼 착용에 두루 활용된다. 리뷰에서는 저렴한 가격에 비해 메쉬 소재의 시원함과 긴 챙의 자외선 차단 효과, 깔끔한 마감과 빠른 배송에 대한 만족도가 높게 나타나지만, 일부 저평점 리뷰에서는 뒤쪽 사이즈 조절용 벨크로(찍찍이) 스트랩이 저렴해 보이고 끈이 튀어나와 미관상 아쉽다는 점, 마감이 미흡하거나 좌우 대칭이 맞지 않는다는 품질 불만, 색상이 화면보다 어둡게 느껴진다는 지적이 단점으로 제기된다.', '{"색상":["블랙","화이트","베이지","그레이","네이비"],"사이즈":"사이즈조절형","모자종류":"야구모자/볼캡","성별":"남성","소재":"메쉬/망사","브랜드":"기스모","제조국":"중국","세탁방법":"단독세탁권장","챙길이":"롱챙","클로저타입":"벨크로","장식디테일":["자수"],"계절감":"여름용(메쉬/통풍)","활용스타일":["캐주얼","골프","등산/아웃도어","낚시","스포츠"],"치수정보":{"머리둘레":"55~60cm","챙길이":"10.5cm","모자높이":"11cm","무게":"68g"}}', '블랙·네이비·베이지·화이트·그레이 5색상으로 구성된 남성용 메쉬 캡모자(야구모자/볼캡)로, 사이즈조절형 벨크로 클로저에 무게 68g의 초경량 소재를 사용했다. 10.5cm 롱챙 디자인으로 햇빛 가림 면적이 넓고 얼굴이 작아 보이는 착시 효과가 있으며, 사이드·백 패널이 메쉬(망사) 소재라 가볍고 통풍이 잘 되어 여름용으로 적합하다. 전면에는 필기체 로고 자수 장식이 있고, 골프·등산·낚시·스포츠 등 야외활동과 캐주얼 착용에 두루 활용된다. 리뷰에서는 저렴한 가격에 비해 메쉬 소재의 시원함과 긴 챙의 자외선 차단 효과, 깔끔한 마감과 빠른 배송에 대한 만족도가 높게 나타나지만, 일부 저평점 리뷰에서는 뒤쪽 사이즈 조절용 벨크로(찍찍이) 스트랩이 저렴해 보이고 끈이 튀어나와 미관상 아쉽다는 점, 마감이 미흡하거나 좌우 대칭이 맞지 않는다는 품질 불만, 색상이 화면보다 어둡게 느껴진다는 지적이 단점으로 제기된다.', 'ON_SALE', NOW(), NOW()),
(3923656637, (SELECT id FROM brand WHERE name = '농사친구' LIMIT 1), (SELECT id FROM category WHERE name = '꽃/원예 > 꽃/식물' LIMIT 1), '농사친구 루팅파우더 삽목 뿌리 농약 발근제 아님 촉진 다육이 관엽식물 제라늄 접목 장미 라벤더 삽', 15800, 15790, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/3923656637/B.webp?51548875', 0, '농사친구 루팅파우더 플러스(75g)는 삽목·꺾꽂이용 발근제(약제) 분말 제품으로, 흰색 병에 담긴 해초 유래 성분 함유 분말을 절단면에 묻히거나 물에 2000배 희석해 사용한다. 다육이, 제라늄, 라벤더, 로즈마리 같은 반경질 식물부터 장미, 무화과나무, 블루베리 같은 경질 식물, 허브·국화 같은 연질 식물까지 폭넓게 적용 가능해 삽목·꺾꽂이·묘목 정식 등 번식을 시도하는 원예 초보자와 애호가에게 적합하다. 화학 합성제 무첨가로 부담이 적다는 점과 배송이 빠르고 사용법 안내가 친절하다는 점, 제라늄·블루베리 삽목 후 뿌리가 잘 내렸다는 후기가 장점으로 꼽히나, 화원 판매가 대비 다소 비싸다는 의견과 별다른 사유 없이 낮은 평점만 남긴 리뷰가 일부 있어 구체적 단점 파악에는 한계가 있다.', '{"상품유형":"약제(살충제·발근제등)","식물종류":"해당없음","브랜드":"농사친구","제조국":"대한민국","색상":null,"사이즈":null,"규격":"75g","판매단위":"무게(g/kg)","화분포함여부":"해당없음","화분소재":"해당없음","생육형태":"해당없음","재배환경":"해당없음","용도":["발근/삽목촉진"],"인증정보":"비료생산업자 등록번호: 경기평택 01-가-10405호(미량요소복합비료, 보증성분 붕소 0.05%·몰리브덴 0.0005%)","세트구성":null,"선물포장여부":"해당없음"}', '농사친구 루팅파우더 플러스(75g)는 삽목·꺾꽂이용 발근제(약제) 분말 제품으로, 흰색 병에 담긴 해초 유래 성분 함유 분말을 절단면에 묻히거나 물에 2000배 희석해 사용한다. 다육이, 제라늄, 라벤더, 로즈마리 같은 반경질 식물부터 장미, 무화과나무, 블루베리 같은 경질 식물, 허브·국화 같은 연질 식물까지 폭넓게 적용 가능해 삽목·꺾꽂이·묘목 정식 등 번식을 시도하는 원예 초보자와 애호가에게 적합하다. 화학 합성제 무첨가로 부담이 적다는 점과 배송이 빠르고 사용법 안내가 친절하다는 점, 제라늄·블루베리 삽목 후 뿌리가 잘 내렸다는 후기가 장점으로 꼽히나, 화원 판매가 대비 다소 비싸다는 의견과 별다른 사유 없이 낮은 평점만 남긴 리뷰가 일부 있어 구체적 단점 파악에는 한계가 있다.', 'ON_SALE', NOW(), NOW()),
(4151330708, (SELECT id FROM brand WHERE name = 'SCUTI' LIMIT 1), (SELECT id FROM category WHERE name = '남성신발 > 신발용품' LIMIT 1), '평발 깔창 기능성 아치 자세 오다리 교정 신발 남성 여성 인솔', 22100, 19900, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/4151330708/B.webp?806237139', 0, '대한민국 제조 SCUTI 브랜드의 남녀공용 아치서포트 하프 인솔로, 뒤꿈치부터 아치까지 감싸는 PVC 복합소재 구조에 그레이(HARD)와 베이지(SOFT) 두 가지 경도, S/M/L 세 가지 사이즈로 운동화나 슬리퍼 등 다양한 신발에 넣어 사용할 수 있다. 뒤꿈치 벌집형 통기홀과 다수의 통풍구멍을 갖춘 하이볼륨 쿠션 구조로 평발, 족저근막염, 오다리·안짱걸음 교정과 충격 흡수를 돕는다고 광고하며, 실제 후기에서도 아치를 받쳐줘 걸을 때 발바닥과 뒤꿈치 통증이 줄고 장시간 서서 일할 때 다리 피로가 완화됐다는 긍정 평가와 마감·재질에 대한 만족이 많다. 다만 사이즈가 맞지 않으면 인솔이 신발 안에서 밀리거나 고정되지 않고, 두께 때문에 신발을 한 치수 크게 신어야 하며, 일부 제품은 양쪽 아치 위치가 미세하게 달라 한쪽 발이 불편하다는 저평점 후기와 작은 발 사이즈에서는 아치 위치가 어긋난다는 지적도 있어 구매 전 정확한 사이즈 선택이 중요하다.', '{"색상":["그레이","베이지"],"사이즈":["S","M","L"],"소재":"PVC","용도유형":["평발교정","아치서포트","바른자세교정","오다리교정","충격흡수/쿠션"],"적용신발종류":["운동화","슬리퍼","전신발공용"],"성별":"남녀공용","두께":"하이볼륨/고쿠션","브랜드":"SCUTI","제조국":"대한민국","구성수량":"1개입(1켤레)","재단가능여부":null,"세탁방법":null}', '대한민국 제조 SCUTI 브랜드의 남녀공용 아치서포트 하프 인솔로, 뒤꿈치부터 아치까지 감싸는 PVC 복합소재 구조에 그레이(HARD)와 베이지(SOFT) 두 가지 경도, S/M/L 세 가지 사이즈로 운동화나 슬리퍼 등 다양한 신발에 넣어 사용할 수 있다. 뒤꿈치 벌집형 통기홀과 다수의 통풍구멍을 갖춘 하이볼륨 쿠션 구조로 평발, 족저근막염, 오다리·안짱걸음 교정과 충격 흡수를 돕는다고 광고하며, 실제 후기에서도 아치를 받쳐줘 걸을 때 발바닥과 뒤꿈치 통증이 줄고 장시간 서서 일할 때 다리 피로가 완화됐다는 긍정 평가와 마감·재질에 대한 만족이 많다. 다만 사이즈가 맞지 않으면 인솔이 신발 안에서 밀리거나 고정되지 않고, 두께 때문에 신발을 한 치수 크게 신어야 하며, 일부 제품은 양쪽 아치 위치가 미세하게 달라 한쪽 발이 불편하다는 저평점 후기와 작은 발 사이즈에서는 아치 위치가 어긋난다는 지적도 있어 구매 전 정확한 사이즈 선택이 중요하다.', 'ON_SALE', NOW(), NOW()),
(4273715844, (SELECT id FROM brand WHERE name = 'MISSHA' LIMIT 1), (SELECT id FROM category WHERE name = '메이크업 > 페이스메이크업' LIMIT 1), '미샤 M 퍼펙트 커버 비비 크림 50ml 21호 X 2개', 19500, 19500, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/4273715844/B.webp?466433908', 0, '미샤 M 퍼펙트 커버 비비 크림 50ml 21호 화사한 베이지 2개입으로, SPF42/PA+++의 미백·주름개선·자외선차단 복합기능성 BB크림이다. 모든피부용으로 한국에서 제조되었으며 붉은 와인색 튜브에 스펀지 어플리케이터가 달려 있어 데일리 메이크업과 잡티 커버에 간편하게 사용하기 좋다. 다수 리뷰에서 발림성이 부드럽고 발색과 지속력이 뛰어나며 2개입 구성으로 가성비가 좋아 여러 연령대가 꾸준히 재구매하는 스테디셀러로 평가된다. 다만 일부 저평점 리뷰에서는 색상이 회색빛이 돌거나 피부톤보다 어둡게 느껴진다는 점, 발색이 아쉽다는 점을 단점으로 지적했다.', '{"브랜드":"MISSHA","제품타입":"BB크림","색상":"21호","호수":"21호 화사한 베이지","용량":"50ml X 2개","피부타입":"모든피부","SPF지수":"SPF42/PA+++","기능성분류":["미백","주름개선","자외선차단","복합기능성"],"밀착력지속력":["커버력","지속력"],"제조국":"한국","제조판매업자":"(주)하나코스 / (주)에이블씨엔씨","사용기한":"제조일로부터 3년, 개봉 후 1년이내 사용","구성":"2개입","판매단위수량":"50ml X 2개"}', '미샤 M 퍼펙트 커버 비비 크림 50ml 21호 화사한 베이지 2개입으로, SPF42/PA+++의 미백·주름개선·자외선차단 복합기능성 BB크림이다. 모든피부용으로 한국에서 제조되었으며 붉은 와인색 튜브에 스펀지 어플리케이터가 달려 있어 데일리 메이크업과 잡티 커버에 간편하게 사용하기 좋다. 다수 리뷰에서 발림성이 부드럽고 발색과 지속력이 뛰어나며 2개입 구성으로 가성비가 좋아 여러 연령대가 꾸준히 재구매하는 스테디셀러로 평가된다. 다만 일부 저평점 리뷰에서는 색상이 회색빛이 돌거나 피부톤보다 어둡게 느껴진다는 점, 발색이 아쉽다는 점을 단점으로 지적했다.', 'ON_SALE', NOW(), NOW()),
(5917693832, (SELECT id FROM brand WHERE name = '비비안웨스트우드' LIMIT 1), (SELECT id FROM category WHERE name = '수입명품 > 쥬얼리' LIMIT 1), '비비안웨스트우드 26SS 실버 미니 바스 릴리프 목걸이 63020086 02P116 CN', 245000, 208250, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/pd/v2/6/9/3/8/3/2/BVJnl/5917693832_B.webp', 0, '비비안웨스트우드 26SS 실버 미니 바스 릴리프 목걸이(63020086 02P116 CN)는 황동 소재에 실버 톤 도금을 입힌 여성용 목걸이로, 브랜드 시그니처인 새턴(토성 고리) 오브 모양 펜던트에 크리스탈 큐빅이 촘촘히 세팅되어 있고 상단에는 크로스 장식이 더해져 심플하면서도 포인트가 확실한 디자인이다. 펜던트는 가로 2.7cm, 세로 1.7cm의 미니 사이즈이며 체인 길이는 48cm로 데일리 착용과 선물용으로 모두 적합하다. 태국에서 제조되어 병행수입(리얼트루컴퍼니)으로 판매되는 정품이며, 자체 제작 보증서가 포함되나 브랜드 정식 케어카드는 아닐 수 있다는 점과 세탁 시 이염·손상 우려가 있어 전문 세탁업소 이용을 권장한다는 점은 구매 전 참고할 부분이다.', '{"브랜드":"비비안웨스트우드","종류":"목걸이","성별":"여성","소재":["황동"],"색상":"실버","사이즈":["ONE SIZE"],"치수":{"펜던트_가로_cm":2.7,"펜던트_세로_cm":1.7,"체인길이_cm":48},"중량":"10g","제조국":"태국","제조자수입자":"비비안 웨스트우드/병행수입(리얼트루컴퍼니)","병행수입여부":"병행수입","보증서제공여부":"상세설명참조","세탁관리방법":"의류 직물 등은 반드시 케어라벨 기호를 확인하고 세탁. 가죽 및 프린팅, 스터드 등 디테일 제품은 세탁 시 이염·손상 우려로 세탁 자제 또는 전문 세탁업소 의뢰 권장.","품질보증기준":"관련법 및 소비자분쟁 해결기준에 따름","AS책임자":"㈜리얼트루컴퍼니 / 1833-8869","시즌":"26SS"}', '비비안웨스트우드 26SS 실버 미니 바스 릴리프 목걸이(63020086 02P116 CN)는 황동 소재에 실버 톤 도금을 입힌 여성용 목걸이로, 브랜드 시그니처인 새턴(토성 고리) 오브 모양 펜던트에 크리스탈 큐빅이 촘촘히 세팅되어 있고 상단에는 크로스 장식이 더해져 심플하면서도 포인트가 확실한 디자인이다. 펜던트는 가로 2.7cm, 세로 1.7cm의 미니 사이즈이며 체인 길이는 48cm로 데일리 착용과 선물용으로 모두 적합하다. 태국에서 제조되어 병행수입(리얼트루컴퍼니)으로 판매되는 정품이며, 자체 제작 보증서가 포함되나 브랜드 정식 케어카드는 아닐 수 있다는 점과 세탁 시 이염·손상 우려가 있어 전문 세탁업소 이용을 권장한다는 점은 구매 전 참고할 부분이다.', 'ON_SALE', NOW(), NOW()),
(6709132985, (SELECT id FROM brand WHERE name = '파리생제르망' LIMIT 1), (SELECT id FROM category WHERE name = '언더웨어/잠옷 > 남성 팬티' LIMIT 1), '[T멤버십 특.가] 누적판매 150만장! PSG 파리생제르망 남성 드로즈 팬티 10종+파우치 세트 PSG-UWM-23F01', 39800, 39800, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/dl/v2/1/3/2/9/8/5/aQcgS/6709132985_235076818.webp', 0, '파리생제르망(PSG) 라이선스의 남성 드로즈 팬티 10종+파우치 세트로 사이즈는 95·100·105·110 중 선택 가능하며 그레이, 블루, 블랙, 네이비, 와인 등 10가지 멀티 컬러로 구성되어 있다. 블랙 바탕에 PARIS 로고 밴드와 PSG 원형 엠블럼 자수가 포인트이며 매끈한 저지 원단에 신축성이 좋아 착용감이 편하고, 여행용 파우치가 함께 제공되어 선물용이나 일상 다회용으로도 적합하다. 리뷰에서는 촉감이 부드럽고 얇으며 밴드가 탄탄해 착용감이 좋다는 평가와 10장 구성 대비 가성비가 좋다는 호평이 많지만, 세탁 후 보풀이 금방 일어나고 일부 제품에 바느질 불량이 있었다는 불만, 사이즈 편차(크거나 작음)에 대한 상반된 후기, 걸을 때 팬티가 말려 불편하다는 지적도 있어 재질 내구성과 사이즈 선택에는 유의가 필요하다.', '{"색상":["그레이","블루","블랙","네이비","멀티(혼합)"],"사이즈":["95","100","105","110"],"소재":null,"팬티유형":"드로즈","구성수량":"10매","연령대":"성인","브랜드":"파리생제르망","라이선스캐릭터":"PSG 파리생제르망","기능성태그":["신축성"],"성별":"남성","제조국":null,"세탁방법":null}', '파리생제르망(PSG) 라이선스의 남성 드로즈 팬티 10종+파우치 세트로 사이즈는 95·100·105·110 중 선택 가능하며 그레이, 블루, 블랙, 네이비, 와인 등 10가지 멀티 컬러로 구성되어 있다. 블랙 바탕에 PARIS 로고 밴드와 PSG 원형 엠블럼 자수가 포인트이며 매끈한 저지 원단에 신축성이 좋아 착용감이 편하고, 여행용 파우치가 함께 제공되어 선물용이나 일상 다회용으로도 적합하다. 리뷰에서는 촉감이 부드럽고 얇으며 밴드가 탄탄해 착용감이 좋다는 평가와 10장 구성 대비 가성비가 좋다는 호평이 많지만, 세탁 후 보풀이 금방 일어나고 일부 제품에 바느질 불량이 있었다는 불만, 사이즈 편차(크거나 작음)에 대한 상반된 후기, 걸을 때 팬티가 말려 불편하다는 지적도 있어 재질 내구성과 사이즈 선택에는 유의가 필요하다.', 'ON_SALE', NOW(), NOW()),
(6720007924, (SELECT id FROM brand WHERE name = '11번가 판매자 46444123' LIMIT 1), (SELECT id FROM category WHERE name = '게임 > PC게임' LIMIT 1), 'XBOX PC 팔월드 디지털코드 Palworld 팰월드', 7000, 6700, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/6720007924/B.jpg?6000000', 0, 'XBOX PC용 팰월드(Palworld) 디지털 다운로드 코드 상품으로, 정품을 이메일로 전송받아 즉시 이용할 수 있는 시뮬레이션 장르 신품 게임 코드이다. 정가보다 저렴한 가격에 빠르면 수십 초에서 5분 이내로 코드가 전송되어 선물용이나 급하게 정품을 구매하고 싶을 때 적합하며, 설치와 실행 절차도 어렵지 않다는 후기가 많다. 다만 스팀이 아닌 엑박(Xbox) 버전이라 PC에서의 접근성이 다소 떨어진다는 점, 실행 후 발생하는 오류는 그래픽카드 드라이버 업데이트 등을 직접 검색해 해결해야 하는 경우가 있다는 점, 활용도를 낮게 평가한 저평점 리뷰도 일부 존재한다는 점은 단점으로 꼽힌다.', '{"플랫폼":"Xbox","제공방식":"다운로드코드","장르":"시뮬레이션","상품상태":"신품","코드전송방식":"이메일전송","언어":null,"이용조건이용기간":null,"최소시스템사양":null,"제작사배급사":null,"브랜드":null,"제조국":null,"색상":null,"지역국가코드":null,"게임등급":null,"청약철회가능여부":null,"옵션구성":["이메일주소 입력"]}', 'XBOX PC용 팰월드(Palworld) 디지털 다운로드 코드 상품으로, 정품을 이메일로 전송받아 즉시 이용할 수 있는 시뮬레이션 장르 신품 게임 코드이다. 정가보다 저렴한 가격에 빠르면 수십 초에서 5분 이내로 코드가 전송되어 선물용이나 급하게 정품을 구매하고 싶을 때 적합하며, 설치와 실행 절차도 어렵지 않다는 후기가 많다. 다만 스팀이 아닌 엑박(Xbox) 버전이라 PC에서의 접근성이 다소 떨어진다는 점, 실행 후 발생하는 오류는 그래픽카드 드라이버 업데이트 등을 직접 검색해 해결해야 하는 경우가 있다는 점, 활용도를 낮게 평가한 저평점 리뷰도 일부 존재한다는 점은 단점으로 꼽힌다.', 'ON_SALE', NOW(), NOW()),
(6780837753, (SELECT id FROM brand WHERE name = '오너클랜' LIMIT 1), (SELECT id FROM category WHERE name = '공구 > 전동공구' LIMIT 1), '[오너클랜]디지털 클램프 테스터 3280-10F', 141920, 123390, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/pd/v2/8/3/7/7/5/3/QTUhH/6780837753_B.webp', 0, '일본 HIOKI가 제조하고 오너클랜이 판매하는 디지털 클램프 테스터(AC 클램프미터) 3280-10F로, 공구>전동공구>전동공구 기타(측정기) 카테고리의 단일 상품이다. 검정 본체에 노란색 클램프가 대비를 이루고 파란색 다이얼 스위치와 LCD 숫자창을 갖췄으며, 전용 파우치와 테스트 리드선이 포함된 완제품세트 구성으로 전기설비 점검, 누전/전류 측정, 전기공사 현장에서의 휴대용 계측에 적합하다. 수집된 리뷰 데이터가 없어 실사용 장단점은 파악되지 않았다.', '{"브랜드":"오너클랜","상품유형":"측정기(클램프미터/테스터)","전원방식":null,"전압":null,"구성형태":"완제품세트","색상":"블랙","세트구성수량":null,"규격사이즈":null,"모델명":"3280-10F","제조국":"일본","제조자수입자":"HIOKI/HIOKI","KC인증정보":"상세설명참조","AS정보":"오피스넥스/0234425007","용도":["전기측정"],"소재":null,"옵션구성":null,"모음전여부":"단일상품"}', '일본 HIOKI가 제조하고 오너클랜이 판매하는 디지털 클램프 테스터(AC 클램프미터) 3280-10F로, 공구>전동공구>전동공구 기타(측정기) 카테고리의 단일 상품이다. 검정 본체에 노란색 클램프가 대비를 이루고 파란색 다이얼 스위치와 LCD 숫자창을 갖췄으며, 전용 파우치와 테스트 리드선이 포함된 완제품세트 구성으로 전기설비 점검, 누전/전류 측정, 전기공사 현장에서의 휴대용 계측에 적합하다. 수집된 리뷰 데이터가 없어 실사용 장단점은 파악되지 않았다.', 'ON_SALE', NOW(), NOW()),
(6852582823, (SELECT id FROM brand WHERE name = '아띠꼴로' LIMIT 1), (SELECT id FROM category WHERE name = '패션잡화 > 선글라스' LIMIT 1), '남자 미러 편광 선글라스 여성 고글 썬그라스 가벼운 보잉 자외선차단 여름 연예인 패션 명품 UV 자외선차단', 11300, 10170, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/6852582823/B.webp?617694108', 0, '아띠꼴로 남녀공용 보잉형 패션 선글라스로, 렌즈는 TAC, 프레임은 메탈 소재이며 쿨 블랙·클리어 실버·아이스 블루 3가지 색상 중 선택할 수 있다. 더블 브릿지의 각진 헥사곤 렌즈 실루엣에 편광·미러·자외선차단 기능을 갖춰 운전, 여행, 낚시, 등산, 골프, 워터파크 등 여름 야외활동에 데일리로 쓰기 좋다. 실리콘 코패드와 곡선형 다리 팁으로 착용감을 보완했고 구매 시 가죽 파우치형 케이스와 안경닦이가 함께 제공된다. 리뷰에서는 고급스러운 재질감과 깔끔한 마감, 가격 대비 만족도가 좋다는 평가가 많지만, 일부 구매자는 마감과 재질을 ''보통'' 수준으로 평가했고 구체적 사유 없이 낮은 별점만 남긴 후기도 있어 개인에 따라 만족도 편차가 있을 수 있다.', '{"색상":["블랙","실버","블루"],"사이즈":null,"브랜드":"아띠꼴로","제조국":"아시아/중국","소재":{"프레임재질":"메탈","렌즈재질":"TAC"},"성별":"남녀공용","선글라스종류":"패션 선글라스","렌즈기능":["UV400차단","편광","미러"],"프레임형태":"보잉형","용도":["데일리","여행용","운전용"],"세트구성":["케이스포함","안경닦이포함"],"AS보증":"042-581-3669 / 010-5828-3669, 상담 평일 09:30~17:30(점심 11:30~12:30 제외, 토일/공휴일 휴무)"}', '아띠꼴로 남녀공용 보잉형 패션 선글라스로, 렌즈는 TAC, 프레임은 메탈 소재이며 쿨 블랙·클리어 실버·아이스 블루 3가지 색상 중 선택할 수 있다. 더블 브릿지의 각진 헥사곤 렌즈 실루엣에 편광·미러·자외선차단 기능을 갖춰 운전, 여행, 낚시, 등산, 골프, 워터파크 등 여름 야외활동에 데일리로 쓰기 좋다. 실리콘 코패드와 곡선형 다리 팁으로 착용감을 보완했고 구매 시 가죽 파우치형 케이스와 안경닦이가 함께 제공된다. 리뷰에서는 고급스러운 재질감과 깔끔한 마감, 가격 대비 만족도가 좋다는 평가가 많지만, 일부 구매자는 마감과 재질을 ''보통'' 수준으로 평가했고 구체적 사유 없이 낮은 별점만 남긴 후기도 있어 개인에 따라 만족도 편차가 있을 수 있다.', 'ON_SALE', NOW(), NOW()),
(7561088629, (SELECT id FROM brand WHERE name = '리파' LIMIT 1), (SELECT id FROM category WHERE name = '몸매관리용품 > 얼굴관리' LIMIT 1), '리파 카사M1 + 바운싱크림50ml*1개', 135000, 118800, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/7561088629/B.webp?478383163', 0, '리파 카사M1과 가히(KAHI) M1 바운싱크림 50ml로 구성된 뷰티 디바이스+스킨케어 세트 상품이다. 레드, 퍼플 두 가지 색상 중 선택 가능하며, 카사M1은 전원이 필요 없는 수동형 마사지 기기로 4개의 회전 롤러가 얼굴과 목선(V라인)을 따라 밀착되어 탄력·리프팅과 붓기케어에 도움을 주도록 설계되었다. 바운싱크림은 밀도 높은 소프트 캡슐 텍스처로 보습과 영양 케어에 초점을 맞췄고, 민감성 피부 대상 자극 테스트를 거친 점을 상세페이지에서 강조한다. 다만 상품고시에는 제조국·소재·인증사항 등이 모두 ''상품상세 설명 참고''로만 표기되어 있어 구체적인 스펙 확인이 어렵고, 수집된 리뷰 데이터가 없어 실제 사용자의 장단점 평가는 확인되지 않는다.', '{"브랜드":"리파","제품유형":"세트/기획전","색상":["레드","퍼플"],"용량":"50ml","세트구성":{"구성품":["리파 카사M1 (마사지 기기)","가히(KAHI) M1 바운싱크림 50ml"]},"피부타입":"민감성","주요효능":["탄력/리프팅","보습","붓기케어"],"기능성화장품여부":null,"성별":null,"전원방식":"수동(무전원)","사용부위":["얼굴전체","목"],"제조국":null,"사용기한":null,"소재":null,"사이즈":null}', '리파 카사M1과 가히(KAHI) M1 바운싱크림 50ml로 구성된 뷰티 디바이스+스킨케어 세트 상품이다. 레드, 퍼플 두 가지 색상 중 선택 가능하며, 카사M1은 전원이 필요 없는 수동형 마사지 기기로 4개의 회전 롤러가 얼굴과 목선(V라인)을 따라 밀착되어 탄력·리프팅과 붓기케어에 도움을 주도록 설계되었다. 바운싱크림은 밀도 높은 소프트 캡슐 텍스처로 보습과 영양 케어에 초점을 맞췄고, 민감성 피부 대상 자극 테스트를 거친 점을 상세페이지에서 강조한다. 다만 상품고시에는 제조국·소재·인증사항 등이 모두 ''상품상세 설명 참고''로만 표기되어 있어 구체적인 스펙 확인이 어렵고, 수집된 리뷰 데이터가 없어 실제 사용자의 장단점 평가는 확인되지 않는다.', 'ON_SALE', NOW(), NOW()),
(7667090926, (SELECT id FROM brand WHERE name = '마이플랜트' LIMIT 1), (SELECT id FROM category WHERE name = '꽃배달 > 꽃다발' LIMIT 1), '생화 계절꽃 랜덤 어레인지먼트 사계절 제철꽃 화병 꽃배달 정기구독', 12900, 12900, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/7667090926/B.webp?690502153', 0, '마이플랜트의 계절꽃 랜덤 어레인지먼트는 장미, 리시안셔스, 거베라, 카네이션, 스타티스 등 제철 생화를 플로리스트가 파스텔톤 믹스 컬러로 구성해 크라프트지에 포장, 절화보존제와 함께 보내는 1만원대 정기구독형 꽃다발이다. 소형(7~8줄기)과 중형(10~11줄기) 두 사이즈로 주문 가능하며, 집들이 선물이나 졸업식 축하, 기념일 깜짝 선물, 평소 소확행 셀프플라워로 좋다는 평이 많다. 색감이 예쁘고 가격 대비 구성이 알차며 예정보다 빠르고 신선하게 도착했다는 긍정 후기가 다수이나, 계절 기온에 따라 꽃이 얼거나 시들어 오거나 꽃잎이 떨어지는 하자, 메인꽃 없이 사이드꽃 위주로 느껴지는 빈약함, 배송 지연으로 행사 일정에 맞추기 어려웠던 점, 상세 이미지와 실제 수령 포장·구성이 다르다는 아쉬움도 존재한다.', '{"꽃종류":"계절꽃랜덤","상품유형":"화병어레인지먼트","색상":"랜덤컬러","사이즈":["소형","중형"],"구성":"제철 생화(장미, 리시안셔스, 거베라, 카네이션, 스타티스 등)를 플로리스트가 혼합 구성; 소형 7~8줄기, 중형 10~11줄기, 절화보존제 무료 증정","포장방식":"크라프트포장","용도":["집들이","기념일","졸업","축하"],"정기구독여부":"정기구독","배송방식":"지정일배송","브랜드":"마이플랜트","제조국":"국내외혼용","카드메시지서비스":null,"가격대":"1만원대"}', '마이플랜트의 계절꽃 랜덤 어레인지먼트는 장미, 리시안셔스, 거베라, 카네이션, 스타티스 등 제철 생화를 플로리스트가 파스텔톤 믹스 컬러로 구성해 크라프트지에 포장, 절화보존제와 함께 보내는 1만원대 정기구독형 꽃다발이다. 소형(7~8줄기)과 중형(10~11줄기) 두 사이즈로 주문 가능하며, 집들이 선물이나 졸업식 축하, 기념일 깜짝 선물, 평소 소확행 셀프플라워로 좋다는 평이 많다. 색감이 예쁘고 가격 대비 구성이 알차며 예정보다 빠르고 신선하게 도착했다는 긍정 후기가 다수이나, 계절 기온에 따라 꽃이 얼거나 시들어 오거나 꽃잎이 떨어지는 하자, 메인꽃 없이 사이드꽃 위주로 느껴지는 빈약함, 배송 지연으로 행사 일정에 맞추기 어려웠던 점, 상세 이미지와 실제 수령 포장·구성이 다르다는 아쉬움도 존재한다.', 'ON_SALE', NOW(), NOW()),
(7834985776, (SELECT id FROM brand WHERE name = '11번가 판매자 55908792' LIMIT 1), (SELECT id FROM category WHERE name = '수입명품 > 럭셔리 라이프' LIMIT 1), 'CK one EDT 200ml', 40200, 40200, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/7834985776/B.webp?266628149', 0, '캘빈클라인 CK one EDT 200ml, 남녀 모두 사용 가능한 유니섹스 향수로 그린티·베르가못·카다멈의 상쾌한 시트러스 탑노트에 바이올렛·로즈·넛맥의 미들노트, 앰버·머스크의 베이스노트가 어우러진 가볍고 캐주얼한 향이다. 제조국은 스페인이며 사용기한은 2028년 12월까지다. 반투명 화이트 유리병에 실버 캡의 미니멀한 디자인으로 선물용으로도 무난하다. 리뷰에서는 빠른 배송과 정품 신뢰도, 은은하고 부담 없는 향, 합리적인 가격 덕에 재구매한다는 긍정 평가가 이어지며, 확보된 리뷰(9건) 중 저평점 사례는 없어 뚜렷한 단점은 확인되지 않았다. 다만 판매자 상세페이지에는 알코올 특유의 냄새와 향 지속시간에 대한 QnA(분사 후 안정화 필요, 향 지속력 관련 안내)가 포함되어 있어 참고가 필요하다.', '{"브랜드":"기타","상품유형":"향수","향수타입":"EDT","성별":"공용/유니섹스","용량":"200ml","제조국":"스페인","피부타입":null,"제품라인":"CK one","세트구성":"단품","전성분":"변성알코올,정제수,테트라하이드로리날룰,향료,리날룰,리모넨,시트로넬올,쿠마린,제라니올,하이드록시시트로넬알,시트랄,아이소유제놀","사용기한":"2028.12.13","색상":null,"사이즈":null,"소재":null,"SPF지수":"해당없음","태그":["정품","해외직수입","면세X"]}', '캘빈클라인 CK one EDT 200ml, 남녀 모두 사용 가능한 유니섹스 향수로 그린티·베르가못·카다멈의 상쾌한 시트러스 탑노트에 바이올렛·로즈·넛맥의 미들노트, 앰버·머스크의 베이스노트가 어우러진 가볍고 캐주얼한 향이다. 제조국은 스페인이며 사용기한은 2028년 12월까지다. 반투명 화이트 유리병에 실버 캡의 미니멀한 디자인으로 선물용으로도 무난하다. 리뷰에서는 빠른 배송과 정품 신뢰도, 은은하고 부담 없는 향, 합리적인 가격 덕에 재구매한다는 긍정 평가가 이어지며, 확보된 리뷰(9건) 중 저평점 사례는 없어 뚜렷한 단점은 확인되지 않았다. 다만 판매자 상세페이지에는 알코올 특유의 냄새와 향 지속시간에 대한 QnA(분사 후 안정화 필요, 향 지속력 관련 안내)가 포함되어 있어 참고가 필요하다.', 'ON_SALE', NOW(), NOW()),
(7936211213, (SELECT id FROM brand WHERE name = '11번가 판매자 73976762' LIMIT 1), (SELECT id FROM category WHERE name = '수입명품 > 럭셔리 라이프' LIMIT 1), '타미 걸 EDT 30ML', 40000, 40000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/7936211213/B.jpg?39234679', 0, '타미힐피거의 여성용 오 드 뜨왈렛(EDT) ''타미 걸'' 30ML 단품으로, 이탈리아에서 제조되며 개봉 전 5년·개봉 후 3년의 사용기한을 갖는다. 베르가못과 스페어민트의 상큼한 탑 노트, 자스민·로즈·아이스 티 어코드의 미들 노트, 샌달우드·앰버·머스크의 베이스 노트로 이어지는 플로럴 계열 향으로 청량하면서도 세련된 여성스러움을 표현해 데일리 사용이나 여름철, 선물용으로 어울린다. 병 디자인은 연둣빛 액체가 담긴 각진 유리병에 실버 캡과 레드 로고가 포인트이며, 레드-화이트-네이비 삼색 스트라이프의 브랜드 시그니처 패키지로 구성된다. 본사 직영몰(씨이오보떼)에서 정품 스티커와 디지털 보증서를 제공하는 정식 수입 정품이다. 리뷰는 총 4건(평점 4.0/5.0)으로 5점 3건, 1점 1건이 있으나 리뷰 본문이 남아있지 않아 구체적인 장단점 텍스트 근거는 확인되지 않는다.', '{"브랜드":"기타","상품유형":"향수","향수타입":"EDT","성별":"여성","용량":"30ml","제조국":"이탈리아","피부타입":null,"제품라인":"타미 걸(Tommy Girl)","세트구성":"단품","전성분":"변성알코올,정제수,향료,리날룰,하이드록시시트로넬알,부틸메톡시디벤조일메탄,제라니올,시트로넬올,리모넨,벤질알코올(향료),헥실신나몰,아이소유제놀,벤질벤조에이트,시트랄,파네솔,유제놀","사용기한":"제조일로부터 개봉 전 5년, 개봉 후 3년","색상":null,"사이즈":null,"소재":null,"SPF지수":"해당없음","태그":["정품","본사직영몰"]}', '타미힐피거의 여성용 오 드 뜨왈렛(EDT) ''타미 걸'' 30ML 단품으로, 이탈리아에서 제조되며 개봉 전 5년·개봉 후 3년의 사용기한을 갖는다. 베르가못과 스페어민트의 상큼한 탑 노트, 자스민·로즈·아이스 티 어코드의 미들 노트, 샌달우드·앰버·머스크의 베이스 노트로 이어지는 플로럴 계열 향으로 청량하면서도 세련된 여성스러움을 표현해 데일리 사용이나 여름철, 선물용으로 어울린다. 병 디자인은 연둣빛 액체가 담긴 각진 유리병에 실버 캡과 레드 로고가 포인트이며, 레드-화이트-네이비 삼색 스트라이프의 브랜드 시그니처 패키지로 구성된다. 본사 직영몰(씨이오보떼)에서 정품 스티커와 디지털 보증서를 제공하는 정식 수입 정품이다. 리뷰는 총 4건(평점 4.0/5.0)으로 5점 3건, 1점 1건이 있으나 리뷰 본문이 남아있지 않아 구체적인 장단점 텍스트 근거는 확인되지 않는다.', 'ON_SALE', NOW(), NOW()),
(7941982980, (SELECT id FROM brand WHERE name = '크록스' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 여성신발 > 샌들' LIMIT 1), '[크록스 본사] 바야밴드 클로그 205089-126', 54140, 54140, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/7941982980/B.webp?100221599', 0, '크록스 바야밴드 클로그 205089-126, 화이트 컬러에 네이비 로고 포인트의 남녀공용 클로그 샌들. 소재는 에틸렌비닐아세테이트(EVA)로 가볍고 발등 압박이 적은 여유로운 핏이며, 발등 펀칭홀로 통기성이 좋고 뒤꿈치 힐 스트랩을 스포츠모드/컴포트모드로 조절해 착용할 수 있다. 베트남 제조, 굽높이는 플랫(0-1cm) 타입으로 일상 편한신발, 여름 물놀이, 실내화, 캠핑 등 다양한 상황에서 신기 좋다. 리뷰에서는 가볍고 편한 착화감, 저렴한 가격 대비 좋은 품질, 깔끔한 마감과 고급스러운 재질, 정사이즈로 잘 맞는 핏이 장점으로 꼽히지만, 화이트 컬러 특성상 때가 잘 타서 쉽게 오염될 수 있고 일부 구매자는 마감과 재질을 보통 수준으로 평가하기도 했다.', '{"브랜드":"크록스","색상":"화이트","사이즈":["220","230","240","250","260","265","270","280","290","300","310"],"굽높이":"플랫(0-1cm)","스타일":"클로그","소재":"에틸렌비닐아세테이트(EVA)","성별":"남녀공용","제조국":"베트남","밑창소재":null,"세탁방법":null,"장식디테일":["펀칭","밴드"],"시즌":"봄여름(SS)","굽형태":"플랫"}', '크록스 바야밴드 클로그 205089-126, 화이트 컬러에 네이비 로고 포인트의 남녀공용 클로그 샌들. 소재는 에틸렌비닐아세테이트(EVA)로 가볍고 발등 압박이 적은 여유로운 핏이며, 발등 펀칭홀로 통기성이 좋고 뒤꿈치 힐 스트랩을 스포츠모드/컴포트모드로 조절해 착용할 수 있다. 베트남 제조, 굽높이는 플랫(0-1cm) 타입으로 일상 편한신발, 여름 물놀이, 실내화, 캠핑 등 다양한 상황에서 신기 좋다. 리뷰에서는 가볍고 편한 착화감, 저렴한 가격 대비 좋은 품질, 깔끔한 마감과 고급스러운 재질, 정사이즈로 잘 맞는 핏이 장점으로 꼽히지만, 화이트 컬러 특성상 때가 잘 타서 쉽게 오염될 수 있고 일부 구매자는 마감과 재질을 보통 수준으로 평가하기도 했다.', 'ON_SALE', NOW(), NOW()),
(8108120723, (SELECT id FROM brand WHERE name = '산과들에' LIMIT 1), (SELECT id FROM category WHERE name = '건과/견과 > 견과류' LIMIT 1), '[산과들에] 피칸담은 하루견과 순수다움 100봉 (고급견과류간식)', 53500, 50290, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/8108120723/B.webp?262675821', 0, '산과들에의 순수다움 하루견과 100봉은 피칸·호두·아몬드·캐슈넛을 볶아 만든 혼합 견과류 간식으로, 1회분 20g씩 낱개 포장되어 휴대와 보관이 간편하다. HACCP·ISO 9001·ISO 22000 인증을 받은 제품으로 사무실 간식, 다이어트 및 헬스 보충용, 출출할 때 간편하게 섭취하기 좋은 상황에 적합하다. 구매 리뷰에서는 신선하고 고소한 맛과 타 사이트 대비 좋은 가성비가 반복적으로 언급되며 꾸준히 재구매하는 후기가 많았으나, 저평점 리뷰에는 구체적인 불만 텍스트가 남아있지 않아 뚜렷한 단점 근거는 확인되지 않았다.', '{"견과종류":"하루견과(혼합)","가공형태":"볶음(로스팅)","껍질유무":"깐것(탈각)","간여부":null,"총중량":"20g x 100봉","포장단위":"20g x 100봉","상품구성":"혼합구성(믹스)","원산지":null,"수입여부":null,"브랜드":"산과들에","알레르기유발물질":["땅콩","호두"],"소비기한":null,"보관방법":null,"유전자변형여부":null,"용도":"간식용","옵션구성":null}', '산과들에의 순수다움 하루견과 100봉은 피칸·호두·아몬드·캐슈넛을 볶아 만든 혼합 견과류 간식으로, 1회분 20g씩 낱개 포장되어 휴대와 보관이 간편하다. HACCP·ISO 9001·ISO 22000 인증을 받은 제품으로 사무실 간식, 다이어트 및 헬스 보충용, 출출할 때 간편하게 섭취하기 좋은 상황에 적합하다. 구매 리뷰에서는 신선하고 고소한 맛과 타 사이트 대비 좋은 가성비가 반복적으로 언급되며 꾸준히 재구매하는 후기가 많았으나, 저평점 리뷰에는 구체적인 불만 텍스트가 남아있지 않아 뚜렷한 단점 근거는 확인되지 않았다.', 'ON_SALE', NOW(), NOW())
