(8164281360, (SELECT id FROM brand WHERE name = '키플링' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 여행가방 > 소프트 캐리어' LIMIT 1), '기내용캐리어 뉴유리스핀S 블랙누아르 KOABY01 BK/N', 240000, 230400, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/8164281360/B.webp?238530356', 0, '키플링 뉴유리스핀S 블랙누아르 기내용 소프트 캐리어(20인치, 33리터, 55x35x23cm)로, 겉감 나일론과 안감 재생폴리에스터를 혼방한 가벼운 소재에 생활방수 기능을 갖췄다. 무광 블랙 바디에 키플링 시그니처 몽키 참이 달려 있고, 앞면에는 상단 소형·하단 대형 지퍼포켓이 이중으로 배치되어 있으며, 내부는 지도 프린트 패턴의 그레이 안감과 상하단 지퍼 메쉬 포켓으로 짐 정리가 용이하다. 4륜 스피너 바퀴와 2단 신축식 트롤리 손잡이로 이동이 편리해 국내외 단기 여행이나 1~3박 출장용 기내 반입 캐리어로 적합하다. 세탁은 불가하며, 정품 보증서가 있어야 AS(지퍼·박음질·바퀴·웨빙손잡이 등)가 가능하다.', '{"브랜드":"키플링","색상":"블랙누아르","사이즈":"20인치","기내용여부":"기내용","용량":"33리터","중량":null,"규격":"55 x 35 x 23 CM","소재":"혼방","바퀴타입":"4륜(스피너)","잠금장치":null,"방수여부":"발수/방수","확장기능":null,"제조국":null,"제조자수입자":"VF사//(주)리노스","세탁방법":"세탁불가","구성세트":"단품","품질보증기준":"관련법 및 소비자분쟁해결 기준에 따름","AS책임자연락처":"(주)리노스//02)3489-6415","태그":["기내용","경량","4륜","스피너","생활방수"]}', '키플링 뉴유리스핀S 블랙누아르 기내용 소프트 캐리어(20인치, 33리터, 55x35x23cm)로, 겉감 나일론과 안감 재생폴리에스터를 혼방한 가벼운 소재에 생활방수 기능을 갖췄다. 무광 블랙 바디에 키플링 시그니처 몽키 참이 달려 있고, 앞면에는 상단 소형·하단 대형 지퍼포켓이 이중으로 배치되어 있으며, 내부는 지도 프린트 패턴의 그레이 안감과 상하단 지퍼 메쉬 포켓으로 짐 정리가 용이하다. 4륜 스피너 바퀴와 2단 신축식 트롤리 손잡이로 이동이 편리해 국내외 단기 여행이나 1~3박 출장용 기내 반입 캐리어로 적합하다. 세탁은 불가하며, 정품 보증서가 있어야 AS(지퍼·박음질·바퀴·웨빙손잡이 등)가 가능하다.', 'ON_SALE', NOW(), NOW()),
(8324347759, (SELECT id FROM brand WHERE name = '소다' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 여성신발 > 오픈슈즈' LIMIT 1), '[소다][소다] FLD324 KS10 세미드레스 샌들 5센치굽 (P003616477)', 148000, 128010, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/8324347759/B.webp?61565394', 0, '소다 FLD324 세미드레스 샌들은 스퀘어 오픈토와 슬링백 골드 버클 스트랩이 특징인 5cm 블록힐 샌들로, 천연 소가죽 갑피와 밑창 테두리의 골드 메탈릭 라인 장식이 세미포멀한 무드를 더한다. 연베이지와 흑색 두 컬러, 225~250 사이즈로 구성되어 출근룩이나 여름 데일리룩에 두루 활용하기 좋으며, 퀄팅 인솔로 착화감을 보강했다. 아직 수집된 리뷰가 없어 실제 착용 후기 기반의 장단점은 확인되지 않았다.', '{"브랜드":"소다","색상":["베이지","블랙"],"사이즈":["225","230","235","240","245","250"],"신발타입":"샌들","굽높이":"미드힐(3~5cm)","소재":["천연가죽","소가죽"],"여밈방식":"스트랩","성별":"여성","제조국":"대한민국","제조자수입자":"디에프디인터내셔날","관리방법":null,"품질보증기준":"관련법 및 소비자분쟁해결기준에 따름","AS책임자":null,"주문제작여부":null,"옵션구성":{"axes":["색상/사이즈"],"combinations":["연베이지/225","연베이지/230","연베이지/235","연베이지/240","연베이지/245","연베이지/250","흑색/225","흑색/230","흑색/235","흑색/240","흑색/245","흑색/250"]}}', '소다 FLD324 세미드레스 샌들은 스퀘어 오픈토와 슬링백 골드 버클 스트랩이 특징인 5cm 블록힐 샌들로, 천연 소가죽 갑피와 밑창 테두리의 골드 메탈릭 라인 장식이 세미포멀한 무드를 더한다. 연베이지와 흑색 두 컬러, 225~250 사이즈로 구성되어 출근룩이나 여름 데일리룩에 두루 활용하기 좋으며, 퀄팅 인솔로 착화감을 보강했다. 아직 수집된 리뷰가 없어 실제 착용 후기 기반의 장단점은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(8375373607, (SELECT id FROM brand WHERE name = '캉골' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 남성가방 > 토트백' LIMIT 1), '[롯데백화점]캉골 뉴 타이니 캔버스 미니토트백 4004 블랙 (KRFBTB40040)', 52000, 44000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/8375373607/B.webp?768268102', 0, '캉골 뉴 타이니 캔버스 미니토트백(KRFBTB40040)은 블랙 컬러 면 100% 캔버스 원단에 폴리에스터 안감을 댄 남성용 미니 토트백으로, 가로20 x 세로21 x 폭14cm의 컴팩트한 사이즈에 무게 약 315g으로 가볍게 들기 좋다. 짧은 핸들과 길이조절이 가능한 카라비너형 탈부착 크로스 스트랩을 함께 갖춰 토트백과 크로스백 스타일링을 모두 소화할 수 있고, 입구에는 스냅 단추 여밈과 내부 오픈 포켓이 있어 소지품을 간단히 분리 수납할 수 있다. 정면 하단에 화이트 캉골 캥거루 로고가 포인트로 프린트되어 있어 가벼운 외출이나 포인트 아이템으로 활용하기 좋으며, 중국에서 제조되었다. 세탁 및 드라이클리닝은 불가하고 마른천 관리만 가능하며 원단 특성상 보풀이 발생할 수 있다는 점, 정품 상품고시 크기(가로25 x 세로22 x 폭11cm)와 상세페이지 사이즈컷 표기가 서로 달라 실측 시 혼동될 수 있다는 점은 참고가 필요하다.', '{"브랜드":"캉골","색상":["블랙"],"사이즈":{"너비_cm":20,"높이_cm":21,"폭_cm":14,"비고":"notice 표기(가로25 x 세로22 x 폭11cm)와 상세 사이즈컷 표기(너비20 x 높이21 x 폭14cm)가 상이하여 상세 사이즈컷(OS) 기준값 채택"},"소재":"캔버스(면)","성별":"남성","가방형태":"미니토트백","개폐방식":"자석 잠금","스트랩타입":"탈부착 스트랩","장식디테일":["로고장식"],"제조국":"중국","세탁방법":"가방은 목적에 맞게 사용하십시오. 세탁 및 드라이클리닝은 하지마십시오. 오염시 마른천등으로 용도에 맞게 가볍게 닦아주십시오. 습기에 유의하십시오. 원단특성상 보풀이 발생할수 있으므로 유의하십시오.","제조자수입자":"에스제이그룹//에스제이그룹","품질보증기준":"관련법 및 소비자분쟁해결기준에 따름","AS책임자":"에스제이그룹//1899-0186","부가기능":["내부수납포켓"]}', '캉골 뉴 타이니 캔버스 미니토트백(KRFBTB40040)은 블랙 컬러 면 100% 캔버스 원단에 폴리에스터 안감을 댄 남성용 미니 토트백으로, 가로20 x 세로21 x 폭14cm의 컴팩트한 사이즈에 무게 약 315g으로 가볍게 들기 좋다. 짧은 핸들과 길이조절이 가능한 카라비너형 탈부착 크로스 스트랩을 함께 갖춰 토트백과 크로스백 스타일링을 모두 소화할 수 있고, 입구에는 스냅 단추 여밈과 내부 오픈 포켓이 있어 소지품을 간단히 분리 수납할 수 있다. 정면 하단에 화이트 캉골 캥거루 로고가 포인트로 프린트되어 있어 가벼운 외출이나 포인트 아이템으로 활용하기 좋으며, 중국에서 제조되었다. 세탁 및 드라이클리닝은 불가하고 마른천 관리만 가능하며 원단 특성상 보풀이 발생할 수 있다는 점, 정품 상품고시 크기(가로25 x 세로22 x 폭11cm)와 상세페이지 사이즈컷 표기가 서로 달라 실측 시 혼동될 수 있다는 점은 참고가 필요하다.', 'ON_SALE', NOW(), NOW()),
(8662121210, (SELECT id FROM brand WHERE name = '닥터지' LIMIT 1), (SELECT id FROM category WHERE name = '몸매관리용품 > 가슴관리' LIMIT 1), '닥터지레드 블레미쉬 클리어 수딩크림 50x2 + 10x2', 31200, 30580, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/8662121210/B.webp?745496328', 0, '대한민국 코스맥스에서 제조한 닥터지 R.E.D 블레미쉬 클리어 수딩크림으로, 50mL 자쿠리 크림 2개와 10mL 튜브 크림 2개로 구성된 세트 제품이다. 민감피부, 트러블피부, 여드름피부, 붉은기 피부를 위한 진정·보습 크림으로 판테놀, 병풀추출물, 마데카소사이드, 아시아티코사이드 등 시카 성분을 함유하고 있으며 화이트와 그린 톤의 미니멀한 패키지에 본품과 미니 사이즈가 함께 담겨 선물용으로도 활용하기 좋다. 다만 이 제품에 대한 수집된 리뷰 데이터가 없어 실제 사용자 평가에 기반한 장단점은 확인되지 않았다.', '{"브랜드":"닥터지","제품유형":"크림","기능":["보습"],"용량":"50mL x2 + 10mL x2","구성":"50mL 크림 2개 + 10mL 크림 2개 세트","피부타입":"민감성","주요성분":["판테놀","베타-글루칸","병풀추출물","마데카소사이드","아시아티코사이드","마데카식애씨드"],"사용부위":null,"사이즈":null,"색상":null,"소재":null,"전원방식":"해당없음","사용기한":"유통기한 36개월, 개봉 후 사용기간 12개월","사용방법":"적당량을 덜어 얼굴에 골고루 펴 바른 후 흡수시켜 줍니다.","제조국":"대한민국","기능성화장품여부":"대상아님","품질보증기준":"관련 법령 및 공정거래위원회의 소비자 분쟁해결 기준에 따름","판매자":"pjm1693"}', '대한민국 코스맥스에서 제조한 닥터지 R.E.D 블레미쉬 클리어 수딩크림으로, 50mL 자쿠리 크림 2개와 10mL 튜브 크림 2개로 구성된 세트 제품이다. 민감피부, 트러블피부, 여드름피부, 붉은기 피부를 위한 진정·보습 크림으로 판테놀, 병풀추출물, 마데카소사이드, 아시아티코사이드 등 시카 성분을 함유하고 있으며 화이트와 그린 톤의 미니멀한 패키지에 본품과 미니 사이즈가 함께 담겨 선물용으로도 활용하기 좋다. 다만 이 제품에 대한 수집된 리뷰 데이터가 없어 실제 사용자 평가에 기반한 장단점은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(8778377338, (SELECT id FROM brand WHERE name = '루즈앤라운지' LIMIT 1), (SELECT id FROM category WHERE name = '여성가방 > 클러치백' LIMIT 1), '알베로 클러치백 RA2F9ABG192WBS-J', 207900, 158300, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/8778377338/B.webp?919159455', 0, '루즈앤라운지 알베로 클러치백(모델명 RA2F9ABG192WBS-J)은 브라운슈가 컬러의 크랙 텍스처 소가죽으로 제작된 단일사이즈 여성 클러치백이다. 가방 바닥이 완만하게 굴곡진 언덕형 실루엣과 전면 정사각 로고 장식이 특징이며, 상단은 지퍼로 여미고 내부는 폴리에스터 안감에 오픈포켓 1개, 지퍼포켓 1개, 카드 라벨 1개가 있어 소지품을 실용적으로 정리할 수 있다. 32~60cm 길이로 탈부착 및 조절이 가능한 롱스트랩이 있어 클러치처럼 손에 들거나 숄더·크로스백으로도 연출할 수 있는 다목적 디자인으로, 무지 패턴의 데일리·오피스룩에 두루 매치하기 좋다. 다만 소재 특성상 표면이 벗겨지거나 물/열에 의해 변형되기 쉽고 장시간 일광노출 시 변색될 수 있어 세탁이 불가능하고 관리에 주의가 필요하며, 판매 페이지에 수집된 리뷰가 없어 실사용 만족도나 하자 발생 빈도는 확인되지 않았다.', '{"브랜드":"루즈앤라운지","색상":"브라운","사이즈":"단일사이즈(Free)","실측사이즈":{"가로":"22(27)cm","세로":"15cm","폭(마대)":"16cm","손잡이길이":null,"스트랩길이":"32~60cm"},"소재":"소가죽","세부종류":"클러치백","패턴":"무지","개폐방식":"지퍼","휴대방식":"탈부착스트랩(숄더겸용)","성별":"여성","스타일태그":["데일리","오피스"],"제조국":"대한민국","모델명":"RA2F9ABG192WBS-J","품질보증기준":"관련법 및 소비자분쟁해결 규정에 따름","세탁관리방법":"절대 세탁 금지, 물/난방기구/열로 인한 변형 및 장시간 일광노출 시 변색 우려, 마찰이나 수분에 의한 이염 및 탈변색 가능","AS책임자및전화번호":"(주)한섬, 1800-5700","가격대":"10-30만원","재고상태":"재고있음"}', '루즈앤라운지 알베로 클러치백(모델명 RA2F9ABG192WBS-J)은 브라운슈가 컬러의 크랙 텍스처 소가죽으로 제작된 단일사이즈 여성 클러치백이다. 가방 바닥이 완만하게 굴곡진 언덕형 실루엣과 전면 정사각 로고 장식이 특징이며, 상단은 지퍼로 여미고 내부는 폴리에스터 안감에 오픈포켓 1개, 지퍼포켓 1개, 카드 라벨 1개가 있어 소지품을 실용적으로 정리할 수 있다. 32~60cm 길이로 탈부착 및 조절이 가능한 롱스트랩이 있어 클러치처럼 손에 들거나 숄더·크로스백으로도 연출할 수 있는 다목적 디자인으로, 무지 패턴의 데일리·오피스룩에 두루 매치하기 좋다. 다만 소재 특성상 표면이 벗겨지거나 물/열에 의해 변형되기 쉽고 장시간 일광노출 시 변색될 수 있어 세탁이 불가능하고 관리에 주의가 필요하며, 판매 페이지에 수집된 리뷰가 없어 실사용 만족도나 하자 발생 빈도는 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
