(8824944130, (SELECT id FROM brand WHERE name = '베베숲(Bebesup)' LIMIT 1), (SELECT id FROM category WHERE name = '물티슈 > 물티슈액세서리' LIMIT 1), '베베숲 물티슈 트러스트 프리미엄 80매 X 20개 (1박스)  정말 도톰한 두꺼운 프리미엄 물티슈', 27000, 27000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/8824944130/B.webp?680958397', 0, '베베숲(Bebesup) 트러스트 프리미엄 물티슈로 80매 캡형 낱개팩 20개가 들어있는 메가팩 대용량 박스 구성이며 55gsm 도톰한 두께의 유아용 물티슈다. 무전원 캡형 리필 구성으로 전동 워머나 별도 기기 없이 바로 사용할 수 있고, 대한민국에서 제조되었다. 리뷰에서는 저렴한 가격 대비 가성비가 좋고 엠보싱이 적당해 부담없이 쓰기 좋다는 긍정 평가가 많았으며, 별다른 품질 불만은 확인되지 않았다. 대용량으로 자주 구매해야 하는 신생아·유아 가정의 상비 물티슈나 출산 선물용으로 적합하다.', '{"상품유형":"리필커버","색상":null,"사이즈":null,"소재":null,"호환물티슈규격":"80매 캡형 x 20개입, 55gsm","전원방식":"무전원(비전동)","사용대상":"유아용","부착방식":null,"브랜드":"베베숲(Bebesup)","제조국":"대한민국","세트구성":{"구성수량":20,"단위":"팩","매수_팩당":80},"디자인패턴":null}', '베베숲(Bebesup) 트러스트 프리미엄 물티슈로 80매 캡형 낱개팩 20개가 들어있는 메가팩 대용량 박스 구성이며 55gsm 도톰한 두께의 유아용 물티슈다. 무전원 캡형 리필 구성으로 전동 워머나 별도 기기 없이 바로 사용할 수 있고, 대한민국에서 제조되었다. 리뷰에서는 저렴한 가격 대비 가성비가 좋고 엠보싱이 적당해 부담없이 쓰기 좋다는 긍정 평가가 많았으며, 별다른 품질 불만은 확인되지 않았다. 대용량으로 자주 구매해야 하는 신생아·유아 가정의 상비 물티슈나 출산 선물용으로 적합하다.', 'ON_SALE', NOW(), NOW()),
(8900943530, (SELECT id FROM brand WHERE name = '캐츠랑' LIMIT 1), (SELECT id FROM category WHERE name = '고양이용품 > 간식' LIMIT 1), '캐츠랑 비타플러스 전연령 20kg 1개', 60900, 60900, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/8900943530/B.webp?7552873', 0, '캐츠랑 비타플러스 전연령 20kg 1개는 닭과 참치를 주원료로 하고 곡물이 포함된 건식 사료로, 조단백 32% 이상·조지방 12% 이상의 영양 구성과 HACCP 인증, All Life Stages(전연령용) 표기를 갖춘 대용량 단일구성 제품이다. 원산지는 국산(충청남도 서천군)이며 입자크기 보통(8~13mm)에 단단한 정도는 하드로, 다묘가정이나 장기간 사료를 비축해두고 급여하려는 보호자에게 적합하다. 가격은 60,900원으로 4% 할인이 적용되어 있으며, 현재까지 수집된 리뷰 데이터가 없어 실사용자의 평점이나 장단점 후기는 확인되지 않는다.', '{"브랜드":"캐츠랑","간식형태":"건어물/슬라이스","주원료":"기타","중량":"20kg","수량":"1개","총내용량":"20kg","옵션구성":"단일구성","곡물함유여부":"곡물포함","제조국":"한국","제조사수입자":null,"소비기한":null,"적용대상연령":"전연령","식품유형":null,"판매가":"60900","할인율":"4","평점":null}', '캐츠랑 비타플러스 전연령 20kg 1개는 닭과 참치를 주원료로 하고 곡물이 포함된 건식 사료로, 조단백 32% 이상·조지방 12% 이상의 영양 구성과 HACCP 인증, All Life Stages(전연령용) 표기를 갖춘 대용량 단일구성 제품이다. 원산지는 국산(충청남도 서천군)이며 입자크기 보통(8~13mm)에 단단한 정도는 하드로, 다묘가정이나 장기간 사료를 비축해두고 급여하려는 보호자에게 적합하다. 가격은 60,900원으로 4% 할인이 적용되어 있으며, 현재까지 수집된 리뷰 데이터가 없어 실사용자의 평점이나 장단점 후기는 확인되지 않는다.', 'ON_SALE', NOW(), NOW()),
(8983095732, (SELECT id FROM brand WHERE name = '11번가 판매자 76154013' LIMIT 1), (SELECT id FROM category WHERE name = 'DIY자재/용품 > 반제품' LIMIT 1), '옷걸이 고정식 920 2단행거 10행거 고정식옷걸이 10옷행거', 44820, 43930, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/8983095732/B.webp?912961536', 0, '화이트 색상의 28mm 스틸 기둥으로 제작된 고정식 2단 행거로, 천장과 바닥 사이에 나사조임과 내장 강철스프링으로 압착 고정해 별도의 벽 타공 없이 원룸이나 드레스룸에 설치할 수 있는 DIY 반제품이다. 폭 800~1500mm, 높이 1300~2600mm 범위에서 나사조임 방식으로 간편하게 사이즈를 조절할 수 있어 공간에 맞춰 옷장을 대체하거나 이사 후 임시 수납 용도로 활용하기 좋다. 상단 가로봉에는 셔츠 등 상의를, 하단 가로봉에는 바지 등 하의를 나눠 걸 수 있는 2단 구조이며, 세로기둥 상하단 조임나사와 바닥고무, 가로봉 연결부 조임나사로 흔들림을 줄이도록 설계되었다. 다만 나사조임 압착 고정 방식 특성상 천장 재질이나 높이에 따라 고정력 편차가 발생할 수 있고 조립형 반제품이라 직접 설치 과정이 필요하다는 점은 구매 전 감안해야 하며, 수집된 리뷰 데이터가 없어 실제 사용자 만족도나 하자 발생률은 확인되지 않았다.', '{"상품유형":"행거","색상":"화이트","사이즈":{"폭":"800~1500mm (조절식)","높이":"1300~2600mm (조절식)","기둥직경":"28mm"},"소재":"스틸","브랜드":null,"제조국":null,"구성품":"2단 고정식 행거(세로기둥 2개, 가로봉 2개), 조임나사, 바닥고무, 강철스프링","구성수량":null,"조립여부":"조립필요(반제품)","최대하중":null,"바퀴여부":null,"무소음여부":null,"용도":["가정","수납/정리"],"설치방식":"고정식","KC인증정보":null,"품질보증기준":null,"제조자수입자":null,"AS정보":null}', '화이트 색상의 28mm 스틸 기둥으로 제작된 고정식 2단 행거로, 천장과 바닥 사이에 나사조임과 내장 강철스프링으로 압착 고정해 별도의 벽 타공 없이 원룸이나 드레스룸에 설치할 수 있는 DIY 반제품이다. 폭 800~1500mm, 높이 1300~2600mm 범위에서 나사조임 방식으로 간편하게 사이즈를 조절할 수 있어 공간에 맞춰 옷장을 대체하거나 이사 후 임시 수납 용도로 활용하기 좋다. 상단 가로봉에는 셔츠 등 상의를, 하단 가로봉에는 바지 등 하의를 나눠 걸 수 있는 2단 구조이며, 세로기둥 상하단 조임나사와 바닥고무, 가로봉 연결부 조임나사로 흔들림을 줄이도록 설계되었다. 다만 나사조임 압착 고정 방식 특성상 천장 재질이나 높이에 따라 고정력 편차가 발생할 수 있고 조립형 반제품이라 직접 설치 과정이 필요하다는 점은 구매 전 감안해야 하며, 수집된 리뷰 데이터가 없어 실제 사용자 만족도나 하자 발생률은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9082737248, (SELECT id FROM brand WHERE name = 'Vetoquinol(베토키놀)' LIMIT 1), (SELECT id FROM category WHERE name = '고양이용품 > 영양제' LIMIT 1), '아조딜 90캡슐 신장질환 보조제 4451314', 138000, 131100, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9082737248/B.webp?28509163', 0, '아조딜(Azodyl) 90캡슐은 고양이·강아지의 신장/간 건강 관리를 위한 프로바이오틱스 보조제로, 위산에 강한 내산성(Acid-Resistant) 캡슐 형태로 제작되어 신부전이 있는 반려묘의 콩팥 건강 관리 상황에 적합합니다. 흰색 병에 빨간 뚜껑, ''SUPPORTS KIDNEYS'' 뱃지가 표기된 Vetoquinol 브랜드 제품이며 단일상품(모음전 아님)으로 판매됩니다. 다만 상품고시에는 브랜드·원산지·제조자 정보가 ''상품상세페이지 참조''로만 표기되어 있어 상세 성분표나 원산지 등 구체적 정보가 부족하고, 수집된 리뷰가 없어 실제 급여 효과나 기호성에 대한 소비자 평가는 확인되지 않는 점은 참고가 필요합니다.', '{"영양제유형":"신장/간영양제","브랜드":"Vetoquinol(베토키놀)","제형":"캡슐","용량":"90캡슐","주요성분":["프로바이오틱스"],"건강기능식품여부":null,"적용연령":null,"원산지":null,"구성수량":null,"옵션":null,"모음전여부":"단일상품"}', '아조딜(Azodyl) 90캡슐은 고양이·강아지의 신장/간 건강 관리를 위한 프로바이오틱스 보조제로, 위산에 강한 내산성(Acid-Resistant) 캡슐 형태로 제작되어 신부전이 있는 반려묘의 콩팥 건강 관리 상황에 적합합니다. 흰색 병에 빨간 뚜껑, ''SUPPORTS KIDNEYS'' 뱃지가 표기된 Vetoquinol 브랜드 제품이며 단일상품(모음전 아님)으로 판매됩니다. 다만 상품고시에는 브랜드·원산지·제조자 정보가 ''상품상세페이지 참조''로만 표기되어 있어 상세 성분표나 원산지 등 구체적 정보가 부족하고, 수집된 리뷰가 없어 실제 급여 효과나 기호성에 대한 소비자 평가는 확인되지 않는 점은 참고가 필요합니다.', 'ON_SALE', NOW(), NOW()),
(9090455596, (SELECT id FROM brand WHERE name = '폰타나' LIMIT 1), (SELECT id FROM category WHERE name = '가공식품 > 면류/국수' LIMIT 1), '폰타나 카르니아 크림 파스타소스 430g 3개 + 스파게티면 500g', 33000, 33000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9090455596/B.webp?256477447', 0, '폰타나 카르니아 베이컨&머쉬룸 크림 파스타소스 430g 3개와 이탈리아산 세몰리나 듀럼밀 100% 스파게티면 500g을 함께 구성한 크림파스타 세트로, 유리병 소스는 국내 진푸드에서 제조하고 면은 이탈리아 OEM으로 수입된다. 밀, 대두, 우유, 계란, 돼지고기, 닭고기, 쇠고기 알레르기 유발물질을 포함하며 상온 보관 제품으로 소비기한 여유를 두고 배송된다. 소스와 면이 세트로 구성돼 별도 구매 없이 바로 크림파스타를 조리할 수 있어 자취생 간편식이나 홈파티, 손님 초대상 요리에 적합하다. 수집된 리뷰 데이터가 없어 실제 사용자 평가에 근거한 장단점은 확인할 수 없다.', '{"브랜드":"폰타나","면종류":"스파게티/파스타면","식품유형":"소스류","맛종류":"크림","포장중량":"카르니아 크림 파스타소스 430g x3, 스파게티면 500g x1","묶음수량":null,"세트구성":"카르니아 베이컨&머쉬룸 크림 파스타소스 430g 3개 + 이탈리아 캄파니아 스파게티면 500g","원산지제조국":"소스: 국내 제조((주)진푸드, 경기도 화성시), 화이트루 밀 미국산; 면: 이탈리아산(OEM, 세몰리나 100% 듀럼밀)","곡물원료":["밀"],"알레르기유발물질":["밀","대두","우유","계란","돼지고기","닭고기","쇠고기"],"유통기한소비기한":"수시입출고로 인하여 정확한 소비기한 기재가 어려우나 여유있는 상품으로 배송","보관방법":"상온","유전자변형식품여부":"N","옵션선택":null}', '폰타나 카르니아 베이컨&머쉬룸 크림 파스타소스 430g 3개와 이탈리아산 세몰리나 듀럼밀 100% 스파게티면 500g을 함께 구성한 크림파스타 세트로, 유리병 소스는 국내 진푸드에서 제조하고 면은 이탈리아 OEM으로 수입된다. 밀, 대두, 우유, 계란, 돼지고기, 닭고기, 쇠고기 알레르기 유발물질을 포함하며 상온 보관 제품으로 소비기한 여유를 두고 배송된다. 소스와 면이 세트로 구성돼 별도 구매 없이 바로 크림파스타를 조리할 수 있어 자취생 간편식이나 홈파티, 손님 초대상 요리에 적합하다. 수집된 리뷰 데이터가 없어 실제 사용자 평가에 근거한 장단점은 확인할 수 없다.', 'ON_SALE', NOW(), NOW()),
(9110862068, (SELECT id FROM brand WHERE name = '쌤소나이트 레드' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 남성가방 > 백팩' LIMIT 1), '[쌤소나이트] N 직장인비지니스 백팩 - 유클리드 HR009001', 135000, 101000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/dl/v2/8/6/2/0/6/8/VePdF/9110862068_234283329.jpg', 0, '쌤소나이트 레드의 블랙 컬러 비즈니스 백팩으로, 폴리에스터 소재에 사이즈는 31x11.5x46cm이며 15인치 노트북 수납이 가능하다. 심플한 스퀘어 실루엣에 전면 지퍼 포켓과 하단 가죽 느낌 로고 패널이 포인트이며, 메인 수납 1단과 지퍼 포켓 2개, 물통 포켓 2개로 구성되어 출퇴근이나 노트북을 들고 다니는 직장인의 통근용으로 적합하다. 리뷰에서는 마감이 깔끔하고 재질이 고급스러우며 가볍고 세련된 디자인에 가격까지 합리적이라는 장점이 반복적으로 언급되지만, 일부 구매자는 수납력이 기대보다 아쉽고 생각보다 크기가 작다는 점을 단점으로 지적했다.', '{"브랜드":"쌤소나이트 레드","색상":"블랙","사이즈":"31 x 11.5 x 46 cm","소재":"폴리에스터","종류":"비즈니스백팩","제조국":null,"제조자수입자":null,"용량":null,"노트북수납여부":"가능","성별":"남성용","스타일무드":"비즈니스/정장","방수여부":"해당없음","개폐방식":"지퍼","세탁관리방법":null,"품질보증기준":null,"AS안내":null,"시즌":null,"옵션구성":null,"태그":["직장인","비즈니스백팩","노트북가방","심플캐주얼","유클리드"]}', '쌤소나이트 레드의 블랙 컬러 비즈니스 백팩으로, 폴리에스터 소재에 사이즈는 31x11.5x46cm이며 15인치 노트북 수납이 가능하다. 심플한 스퀘어 실루엣에 전면 지퍼 포켓과 하단 가죽 느낌 로고 패널이 포인트이며, 메인 수납 1단과 지퍼 포켓 2개, 물통 포켓 2개로 구성되어 출퇴근이나 노트북을 들고 다니는 직장인의 통근용으로 적합하다. 리뷰에서는 마감이 깔끔하고 재질이 고급스러우며 가볍고 세련된 디자인에 가격까지 합리적이라는 장점이 반복적으로 언급되지만, 일부 구매자는 수납력이 기대보다 아쉽고 생각보다 크기가 작다는 점을 단점으로 지적했다.', 'ON_SALE', NOW(), NOW()),
(9125386328, (SELECT id FROM brand WHERE name = '닥터지' LIMIT 1), (SELECT id FROM category WHERE name = '메이크업 > 치크/하이라이터' LIMIT 1), '닥터지 블랙 스네일 크림 50ml x 2', 35600, 35600, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9125386328/B.webp?16078018', 0, '닥터지 브랜드의 블랙 스네일 크림 50mL 2개 구성 세트로, 달팽이점액여과물 20%가 함유된 미백·주름개선 2중 기능성 크림입니다. 네이비 유리 용기와 골드 뚜껑의 고급스러운 디자인에 미니 스파츌라가 함께 제공되어 데일리 스킨케어 마무리 단계에 사용하기 좋고, 2개 구성으로 선물용이나 장기간 사용에도 적합합니다. 다만 11번가 카테고리상 치크/블러셔로 분류되어 있으나 실제로는 색조 발색 제품이 아닌 스킨케어 크림으로, 색상·발색력·마무리톤 등 색조 관련 속성은 해당 정보가 없으며, 현재 수집된 리뷰 데이터가 없어 실사용 장단점은 확인되지 않았습니다.', '{"브랜드":"닥터지","제형타입":"크림","제품분류":"블러셔/치크","색상":null,"용량":"50mL","피부타입":null,"발색력":null,"마무리톤":null,"구성수량":"2개","기능성":["미백","주름개선"],"사용부위":null,"제조국":null,"제조판매업체":"㈜고운세상코스메틱(화장품책임판매업자), 한국콜마㈜(제조업자)","사용기한":null,"증정품포함여부":"단품"}', '닥터지 브랜드의 블랙 스네일 크림 50mL 2개 구성 세트로, 달팽이점액여과물 20%가 함유된 미백·주름개선 2중 기능성 크림입니다. 네이비 유리 용기와 골드 뚜껑의 고급스러운 디자인에 미니 스파츌라가 함께 제공되어 데일리 스킨케어 마무리 단계에 사용하기 좋고, 2개 구성으로 선물용이나 장기간 사용에도 적합합니다. 다만 11번가 카테고리상 치크/블러셔로 분류되어 있으나 실제로는 색조 발색 제품이 아닌 스킨케어 크림으로, 색상·발색력·마무리톤 등 색조 관련 속성은 해당 정보가 없으며, 현재 수집된 리뷰 데이터가 없어 실사용 장단점은 확인되지 않았습니다.', 'ON_SALE', NOW(), NOW()),
(9139287871, (SELECT id FROM brand WHERE name = '유세븐' LIMIT 1), (SELECT id FROM category WHERE name = '남성신발 > 기능화' LIMIT 1), '유세븐 남자 메쉬 데일리 런닝화 발편한 작업화 경량 운동화 DM252', 23900, 23900, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9139287871/B.webp?834720037', 0, '유세븐 남자 메쉬 데일리 런닝화 DM252는 그레이·블랙 2가지 색상과 250~280 전 사이즈 옵션을 갖춘 남성용 경량 러닝화다. 통기성 좋은 니트 메쉬 갑피와 U-CELLON EVA 미드솔을 적용해 쿠셔닝과 반발력을 강화했고, 두꺼운 통굽형 밑창과 발볼넓이 10.5cm의 와이드 설계로 편안한 착화감을 준다. 끈 조임 방식에 뒤꿈치 풀탭이 달려 신고 벗기 편하며, 공원 산책이나 가벼운 조깅, 출퇴근 등 데일리 용도로 어울리는 디자인이다. 다만 상세페이지에 제조국·무게·관리방법 등 세부 스펙과 실제 착용 리뷰가 제공되지 않아, 실측 사이즈나 내구성은 구매 전 추가 확인이 필요하다.', '{"색상":["그레이","블랙"],"사이즈":["250","255","260","265","270","275","280"],"기능화용도":"런닝화","소재":"메쉬","성별":"남성","브랜드":"유세븐","제조국":null,"안전인증":null,"밑창기능":["충격흡수","경량","미끄럼방지"],"잠금방식":"끈","굽높이":{"값":"5cm","기준":"260 사이즈 기준"},"중량":null,"관리방법":null,"품질보증기준":null,"제조자수입자":null,"AS책임자":null}', '유세븐 남자 메쉬 데일리 런닝화 DM252는 그레이·블랙 2가지 색상과 250~280 전 사이즈 옵션을 갖춘 남성용 경량 러닝화다. 통기성 좋은 니트 메쉬 갑피와 U-CELLON EVA 미드솔을 적용해 쿠셔닝과 반발력을 강화했고, 두꺼운 통굽형 밑창과 발볼넓이 10.5cm의 와이드 설계로 편안한 착화감을 준다. 끈 조임 방식에 뒤꿈치 풀탭이 달려 신고 벗기 편하며, 공원 산책이나 가벼운 조깅, 출퇴근 등 데일리 용도로 어울리는 디자인이다. 다만 상세페이지에 제조국·무게·관리방법 등 세부 스펙과 실제 착용 리뷰가 제공되지 않아, 실측 사이즈나 내구성은 구매 전 추가 확인이 필요하다.', 'ON_SALE', NOW(), NOW()),
(9177780746, (SELECT id FROM brand WHERE name = '캉골' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 남성가방 > 크로스백' LIMIT 1), '[롯데백화점]캉골 스튜던트 메신저백 2097 블랙 (KRFBMB20970)', 59500, 50340, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9177780746/B.webp?541000115', 0, '캉골(KANGOL) 남성 크로스백으로 블랙 컬러의 나일론 100% 메신저백 스타일 플랩크로스백이다. 사이즈는 너비 39 x 높이 27 x 폭 13cm의 원사이즈(OS)로 15인치 노트북 수납이 가능해 출퇴근이나 통학용 데일리 가방으로 적합하다. 전면에는 캉골 캥거루 로고 패치가 부착되어 있고, 버클 두 개로 여미는 플랩 개폐 방식과 지퍼형 앞주머니를 갖췄으며 어깨 스트랩 길이 조절이 가능해 다양한 체형에 맞춰 멜 수 있다. 다만 세탁 및 드라이클리닝이 불가해 오염 시 마른천으로만 관리해야 하고 원단 특성상 보풀이 생길 수 있다는 점, 제조국이 중국이라는 점은 유의할 부분이다. 수집된 리뷰 데이터가 없어 실사용 만족도나 단점은 추가 확인이 필요하다.', '{"브랜드":"캉골","색상":"블랙","사이즈":"ONE","소재":"겉감 나일론 100%, 안감 폴리에스터 100%","성별":"남성","종류":"플랩크로스백","제조국":"중국","제조자수입자":"에스제이그룹","세탁방법":"세탁 및 드라이클리닝 금지, 오염시 마른천으로 가볍게 닦기, 습기 주의","개폐방식":"플랩(벨크로/버클)","도난방지기능":["없음"],"스트랩조절가능여부":"가능","구성품수":null,"AS가능여부":"가능","브랜드모델명":"KRFBMB20970"}', '캉골(KANGOL) 남성 크로스백으로 블랙 컬러의 나일론 100% 메신저백 스타일 플랩크로스백이다. 사이즈는 너비 39 x 높이 27 x 폭 13cm의 원사이즈(OS)로 15인치 노트북 수납이 가능해 출퇴근이나 통학용 데일리 가방으로 적합하다. 전면에는 캉골 캥거루 로고 패치가 부착되어 있고, 버클 두 개로 여미는 플랩 개폐 방식과 지퍼형 앞주머니를 갖췄으며 어깨 스트랩 길이 조절이 가능해 다양한 체형에 맞춰 멜 수 있다. 다만 세탁 및 드라이클리닝이 불가해 오염 시 마른천으로만 관리해야 하고 원단 특성상 보풀이 생길 수 있다는 점, 제조국이 중국이라는 점은 유의할 부분이다. 수집된 리뷰 데이터가 없어 실사용 만족도나 단점은 추가 확인이 필요하다.', 'ON_SALE', NOW(), NOW()),
(9192224243, (SELECT id FROM brand WHERE name = '언더아머 UNDER ARMOUR' LIMIT 1), (SELECT id FROM category WHERE name = '남성가방 > 스포츠가방' LIMIT 1), '[백화점 정품] 언더아머 Under Armour (1381920) UA 컨테인 듀오 스몰 백팩 더플백 짐백', 93000, 93000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9192224243/B.webp?203752469', 0, '언더아머(UNDER ARMOUR) 정품 UA 컨테인 듀오 스몰 백팩 더플백 짐백(모델명 1381920D001)으로, 남성용 블랙 컬러에 골드 로고 포인트가 돋보이는 헬스/피트니스용 스포츠가방이다. 손잡이로 들거나 어깨끈으로 백팩처럼 멜 수 있는 2-way 듀오 구조이며, 하단 별도 지퍼 구획의 신발 수납칸과 측면 매쉬 물병 포켓, 상단 노트북/태블릿 수납 파우치, 프론트 지퍼 포켓 등 다양한 수납 구조를 갖춰 헬스장 짐백이나 출퇴근·1박2일 여행용 가방으로 쓰기 좋다. 백화점 정품 판매를 내세우는 셀러이며 가격은 93,000원(정가 대비 12% 할인)이다. 다만 상품고시상 색상·소재·제조국·크기 등 세부 정보가 모두 ''상품상세페이지 참조''로만 표기되어 있어 정확한 원단 소재나 실측 사이즈, 방수 여부 등은 상세페이지를 통해 추가로 확인해야 하며, 현재 수집된 리뷰가 없어 실제 사용자 평가(내구성, 냄새, 마감 품질 등)는 아직 검증되지 않았다는 점은 참고할 부분이다.', '{"브랜드":"언더아머 UNDER ARMOUR","색상":["블랙"],"사이즈":null,"용량":null,"가방종류":"더플백","스포츠종류":"헬스/피트니스","소재":null,"제조국":null,"성별":"남성","방수여부":null,"수납구조":["신발 별도 수납칸","메인 대형 수납공간","사이드 물병 수납 포켓","프론트 지퍼 포켓","이어폰 파우치 별도 증정"],"휴대방식":"백팩형(양쪽어깨)","모델명":"1381920D001","품질보증기준":null}', '언더아머(UNDER ARMOUR) 정품 UA 컨테인 듀오 스몰 백팩 더플백 짐백(모델명 1381920D001)으로, 남성용 블랙 컬러에 골드 로고 포인트가 돋보이는 헬스/피트니스용 스포츠가방이다. 손잡이로 들거나 어깨끈으로 백팩처럼 멜 수 있는 2-way 듀오 구조이며, 하단 별도 지퍼 구획의 신발 수납칸과 측면 매쉬 물병 포켓, 상단 노트북/태블릿 수납 파우치, 프론트 지퍼 포켓 등 다양한 수납 구조를 갖춰 헬스장 짐백이나 출퇴근·1박2일 여행용 가방으로 쓰기 좋다. 백화점 정품 판매를 내세우는 셀러이며 가격은 93,000원(정가 대비 12% 할인)이다. 다만 상품고시상 색상·소재·제조국·크기 등 세부 정보가 모두 ''상품상세페이지 참조''로만 표기되어 있어 정확한 원단 소재나 실측 사이즈, 방수 여부 등은 상세페이지를 통해 추가로 확인해야 하며, 현재 수집된 리뷰가 없어 실제 사용자 평가(내구성, 냄새, 마감 품질 등)는 아직 검증되지 않았다는 점은 참고할 부분이다.', 'ON_SALE', NOW(), NOW()),
(9195294245, (SELECT id FROM brand WHERE name = '세빛섬(채빛퀴진)' LIMIT 1), (SELECT id FROM category WHERE name = 'e쿠폰/상품권 > 레스토랑/뷔페' LIMIT 1), '[채빛퀴진] 주말/공휴일 1인', 79000, 69520, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9195294245/B.webp?603137189', 0, '세빛섬 채빛퀴진에서 주말/공휴일에 1인이 이용할 수 있는 뷔페 교환권으로, 쿠프마케팅이 발행하는 모바일쿠폰 형태이며 구매일로부터 93일간 사용 가능하고(연장 불가) 미사용 시 환불도 가능하다. 한강과 잠수교 야경이 보이는 세빛섬에서 샐러드, 회, 랍스터, 스테이크, 초밥, 육회, 새우요리, 디저트 등 다양한 코스가 제공되는 파인다이닝풍 뷔페로, 리뷰에서는 가성비 있게 잘 먹었다는 긍정적 평가가 있으며 뚜렷한 단점 후기는 확인되지 않았다.', '{"상품유형":"교환권","브랜드":"세빛섬(채빛퀴진)","발행처":"쿠프마케팅","매장분류":"뷔페","권종금액":null,"이용인원":"1인","이용가능요일":"주말/공휴일","유효기간":"93일","유효기간연장가능여부":"연장불가","환불가능여부":"환불가능","발권방식":"모바일쿠폰","사용가능매장":null,"사용지역":"서울","잔액환급여부":null}', '세빛섬 채빛퀴진에서 주말/공휴일에 1인이 이용할 수 있는 뷔페 교환권으로, 쿠프마케팅이 발행하는 모바일쿠폰 형태이며 구매일로부터 93일간 사용 가능하고(연장 불가) 미사용 시 환불도 가능하다. 한강과 잠수교 야경이 보이는 세빛섬에서 샐러드, 회, 랍스터, 스테이크, 초밥, 육회, 새우요리, 디저트 등 다양한 코스가 제공되는 파인다이닝풍 뷔페로, 리뷰에서는 가성비 있게 잘 먹었다는 긍정적 평가가 있으며 뚜렷한 단점 후기는 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9206677171, (SELECT id FROM brand WHERE name = '아디다스' LIMIT 1), (SELECT id FROM category WHERE name = '수입명품 > 남성의류' LIMIT 1), '아디다스 ADIZERO A ST M JP1492', 107200, 101840, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/pd/v2/6/7/7/1/7/1/JBmUa/9206677171_B.webp', 0, '아디다스 ADIZERO A ST M(품번 JP1492) 남성용 블랙 컴프레션 타이츠로, 허벅지 중간까지 오는 슬림핏 실루엣과 측면 반사 스트라이프, 허벅지 로고 프린트가 특징이다. 러닝·육상·트레이닝 등 고강도 운동 시 밀착 착용감을 원하는 남성에게 적합하며, 사이즈는 A/M, A/L, A/2XL 중 선택 가능하다. 다만 상품상세페이지 참조로만 표기된 소재·제조국 등 상세 정보가 부족하고, 병행수입 여부가 명확히 고지되지 않아 정품 여부나 세탁 방법 등을 구매 전 별도로 확인해야 하며, 수집된 리뷰가 없어 실착용 후기를 참고하기 어렵다는 점은 단점이다.', '{"브랜드":"아디다스","색상":"블랙","사이즈":["A/2XL","A/L","A/M"],"소재":null,"핏":"슬림핏","카테고리":"이너웨어/언더웨어","성별":"남성","제조국":null,"세탁방법":null,"제조연월":null,"제조자수입자":null,"병행수입여부":null,"넥라인":null,"소매기장":null,"시즌":null,"품번":"JP1492","구성수량":null,"치수상세":null}', '아디다스 ADIZERO A ST M(품번 JP1492) 남성용 블랙 컴프레션 타이츠로, 허벅지 중간까지 오는 슬림핏 실루엣과 측면 반사 스트라이프, 허벅지 로고 프린트가 특징이다. 러닝·육상·트레이닝 등 고강도 운동 시 밀착 착용감을 원하는 남성에게 적합하며, 사이즈는 A/M, A/L, A/2XL 중 선택 가능하다. 다만 상품상세페이지 참조로만 표기된 소재·제조국 등 상세 정보가 부족하고, 병행수입 여부가 명확히 고지되지 않아 정품 여부나 세탁 방법 등을 구매 전 별도로 확인해야 하며, 수집된 리뷰가 없어 실착용 후기를 참고하기 어렵다는 점은 단점이다.', 'ON_SALE', NOW(), NOW()),
(9220143688, (SELECT id FROM brand WHERE name = '11번가 판매자 24936733' LIMIT 1), (SELECT id FROM category WHERE name = '김치 > 별미김치' LIMIT 1), '팔공산 명품김치  1입  10kg(고급 국내산 김치)', 94000, 94000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9220143688/B.webp?148752041', 0, '김치 > 별미김치 > 파김치 카테고리의 팔공산 명품김치로, 국내산 쪽파를 사용해 담근 10kg 대용량 파김치 1입 구성이다. 붉은 양념이 결마다 고르게 버무려지고 잣 고명을 올린 모습이 이미지에서 확인되며, 검은 뚝배기에 담아낸 연출컷으로 제품을 소개하고 있다. 다만 브랜드, 제조방식, 식품유형, 보관방법, 소비기한 등 상세 정보는 상품상세설명 참조로만 표기되어 있어 구체적으로 확인되지 않고, 수집된 리뷰 데이터가 없어 실제 구매자의 맛이나 품질에 대한 평가는 파악할 수 없다.', '{"김치종류":"파김치","브랜드":null,"용량":"기타","구성수량":"1개","원산지":"국내산","제조방식":null,"식품유형":null,"주원료":"쪽파","새우젓함유여부":null,"매운맛정도":null,"보관방법":null,"소비기한":null,"생산자":null,"옵션구성":null,"태그":["국내산","고급"]}', '김치 > 별미김치 > 파김치 카테고리의 팔공산 명품김치로, 국내산 쪽파를 사용해 담근 10kg 대용량 파김치 1입 구성이다. 붉은 양념이 결마다 고르게 버무려지고 잣 고명을 올린 모습이 이미지에서 확인되며, 검은 뚝배기에 담아낸 연출컷으로 제품을 소개하고 있다. 다만 브랜드, 제조방식, 식품유형, 보관방법, 소비기한 등 상세 정보는 상품상세설명 참조로만 표기되어 있어 구체적으로 확인되지 않고, 수집된 리뷰 데이터가 없어 실제 구매자의 맛이나 품질에 대한 평가는 파악할 수 없다.', 'ON_SALE', NOW(), NOW()),
(9222490623, (SELECT id FROM brand WHERE name = '11번가 판매자 25579468' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 주얼리 > 브랜드 여성주얼리' LIMIT 1), '[ VIVIENNEWESTWOOD] 63020086 02P116 여성 목걸이', 259000, 221610, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9222490623/B.webp?677753112', 0, '비비안 웨스트우드(Vivienne Westwood) 여성 목걸이로, 실버톤 합금 소재에 투명 크리스탈이 촘촘히 세팅된 토성(새턴) 모티프 펜던트가 특징이다. 펜던트 사이즈는 2.3x2cm, 목걸이 길이는 45~49cm로 조절 가능한 단품 구성이며, 가는 체인 디자인이라 데일리로 가볍게 착용하거나 선물용으로 활용하기 좋다. 상세페이지에서는 100% 정품(병행수입) 및 정품 미보장시 200% 보상제도를 안내하고 있으나, 브랜드 공식 보증서 제공 여부와 제조국은 상세설명 참조로만 표기되어 있어 명확한 확인이 어렵고, 수집된 리뷰 데이터가 없어 실사용자 평가는 확인할 수 없다는 점은 참고해야 한다.', '{"상품종류":"목걸이","브랜드":"기타","색상":"실버","소재":"합금","순도":"해당없음","스톤종류":null,"반지사이즈":null,"목걸이길이":"45~49cm","세트구성":"단품","제조국":null,"보증서제공여부":null,"본사정품여부":"본사정품","성별":"여성","사용부위":["목"]}', '비비안 웨스트우드(Vivienne Westwood) 여성 목걸이로, 실버톤 합금 소재에 투명 크리스탈이 촘촘히 세팅된 토성(새턴) 모티프 펜던트가 특징이다. 펜던트 사이즈는 2.3x2cm, 목걸이 길이는 45~49cm로 조절 가능한 단품 구성이며, 가는 체인 디자인이라 데일리로 가볍게 착용하거나 선물용으로 활용하기 좋다. 상세페이지에서는 100% 정품(병행수입) 및 정품 미보장시 200% 보상제도를 안내하고 있으나, 브랜드 공식 보증서 제공 여부와 제조국은 상세설명 참조로만 표기되어 있어 명확한 확인이 어렵고, 수집된 리뷰 데이터가 없어 실사용자 평가는 확인할 수 없다는 점은 참고해야 한다.', 'ON_SALE', NOW(), NOW()),
(9233450819, (SELECT id FROM brand WHERE name = 'LG전자' LIMIT 1), (SELECT id FROM category WHERE name = '모니터 > TV 모니터' LIMIT 1), 'LG PC 모니터 80cm 32U631A 2560 x 1440 QHD /온오프', 440000, 440000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9233450819/B.webp?277555399', 0, 'LG전자 32U631A는 79~83cm(32~33인치) 화면크기에 2560x1440 QHD 해상도 IPS 패널을 탑재한 PC 모니터로, sRGB 99%와 HDR10을 지원해 색 표현력이 우수하고 178도 광시야각으로 측면에서도 색 왜곡이 적다. 최대 100Hz 주사율과 5ms(GtG) 응답속도, 액션모드(Dynamic Action Sync)·다크맵 모드(Black Stabilizer)를 갖춰 가벼운 게이밍에도 무난하며, 플리커 세이프와 리더모드로 장시간 사무·문서작업 시 눈의 피로를 줄여준다는 점이 강점이다. USB-C(PD 15W) 한 줄 연결로 노트북 영상 출력과 충전을 동시에 처리할 수 있고 LG 스위치 앱과 듀얼PC 컨트롤로 화면을 최대 6개 영역으로 나눠 관리하는 등 업무 생산성에 초점을 맞춘 구성이다. 다만 스피커가 내장되어 있지 않아 별도 오디오 기기가 필요하고, 스탠드는 틸트(상하 각도조절, -5도~+20도)만 지원하며 스위블·피벗·높낮이 조절은 불가능해 인체공학적 자', '{"화면크기":"32~33인치","해상도":"QHD(2560x1440)","브랜드":"LG전자","제품유형":"PC모니터","패널타입":"IPS","화면주사율":"100Hz","곡률":"평면","튜너내장여부":"미내장(모니터전용)","에너지소비효율등급":null,"제조국":null,"정격전압":null,"소비전력":null,"크기(가로x세로x깊이)":"714.2 x 512.6 x 235 mm (스탠드 포함), 714.2 x 419.4 x 46.8 mm (스탠드 제외)","중량":"6.5 kg (스탠드 포함), 5.4 kg (스탠드 제외)","스탠드거치방식":"스탠드형","연결단자":["HDMI","USB-C"],"스피커내장여부":"미내장","HDR지원":"HDR10","색상":"블랙","모델명":"32U631A","KC인증정보":null,"AS책임자및전화번호":null,"품질보증기준":null,"동일모델출시년월":null,"구성품":null}', 'LG전자 32U631A는 79~83cm(32~33인치) 화면크기에 2560x1440 QHD 해상도 IPS 패널을 탑재한 PC 모니터로, sRGB 99%와 HDR10을 지원해 색 표현력이 우수하고 178도 광시야각으로 측면에서도 색 왜곡이 적다. 최대 100Hz 주사율과 5ms(GtG) 응답속도, 액션모드(Dynamic Action Sync)·다크맵 모드(Black Stabilizer)를 갖춰 가벼운 게이밍에도 무난하며, 플리커 세이프와 리더모드로 장시간 사무·문서작업 시 눈의 피로를 줄여준다는 점이 강점이다. USB-C(PD 15W) 한 줄 연결로 노트북 영상 출력과 충전을 동시에 처리할 수 있고 LG 스위치 앱과 듀얼PC 컨트롤로 화면을 최대 6개 영역으로 나눠 관리하는 등 업무 생산성에 초점을 맞춘 구성이다. 다만 스피커가 내장되어 있지 않아 별도 오디오 기기가 필요하고, 스탠드는 틸트(상하 각도조절, -5도~+20도)만 지원하며 스위블·피벗·높낮이 조절은 불가능해 인체공학적 자유도가 낮다. 연결단자도 HDMI 1개와 USB-C 1개로 제한적이며 NVIDIA G-SYNC나 AMD FreeSync 같은 가변주사율 기술은 지원하지 않아 고사양 게이밍보다는 사무·범용 작업에 더 적합한 모니터다.', 'ON_SALE', NOW(), NOW()),
(9236338700, (SELECT id FROM brand WHERE name = 'MSI' LIMIT 1), (SELECT id FROM category WHERE name = '모니터 > 일반 모니터' LIMIT 1), 'MSI PRO MP273QW E14 게이밍 WQHD 144 스피커내장 화이트 무결점', 241000, 241000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9236338700/B.webp?367943127', 0, 'MSI PRO MP273QW E14는 27인치(68.58cm) WQHD(2560x1440) 해상도의 IPS 패널을 탑재한 화이트 색상의 평면 게이밍 모니터다. 144Hz 주사율과 1ms 응답속도, Adaptive-Sync 가변 주사율을 지원해 게이밍 용도에 적합하며, 178도 광시야각 IPS 패널로 색 왜곡 없이 넓은 시야각을 제공해 사무·협업 용도로도 무리가 없다. 2W x2 스피커가 내장되어 있어 별도 외부 스피커 없이 바로 사용할 수 있고, HDMI 2.0b와 DisplayPort 1.2a 단자를 지원하며 VESA 100x100 마운트와 -5°~20° 틸트 스탠드 기능을 갖췄다. 무결점 등급 제품으로 화이트 톤의 슬림한 베젤과 삼각형 스탠드가 인테리어 친화적인 디자인을 완성한다. 다만 스탠드는 틸트 조절만 가능하고 높이조절·스위블·피벗 기능은 지원하지 않아 세밀한 각도 조정이 필요한 사용자에게는 아쉬울 수 있으며, 현재 수집된 리뷰 데이터가 없어 실사용자 평가는 확인되지 않았다', '{"브랜드":"MSI","화면크기":"27인치","해상도":"WQHD","패널타입":"IPS","주사율":"144Hz","용도":"게이밍","곡률":"평면(플랫)","화면비율":"16:9","스피커내장여부":"내장","HDR지원":"기타","가변주사율기술":null,"무결점등급":"무결점","색상":"화이트","모델명":"PRO MP273QW E14","제조국":null,"에너지소비효율등급":null,"정격전압소비전력":"100~240V, 50/60Hz / 57W","크기무게":"613.49 x 201.00 x 437.52 mm / 4.5kg","동일모델출시년월":null,"품질보증기준":"1년","AS책임자전화번호":null,"KC인증정보":"R-R-MSI-3PE2","연결단자":["HDMI","DisplayPort"],"스탠드기능":["틸트","VESA마운트"],"옵션구성":null}', 'MSI PRO MP273QW E14는 27인치(68.58cm) WQHD(2560x1440) 해상도의 IPS 패널을 탑재한 화이트 색상의 평면 게이밍 모니터다. 144Hz 주사율과 1ms 응답속도, Adaptive-Sync 가변 주사율을 지원해 게이밍 용도에 적합하며, 178도 광시야각 IPS 패널로 색 왜곡 없이 넓은 시야각을 제공해 사무·협업 용도로도 무리가 없다. 2W x2 스피커가 내장되어 있어 별도 외부 스피커 없이 바로 사용할 수 있고, HDMI 2.0b와 DisplayPort 1.2a 단자를 지원하며 VESA 100x100 마운트와 -5°~20° 틸트 스탠드 기능을 갖췄다. 무결점 등급 제품으로 화이트 톤의 슬림한 베젤과 삼각형 스탠드가 인테리어 친화적인 디자인을 완성한다. 다만 스탠드는 틸트 조절만 가능하고 높이조절·스위블·피벗 기능은 지원하지 않아 세밀한 각도 조정이 필요한 사용자에게는 아쉬울 수 있으며, 현재 수집된 리뷰 데이터가 없어 실사용자 평가는 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9256715690, (SELECT id FROM brand WHERE name = '카시오' LIMIT 1), (SELECT id FROM category WHERE name = '수입명품 > 시계' LIMIT 1), '[카시오] 남성 손목 시계 스포츠 MRW-200H-1B2', 53000, 38110, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9256715690/B.webp?725005032', 0, '카시오 남성 아날로그 손목시계 MRW-200H-1B2. 원형 다이버 스타일 회전 베젤에 블랙 레진 밴드를 매치한 스포츠 캐주얼 디자인으로, 화이트 인덱스와 요일/날짜 표시창이 있어 데일리 착용과 학생·선물용으로 두루 적합하다. 10기압(10ATM) 방수 기능을 갖춰 생활 방수는 물론 가벼운 수상 활동에도 대응하며, 케이스 사이즈 44.6x47.9mm, 두께 11.6mm, 무게 약 39g으로 남성 손목에 적당한 볼륨감을 준다. 제조국은 중국이며 월드 워런티(다국어 설명서 및 보증서)가 기본 제공되어 A/S에 대한 안심도가 높다. 다만 수집된 리뷰 데이터가 없어 실사용자의 장단점 평가는 아직 확인되지 않았다.', '{"브랜드":"카시오","성별":"남성","무브먼트":"아날로그","케이스형태":"원형(라운드)","스타일":["스포츠","데일리"],"색상":"블랙","사이즈":"44.6mm x 47.9mm, 두께 11.6mm","케이스소재":"기타","밴드소재":"레진/고무","방수등급":"10ATM","부가기능":["방수","달력표시"],"제조국":"중국","보증서제공여부":"제공","정품인증":null,"모델명":"MRW-200H-1B2","중량":"약 39g","AS책임자":"블레스컴퍼니 주식회사 02-2215-6478"}', '카시오 남성 아날로그 손목시계 MRW-200H-1B2. 원형 다이버 스타일 회전 베젤에 블랙 레진 밴드를 매치한 스포츠 캐주얼 디자인으로, 화이트 인덱스와 요일/날짜 표시창이 있어 데일리 착용과 학생·선물용으로 두루 적합하다. 10기압(10ATM) 방수 기능을 갖춰 생활 방수는 물론 가벼운 수상 활동에도 대응하며, 케이스 사이즈 44.6x47.9mm, 두께 11.6mm, 무게 약 39g으로 남성 손목에 적당한 볼륨감을 준다. 제조국은 중국이며 월드 워런티(다국어 설명서 및 보증서)가 기본 제공되어 A/S에 대한 안심도가 높다. 다만 수집된 리뷰 데이터가 없어 실사용자의 장단점 평가는 아직 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9267864210, (SELECT id FROM brand WHERE name = 'Check-Go' LIMIT 1), (SELECT id FROM category WHERE name = '골프 > 골프피팅용품' LIMIT 1), '라인 무게중심 마킹 밸런스 체크 골프공 측정기', 86800, 84200, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9267864210/B.webp?269660771', 0, '골프피팅용품 중 피팅공구로 분류되는 제품으로, 검정+레드 투톤의 원통형 본체 상단 회전 케이지에 골프공을 넣고 버튼을 눌러 분당 1만 회전으로 고속 회전시켜 공의 무게중심(중심선)을 찾아 전용 마킹펜으로 표시해주는 골프공 밸런스 체커(스윗스팟 파인더)이다. 구성은 본체와 마커 및 펜 1개이며, 드라이버 티샷과 퍼팅 모두에서 공의 무게중심을 정렬해 방향성과 정확도를 높이는 데 쓸 수 있어 퍼팅 연습이나 라운드 준비, 골프 애호가를 위한 선물용으로 적합하다. 다만 해외구매대행 상품으로 배송에 평균 7~14일이 소요되고 전자제품 특성상 개봉 후 교환·반품이 제한되며, 브랜드 표기가 ''알수없음''으로 되어 있는 등 정식 유통 경로가 명확하지 않은 점은 구매 전 유의할 부분이고, 현재까지 수집된 리뷰 데이터는 없어 실사용 만족도나 내구성에 대한 검증된 근거는 부족하다.', '{"상품유형":"피팅공구","색상":null,"브랜드":"Check-Go","소재":"플라스틱","제조국":null,"그립사이즈":null,"그립타입":null,"성별":null,"호환클럽":["드라이버","퍼터"],"세트구성수량":"마커 및 펜 1개","중량":null,"사이즈":null,"옵션구성":{"axes":["색상"],"items":[{"value":"A. 마커 및 펜 1개","label":"A. 마커 및 펜 1개","price":84200,"add_price":0,"sold_out":false,"stock_qty":200}]},"KC인증정보":null,"품질보증기준":null}', '골프피팅용품 중 피팅공구로 분류되는 제품으로, 검정+레드 투톤의 원통형 본체 상단 회전 케이지에 골프공을 넣고 버튼을 눌러 분당 1만 회전으로 고속 회전시켜 공의 무게중심(중심선)을 찾아 전용 마킹펜으로 표시해주는 골프공 밸런스 체커(스윗스팟 파인더)이다. 구성은 본체와 마커 및 펜 1개이며, 드라이버 티샷과 퍼팅 모두에서 공의 무게중심을 정렬해 방향성과 정확도를 높이는 데 쓸 수 있어 퍼팅 연습이나 라운드 준비, 골프 애호가를 위한 선물용으로 적합하다. 다만 해외구매대행 상품으로 배송에 평균 7~14일이 소요되고 전자제품 특성상 개봉 후 교환·반품이 제한되며, 브랜드 표기가 ''알수없음''으로 되어 있는 등 정식 유통 경로가 명확하지 않은 점은 구매 전 유의할 부분이고, 현재까지 수집된 리뷰 데이터는 없어 실사용 만족도나 내구성에 대한 검증된 근거는 부족하다.', 'ON_SALE', NOW(), NOW()),
