(9310146644, (SELECT id FROM brand WHERE name = '파크랜드' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 남성의류 > 점퍼' LIMIT 1), '[오스틴리드]라이트퍼플 나일론 스판 경량점퍼-A2BW2310135C', 65700, 45990, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9310146644/B.webp?335714222', 0, '파크랜드의 오스틴리드 브랜드 남성 경량 점퍼로, 나일론 소재에 폴리우레탄이 혼방된 스판 원단을 사용해 가볍고 신축성 있는 착용감을 준다. 네이비 단색에 스탠드칼라와 전면 지퍼 여밈, 양쪽 슬래시 포켓, 소매 단추 탭 마감이 특징인 바람막이 스타일 점퍼로 환절기 출퇴근이나 가벼운 아우터가 필요한 데일리룩에 어울린다. 정가 65,700원에서 30% 할인된 45,990원에 판매 중이며, 제조국은 미얀마이고 드라이크리닝 세탁을 권장한다. 다만 상품 페이지에 실제 구매자 리뷰가 아직 없어 착용감이나 사이즈감에 대한 후기 기반 정보는 확인되지 않으며, 옵션 정보에서도 색상·사이즈 등 구체적인 선택 값이 제공되지 않아 구매 전 별도 확인이 필요하다.', '{"색상":"네이비","사이즈":null,"점퍼종류":"바람막이점퍼","소재":["나일론"],"핏":null,"넥라인":"스탠드칼라","소매":"긴소매","안감":null,"충전재":"해당없음","방수발수기능":null,"성별":"남성","브랜드":"파크랜드","제조국":"미얀마","세탁방법":"드라이크리닝","제조연월":"202301","품질보증기준":"공정거래위원회 고시 내 소비자 분쟁해결기준에 의거 보상합니다.","모델명":"A2BW2310135C","할인율구간":"10~30%","가격대":"4만원대"}', '파크랜드의 오스틴리드 브랜드 남성 경량 점퍼로, 나일론 소재에 폴리우레탄이 혼방된 스판 원단을 사용해 가볍고 신축성 있는 착용감을 준다. 네이비 단색에 스탠드칼라와 전면 지퍼 여밈, 양쪽 슬래시 포켓, 소매 단추 탭 마감이 특징인 바람막이 스타일 점퍼로 환절기 출퇴근이나 가벼운 아우터가 필요한 데일리룩에 어울린다. 정가 65,700원에서 30% 할인된 45,990원에 판매 중이며, 제조국은 미얀마이고 드라이크리닝 세탁을 권장한다. 다만 상품 페이지에 실제 구매자 리뷰가 아직 없어 착용감이나 사이즈감에 대한 후기 기반 정보는 확인되지 않으며, 옵션 정보에서도 색상·사이즈 등 구체적인 선택 값이 제공되지 않아 구매 전 별도 확인이 필요하다.', 'ON_SALE', NOW(), NOW()),
(9312994293, (SELECT id FROM brand WHERE name = '11번가 판매자 59238157' LIMIT 1), (SELECT id FROM category WHERE name = '메이크업 > 바디메이크업' LIMIT 1), '니플밴드 유두패치젖꼭지밴드 48mm104매 당당니플밴드', 11370, 11360, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9312994293/B.webp?474811440', 0, '48mm 사이즈 원형 니플밴드(유두패치) 104매(52쌍) 구성으로, 남녀공용으로 사용 가능한 바디/피부용 가리개 패치이다. 살구색(누드톤)의 무늬 없는 매트한 원형 패치로 낱장 개별 포장되어 있으며, 지갑에 들어가는 작은 파우치 패키지로 휴대성이 좋다. 여름철 민소매나 얇은 옷, 노브라 착용 시 니플 비침을 가리는 용도로, 상세페이지에는 부드러운 재질과 신축성, 저자극성 접착력으로 민감 피부에도 사용 가능하다고 안내되어 있다. 다만 수집된 리뷰 데이터가 없어 실제 착용감이나 접착 지속력에 대한 사용자 후기 기반 장단점은 확인되지 않는다.', '{"제품유형":"기타","색상":null,"사이즈":null,"용량":"48mm, 104매","세트구성":"104매(52쌍)","향":null,"제형":null,"사용부위":"바디/피부","기능효과":[],"피부타입":null,"브랜드":null,"제조국":null,"사용기한":null,"화장품유형":null,"SPF지수":null}', '48mm 사이즈 원형 니플밴드(유두패치) 104매(52쌍) 구성으로, 남녀공용으로 사용 가능한 바디/피부용 가리개 패치이다. 살구색(누드톤)의 무늬 없는 매트한 원형 패치로 낱장 개별 포장되어 있으며, 지갑에 들어가는 작은 파우치 패키지로 휴대성이 좋다. 여름철 민소매나 얇은 옷, 노브라 착용 시 니플 비침을 가리는 용도로, 상세페이지에는 부드러운 재질과 신축성, 저자극성 접착력으로 민감 피부에도 사용 가능하다고 안내되어 있다. 다만 수집된 리뷰 데이터가 없어 실제 착용감이나 접착 지속력에 대한 사용자 후기 기반 장단점은 확인되지 않는다.', 'ON_SALE', NOW(), NOW()),
(9313739769, (SELECT id FROM brand WHERE name = '랩' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 잡화/소품 > 기타 액세서리' LIMIT 1), '멀티 스트랩 플랫 샌들 AQ7AS404', 35500, 35500, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/dl/v2/7/3/9/7/6/9/sHkxi/9313739769_235242340.webp', 0, '랩(LAP)의 멀티 스트랩 플랫 샌들 AQ7AS404는 갑피 인조가죽 100% 소재로 중국에서 제조된 여성 신발이며, 블랙·브라운·아이보리 3가지 컬러와 S/M/L 3가지 사이즈로 구성된 단품 상품이다. 발등을 여러 가닥 스트랩으로 교차 엮은 위빙 디자인에 앵클 스트랩과 메탈 버클 장식이 더해졌고 굽 없는 플랫 솔로 여름 데일리룩, 휴가·여행룩, 편안한 출근용 플랫슈즈로 활용하기 좋다. 리뷰에서는 합성피혁임에도 가죽 같은 고급스러운 재질감과 편안한 착화감이 장점으로 언급되었으며, 세탁이 불가능한 소재라 관리 시 주의가 필요하다.', '{"브랜드":"랩","색상":["블랙","브라운","베이지"],"사이즈":["S","M","L"],"소재":"인조가죽(합성피혁) 100%","제조국":"중국","제조자수입자":"(주)제이씨패밀리","제조연월":null,"세탁방법및취급주의사항":"세탁 불가","품질보증기준":"관련법 및 소비자분쟁해결 규정에 따름","AS책임자및전화번호":"02-2015-6000","용량중량":null,"구성수량":null,"판매단위":"단품","판매자":"lapkorea","품목유형":["신발","샌들","여성신발"]}', '랩(LAP)의 멀티 스트랩 플랫 샌들 AQ7AS404는 갑피 인조가죽 100% 소재로 중국에서 제조된 여성 신발이며, 블랙·브라운·아이보리 3가지 컬러와 S/M/L 3가지 사이즈로 구성된 단품 상품이다. 발등을 여러 가닥 스트랩으로 교차 엮은 위빙 디자인에 앵클 스트랩과 메탈 버클 장식이 더해졌고 굽 없는 플랫 솔로 여름 데일리룩, 휴가·여행룩, 편안한 출근용 플랫슈즈로 활용하기 좋다. 리뷰에서는 합성피혁임에도 가죽 같은 고급스러운 재질감과 편안한 착화감이 장점으로 언급되었으며, 세탁이 불가능한 소재라 관리 시 주의가 필요하다.', 'ON_SALE', NOW(), NOW()),
