(9344554205, (SELECT id FROM brand WHERE name = '오스틴리드' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 남성의류 > 니트/스웨터' LIMIT 1), '[오스틴리드]네이비 가로무늬 스트라이프 반팔 드레스 셔츠-A6PY2210627C', 13700, 9590, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9344554205/B.webp?792650894', 0, '오스틴리드 브랜드의 남성용 반팔 드레스셔츠로, 화이트 바탕에 가로 페인 스트라이프가 들어간 네이비 계열 컬러와 클래식한 카라(칼라) 여밈이 특징이다. 폴리에스터 70%·면 30% 혼방 소재에 베트남산으로, 여름철 정장 이너나 오피스 데일리룩으로 적합하며 30% 할인된 가격으로 판매 중이다. 리뷰에서는 마감이 깔끔하고 재질이 고급스러우며 배송이 빠르다는 긍정 평가가 많지만, 실제 색상이 표기된 네이비보다 밝고 연한 하늘색에 가깝게 보인다는 의견과 재질·마감을 ''보통'' 수준으로 평가하는 리뷰도 섞여 있어 색감 기대치는 다소 조정이 필요하다.', '{"색상":"네이비","사이즈":null,"소재":"폴리에스터 70%, 면 30%","넥라인":"카라(칼라)넥","소매기장":"반팔","핏":null,"성별":"남성","브랜드":"오스틴리드","제조국":"베트남","세탁방법":"손세탁 (상품고시상 드라이크리닝 병기)","제조자수입자":"웹뜰 02-3446-6623","모델명":"A6PY2210627C","할인율":"30%","품절여부":"판매중"}', '오스틴리드 브랜드의 남성용 반팔 드레스셔츠로, 화이트 바탕에 가로 페인 스트라이프가 들어간 네이비 계열 컬러와 클래식한 카라(칼라) 여밈이 특징이다. 폴리에스터 70%·면 30% 혼방 소재에 베트남산으로, 여름철 정장 이너나 오피스 데일리룩으로 적합하며 30% 할인된 가격으로 판매 중이다. 리뷰에서는 마감이 깔끔하고 재질이 고급스러우며 배송이 빠르다는 긍정 평가가 많지만, 실제 색상이 표기된 네이비보다 밝고 연한 하늘색에 가깝게 보인다는 의견과 재질·마감을 ''보통'' 수준으로 평가하는 리뷰도 섞여 있어 색감 기대치는 다소 조정이 필요하다.', 'ON_SALE', NOW(), NOW()),
(9347669304, (SELECT id FROM brand WHERE name = '엘렌쥬얼리' LIMIT 1), (SELECT id FROM category WHERE name = '주얼리 > 반지' LIMIT 1), '엘렌쥬얼리 실버 Silver 925 미니 나비 미스 링 은 반지', 47000, 28200, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/dl/v2/6/6/9/3/0/4/MfWeK/9347669304_235136979.webp', 0, '엘렌쥬얼리의 925 실버 미니 나비 미스 링으로, 가느다란 유광 밴드에 큐빅 없이 작은 나비 장식 하나만 포인트로 달려 있어 심플하고 데일리하게 착용하기 좋은 여성용 실버반지이다. 한국에서 제조되며 제품 보증서가 함께 제공되고 평생 무상 A/S(광택·세척·끊어짐·길이줄임)를 지원해 관리 부담 없이 오래 착용할 수 있다는 점이 장점이지만, 옵션(색상·호수) 재고 정보가 상세페이지 기준으로만 안내되어 실제 손가락 사이즈에 맞는 호수 선택이 어려울 수 있고 수집된 리뷰 데이터가 없어 실착용 후기나 내구성에 대한 검증은 부족한 상태이다.', '{"소재":"실버925","색상":"실버","사이즈":null,"순도":"925(실버)","브랜드":"엘렌쥬얼리","제조국":"대한민국","디자인스타일":["심플/민자","나비"],"큐빅유무":"큐빅없음","반지폭":null,"보증서제공여부":"제공","세트구성":"단품","성별":"여성","중량":null,"니켈프리알레르기프리":null,"AS가능여부":"AS가능"}', '엘렌쥬얼리의 925 실버 미니 나비 미스 링으로, 가느다란 유광 밴드에 큐빅 없이 작은 나비 장식 하나만 포인트로 달려 있어 심플하고 데일리하게 착용하기 좋은 여성용 실버반지이다. 한국에서 제조되며 제품 보증서가 함께 제공되고 평생 무상 A/S(광택·세척·끊어짐·길이줄임)를 지원해 관리 부담 없이 오래 착용할 수 있다는 점이 장점이지만, 옵션(색상·호수) 재고 정보가 상세페이지 기준으로만 안내되어 실제 손가락 사이즈에 맞는 호수 선택이 어려울 수 있고 수집된 리뷰 데이터가 없어 실착용 후기나 내구성에 대한 검증은 부족한 상태이다.', 'ON_SALE', NOW(), NOW()),
(9349084210, (SELECT id FROM brand WHERE name = '락포트' LIMIT 1), (SELECT id FROM category WHERE name = '남성신발 > 슬립온' LIMIT 1), '락포트 ROCKPORT 찰스 로드 캡토 CHARLESROAD CAPTOE (V80556) V80556 182589', 201500, 201500, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9349084210/B.webp?546630685', 0, '락포트(Rockport) 남성용 블랙 가죽 캡토 더비 슈즈로, 245~290 사이즈(W 폭) 옵션으로 구매 가능하다. 매끈한 풀그레인 가죽 갑피에 캡토 스티칭과 5구 레이스업 디자인을 적용했고, 굽은 낮은 플랫형에 가까워 안정적인 착화감을 준다. 짙은 고무 아웃솔에 브랜드 로고가 각인되어 있으며, 슬랙스나 정장 바지와 매치한 연출 컷에서 보듯 출근룩·비즈니스 캐주얼·면접이나 예식 등 격식 있는 자리에 어울리는 정장/드레스 스타일 구두다. 상품 고시에는 소재·치수·제조국 등 세부 정보가 상세페이지 참조로만 표기되어 있어 정확한 안감 소재나 원산지, 세탁 방법은 확인되지 않으며, 수집된 리뷰 데이터가 없어 실제 착용 만족도나 사이즈감에 대한 사용자 피드백은 아직 반영되지 않았다.', '{"브랜드":"락포트","색상":"블랙","사이즈":["245","250","255","260","265","270","275","280","285","290"],"소재":"가죽","안감소재":null,"밑창소재":"고무","신발타입":null,"굽높이":"플랫","쿠션기능성":[],"시즌":null,"성별":"남성","제조국":null,"스타일":"정장/드레스","세탁방법":null,"품질보증기준":null,"구성형태":"옵션(사이즈만)"}', '락포트(Rockport) 남성용 블랙 가죽 캡토 더비 슈즈로, 245~290 사이즈(W 폭) 옵션으로 구매 가능하다. 매끈한 풀그레인 가죽 갑피에 캡토 스티칭과 5구 레이스업 디자인을 적용했고, 굽은 낮은 플랫형에 가까워 안정적인 착화감을 준다. 짙은 고무 아웃솔에 브랜드 로고가 각인되어 있으며, 슬랙스나 정장 바지와 매치한 연출 컷에서 보듯 출근룩·비즈니스 캐주얼·면접이나 예식 등 격식 있는 자리에 어울리는 정장/드레스 스타일 구두다. 상품 고시에는 소재·치수·제조국 등 세부 정보가 상세페이지 참조로만 표기되어 있어 정확한 안감 소재나 원산지, 세탁 방법은 확인되지 않으며, 수집된 리뷰 데이터가 없어 실제 착용 만족도나 사이즈감에 대한 사용자 피드백은 아직 반영되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9349985278, (SELECT id FROM brand WHERE name = '삼성전자' LIMIT 1), (SELECT id FROM category WHERE name = 'TV > 138~175cm (55~69인치)' LIMIT 1), '[삼성전자] 4K UHD TV LH55BEFHLGFXKR 스탠드형-후[35590284', 809800, 767700, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9349985278/B.webp?599390191', 0, '삼성전자 4K UHD TV LH55BEFHLGFXKR, 55인치(138.7cm) 스탠드형 디스플레이로 거실 TV 교체나 첫 대형TV 구매에 적합하다. Crystal Processor 4K 화질엔진을 탑재해 4K(3,840x2,160) 고해상도를 지원하며, 에너지소비효율 1등급으로 소비전력 125W(On Mode) 수준의 절전형 모델이다. 한국에서 제조되었고(상세페이지 스펙표에는 베트남·중국·태국·멕시코·헝가리·슬로바키아 등 복수 생산국이 함께 기재되어 있어 실제 수령 제품의 원산지는 로트에 따라 다를 수 있음), 2025년 8월 출시된 비교적 최신 모델로 가격은 767,700원(정가 대비 5% 할인)이다. 스탠드형 설치 이미지가 기본이지만 상세페이지에는 동일 모델의 벽걸이 연출컷도 포함되어 있어 설치 방식 확인이 필요하다. 수집된 리뷰 데이터가 없어 실사용 만족도나 화질·음질·설치 관련 실사용자 불만 사항은 확인되지 않았다.', '{"브랜드":"삼성전자","화면크기":"55인치","해상도":"UHD(4K)","패널타입":"LED","설치형태":"스탠드형","스마트기능":null,"에너지소비효율등급":"1등급","제조국":"한국","모델명":"LH55BEFHLGFXKR","출시년월":"2025년 8월","소비전력":"AC220-240V 50/60Hz 소비전력 125W (On Mode)","사이즈":"1224.6 x 707.8 x 76.6mm (스탠드 포함)","KC인증정보":"XU09047-25319R-R-SEC-KU55UF8000","제조자수입자":"삼성전자(주)","AS책임자":"삼성전자서비스센터 / 1588-3366","부가기능":[],"색상":null}', '삼성전자 4K UHD TV LH55BEFHLGFXKR, 55인치(138.7cm) 스탠드형 디스플레이로 거실 TV 교체나 첫 대형TV 구매에 적합하다. Crystal Processor 4K 화질엔진을 탑재해 4K(3,840x2,160) 고해상도를 지원하며, 에너지소비효율 1등급으로 소비전력 125W(On Mode) 수준의 절전형 모델이다. 한국에서 제조되었고(상세페이지 스펙표에는 베트남·중국·태국·멕시코·헝가리·슬로바키아 등 복수 생산국이 함께 기재되어 있어 실제 수령 제품의 원산지는 로트에 따라 다를 수 있음), 2025년 8월 출시된 비교적 최신 모델로 가격은 767,700원(정가 대비 5% 할인)이다. 스탠드형 설치 이미지가 기본이지만 상세페이지에는 동일 모델의 벽걸이 연출컷도 포함되어 있어 설치 방식 확인이 필요하다. 수집된 리뷰 데이터가 없어 실사용 만족도나 화질·음질·설치 관련 실사용자 불만 사항은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9350396752, (SELECT id FROM brand WHERE name = 'GABBA' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 남성의류 > 코트' LIMIT 1), '[eTV][GABBA] 가바 여성 썸머 라이크라 에어홀 데님팬츠3종', 77000, 67760, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9350396752/B.webp?282388778', 0, 'GABBA(가바)의 여성 썸머 라이크라 에어홀 데님팬츠 3종으로, 카테고리는 ''브랜드 남성의류 > 코트 > 패딩/다운코트''로 등록되어 있으나 실제 상품은 코트가 아닌 여성용 하이라이즈 스트레이트~와이드 데님 팬츠이며 성별·품목 카테고리가 실제 상품과 불일치한다. 라이트블루, 미디엄인디고, 아이보리 3가지 컬러로 구성되어 있고 25~32 사이즈(총 7개 옵션, 재고 다수 보유)로 판매되며, 여름철 통기성을 강조한 라이크라 에어홀 소재와 이태리 프리미엄 데님 컬렉션을 표방한다. 상세페이지에는 골드 메탈 버튼과 지퍼 플라이, 은은한 워싱 디테일 등 핏·소재 관련 정보가 담겨 있으나 정확한 원단 혼용률, 제조국, 세탁방법 등 상품고시 정보는 모두 ''상품상세설명 참조''로만 표기되어 있어 구체적 근거를 확인할 수 없다. 수집된 리뷰 데이터가 없어 실제 구매자 평가(장점·단점)는 확인되지 않는다.', '{"브랜드":"GABBA","코트종류":null,"색상":"혼합색상","사이즈":["25","26","27","28","29","30","32"],"소재":null,"핏":null,"넥라인":null,"소매기장":null,"성별":"여성","제조국":null,"세탁방법":null,"제조자수입자":null,"품명및모델명":null,"충전재":null,"방수여부":null,"할인율":"12%","재고상태":"재고있음"}', 'GABBA(가바)의 여성 썸머 라이크라 에어홀 데님팬츠 3종으로, 카테고리는 ''브랜드 남성의류 > 코트 > 패딩/다운코트''로 등록되어 있으나 실제 상품은 코트가 아닌 여성용 하이라이즈 스트레이트~와이드 데님 팬츠이며 성별·품목 카테고리가 실제 상품과 불일치한다. 라이트블루, 미디엄인디고, 아이보리 3가지 컬러로 구성되어 있고 25~32 사이즈(총 7개 옵션, 재고 다수 보유)로 판매되며, 여름철 통기성을 강조한 라이크라 에어홀 소재와 이태리 프리미엄 데님 컬렉션을 표방한다. 상세페이지에는 골드 메탈 버튼과 지퍼 플라이, 은은한 워싱 디테일 등 핏·소재 관련 정보가 담겨 있으나 정확한 원단 혼용률, 제조국, 세탁방법 등 상품고시 정보는 모두 ''상품상세설명 참조''로만 표기되어 있어 구체적 근거를 확인할 수 없다. 수집된 리뷰 데이터가 없어 실제 구매자 평가(장점·단점)는 확인되지 않는다.', 'ON_SALE', NOW(), NOW()),
(9354936736, (SELECT id FROM brand WHERE name = '테비 토퍼' LIMIT 1), (SELECT id FROM category WHERE name = '강아지용품 > 간식' LIMIT 1), '애견용품 반려견스낵 오리꽈배기 1kg 대형견 애견간식', 31300, 26770, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9354936736/B.webp?630983916', 0, '강아지용 오리고기 육포 간식으로, 얇게 저민 오리퐈배기(오리 저민육포) 형태를 1kg 대용량 실속포장으로 담았다. 대형견에게 적합한 용량이며 브랜드는 테비 토퍼(Tabby Topper)의 ''테비 사사미'' 라인이다. 낱개 포장 없이 벌크 형태로 들어있어 훈련용 보상 간식이나 평소 간식으로 나눠 급여하기 좋다. 원재료는 오리고기 위주이며 무곡물 여부나 제조국, 소비기한 등은 상세페이지에 별도 표기가 없어 확인이 필요하다. 수집된 리뷰 데이터가 없어 실제 구매자의 장단점 평가는 확인할 수 없었다.', '{"간식종류":"육포","대상동물":"강아지","브랜드":"테비 토퍼","주원료":["오리고기"],"총중량":{"단위중량":"1kg","수량":1,"총량":"1kg"},"포장수량":null,"대상견종크기":"대형견","대상연령":null,"제조국":null,"무곡물여부":"표시없음","기능성":["없음"],"포장형태":"벌크(낱개산포장)","옵션종류":{"축":["1.옵션"],"값개수":1,"비고":"단일옵션(기본상품)으로 실질적 옵션 분기 없음"},"소비기한":null}', '강아지용 오리고기 육포 간식으로, 얇게 저민 오리퐈배기(오리 저민육포) 형태를 1kg 대용량 실속포장으로 담았다. 대형견에게 적합한 용량이며 브랜드는 테비 토퍼(Tabby Topper)의 ''테비 사사미'' 라인이다. 낱개 포장 없이 벌크 형태로 들어있어 훈련용 보상 간식이나 평소 간식으로 나눠 급여하기 좋다. 원재료는 오리고기 위주이며 무곡물 여부나 제조국, 소비기한 등은 상세페이지에 별도 표기가 없어 확인이 필요하다. 수집된 리뷰 데이터가 없어 실제 구매자의 장단점 평가는 확인할 수 없었다.', 'ON_SALE', NOW(), NOW()),
(9355865199, (SELECT id FROM brand WHERE name = '도미노피자' LIMIT 1), (SELECT id FROM category WHERE name = 'e쿠폰/상품권 > 피자/치킨' LIMIT 1), '도미노피자 [배달주문가능] 블랙타이거슈림프(L)+콜라1.25L', 39400, 35460, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9355865199/B.webp?333198291', 0, '도미노피자 블랙타이거슈림프(L) 피자와 콜라 1.25L이 함께 구성된 배달주문 가능 교환형 e쿠폰(기프티콘)이다. L사이즈 도우 위에 통새우를 듬뿍 올리고 파인애플·양파·피망·베이컨 등을 곁들인 해산물 피자로, 정가 39,400원에서 10% 할인된 35,460원에 판매되며 3~4만원대 가격대에 속한다. 유효기간은 발급일로부터 365일이며 종료 30일 전부터 5년간 횟수 제한 없이 90일 단위로 연장할 수 있어 사용 시점을 여유 있게 조절할 수 있고, 유효기간 경과 전에는 11번가 앱에서 직접 100% 환불, 경과 후에도 90% 환불이 가능해 활용도가 높다. 다만 판매가 중단되거나 가격이 변경된 상품은 연장이 불가해 환불 처리되는 점, 매장 방문 교환이 원칙이라 배송상품이 아닌 SMS 미발송(모바일 e쿠폰함에서 확인) 방식이라는 점은 사용 전 유의할 부분이다. 리뷰 데이터가 수집되지 않아 실제 구매자의 만족도나 단점은 확인되지 않았다.', '{"브랜드":"도미노피자","상품유형":"피자","교환권유형":"교환권","메뉴구성":"블랙타이거슈림프(L)+콜라1.25L","세트구성":"세트(음료포함)","피자사이즈":"L","음료구성":"콜라1.25L","발행처":"기프티콘","유효기간":"유효기간 365일, 종료 전 마지막 30일 동안 5년 이내 횟수 제한 없이 90일 단위 연장 가능(판매중단·매가변경 상품은 연장 불가 후 환불)","사용가능매장":null,"배달가능여부":"배달가능","환불조건":"유효기간 경과 전 100% 환불(11번가 APP 직접 가능), 경과 후 90% 환불","가격대":"3~4만원","할인율":"10%","판매자":"skpgifticon"}', '도미노피자 블랙타이거슈림프(L) 피자와 콜라 1.25L이 함께 구성된 배달주문 가능 교환형 e쿠폰(기프티콘)이다. L사이즈 도우 위에 통새우를 듬뿍 올리고 파인애플·양파·피망·베이컨 등을 곁들인 해산물 피자로, 정가 39,400원에서 10% 할인된 35,460원에 판매되며 3~4만원대 가격대에 속한다. 유효기간은 발급일로부터 365일이며 종료 30일 전부터 5년간 횟수 제한 없이 90일 단위로 연장할 수 있어 사용 시점을 여유 있게 조절할 수 있고, 유효기간 경과 전에는 11번가 앱에서 직접 100% 환불, 경과 후에도 90% 환불이 가능해 활용도가 높다. 다만 판매가 중단되거나 가격이 변경된 상품은 연장이 불가해 환불 처리되는 점, 매장 방문 교환이 원칙이라 배송상품이 아닌 SMS 미발송(모바일 e쿠폰함에서 확인) 방식이라는 점은 사용 전 유의할 부분이다. 리뷰 데이터가 수집되지 않아 실제 구매자의 만족도나 단점은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9365138307, (SELECT id FROM brand WHERE name = 'K2세이프티' LIMIT 1), (SELECT id FROM category WHERE name = '주얼리 > 주얼리 소품' LIMIT 1), 'K2세이프티 아쿠아엑스 기능원단 베이직 쿨토시', 14140, 13300, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9365138307/B.webp?925044184', 0, 'K2세이프티 아쿠아엑스 기능원단 베이직 쿨토시는 Aqua-X 100% 폴리에스터에 CREORA 스판을 사용한 무봉제(심리스) 팔토시로, 그레이·블랙·화이트 3가지 컬러의 프리사이즈 남녀공용 제품이다. 자외선차단과 냉감 기능을 갖춰 여름철 등산, 캠핑, 운전, 자전거, 골프 등 야외활동 시 팔 전체를 감싸 햇볕과 더위로부터 보호해주며, 신축성 있는 밀착 핏과 이음새 없는 매끈한 마감이 특징이다. 다만 상세 이미지만 제공되고 실제 구매자 리뷰 데이터가 수집되지 않아 착용감이나 사이즈 만족도에 대한 실사용 평가는 확인되지 않는다.', '{"색상":["그레이","블랙","화이트"],"소재":"Aqua-X 100% 폴리에스터, CREORA 스판 사용","사이즈":"프리사이즈","브랜드":"K2세이프티","제조국":null,"세탁방법":null,"용도":"야외활동용","자외선차단기능":"있음","냉감기능":"있음","봉제방식":"무봉제","판매구성":"1켤레(2개)","성별":"남녀공용","AS책임자":null,"제조자수입자":null,"품질보증기준":null,"가격대":"13300원"}', 'K2세이프티 아쿠아엑스 기능원단 베이직 쿨토시는 Aqua-X 100% 폴리에스터에 CREORA 스판을 사용한 무봉제(심리스) 팔토시로, 그레이·블랙·화이트 3가지 컬러의 프리사이즈 남녀공용 제품이다. 자외선차단과 냉감 기능을 갖춰 여름철 등산, 캠핑, 운전, 자전거, 골프 등 야외활동 시 팔 전체를 감싸 햇볕과 더위로부터 보호해주며, 신축성 있는 밀착 핏과 이음새 없는 매끈한 마감이 특징이다. 다만 상세 이미지만 제공되고 실제 구매자 리뷰 데이터가 수집되지 않아 착용감이나 사이즈 만족도에 대한 실사용 평가는 확인되지 않는다.', 'ON_SALE', NOW(), NOW()),
(9367882762, (SELECT id FROM brand WHERE name = '사임당' LIMIT 1), (SELECT id FROM category WHERE name = '건강관리용품 > 물리치료용품' LIMIT 1), '[사임당]발패치 60매', 59800, 50830, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9367882762/B.webp?428660097', 0, '사임당 발패치 60매는 한국에서 제조된 남녀공용 프리사이즈 족부패치로, 살구빛 부직포 소재의 얇은 패치를 신발 속 발바닥에 붙여 사용하는 물리치료용품이다. 청록색 파우치 6매 묶음 2세트로 총 60매가 구성되어 있으며, 장시간 서서 일하거나 걷는 동안 또는 잠자기 전 다리와 발의 피로를 덜어주고 붓기 완화와 혈액순환 개선에 도움을 주는 용도로 제작되었다. 제품 상세페이지에는 인체적용시험 결과 붓기 감소 효과를 보여주는 그래프와 6대 환경유해물질 검사, EU 유해물질 기준 통과 등 안전성 시험성적서가 함께 제시되어 있다. 다만 현재 수집된 리뷰가 없어 실제 사용자 평가나 구체적인 단점은 확인되지 않았으며, 붙이는 패치 특성상 지속력이나 밀착감은 개인 발 사이즈나 신발 형태에 따라 차이가 있을 수 있다.', '{"브랜드":"사임당","제품유형":"발패치/족부패치","적용부위":"발/발바닥","용도효능":["붓기/부종완화","혈액순환"],"구성수량":"60매","사이즈":"FREE","색상":null,"소재":null,"전원방식":"해당없음","제조국":"한국","인증허가사항":null,"의료기기여부":null}', '사임당 발패치 60매는 한국에서 제조된 남녀공용 프리사이즈 족부패치로, 살구빛 부직포 소재의 얇은 패치를 신발 속 발바닥에 붙여 사용하는 물리치료용품이다. 청록색 파우치 6매 묶음 2세트로 총 60매가 구성되어 있으며, 장시간 서서 일하거나 걷는 동안 또는 잠자기 전 다리와 발의 피로를 덜어주고 붓기 완화와 혈액순환 개선에 도움을 주는 용도로 제작되었다. 제품 상세페이지에는 인체적용시험 결과 붓기 감소 효과를 보여주는 그래프와 6대 환경유해물질 검사, EU 유해물질 기준 통과 등 안전성 시험성적서가 함께 제시되어 있다. 다만 현재 수집된 리뷰가 없어 실제 사용자 평가나 구체적인 단점은 확인되지 않았으며, 붙이는 패치 특성상 지속력이나 밀착감은 개인 발 사이즈나 신발 형태에 따라 차이가 있을 수 있다.', 'ON_SALE', NOW(), NOW()),
(9368400700, (SELECT id FROM brand WHERE name = 'Conquer dream' LIMIT 1), (SELECT id FROM category WHERE name = '남성의류 > 트레이닝복' LIMIT 1), 'JEEP SPIRIT 남성 시어서커 냉감 반팔 반바지 셋업 여름 와이드핏 트레이닝복', 98000, 97500, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/dl/v2/4/0/0/7/0/0/fMHIw/9368400700_234832008.webp', 0, 'JEEP SPIRIT 남성 시어서커 냉감 반팔 반바지 셋업으로, 여름철 통기성과 시원한 촉감을 강조한 아이스쿨 원단을 사용한 상하 세트 트레이닝복입니다. 카라 넥라인에 전면 지퍼 여밈, 박시하고 여유로운 와이드핏 실루엣이 특징이며, 상의 밑단 지퍼 포켓 조임끈과 반바지의 스트링 밴딩·사선 포켓·뒷주머니 등 디테일이 돋보입니다. 화이트&그레이 마블(타이다이)톤, 블랙 솔리드, 라이트블루 마블톤 등 4가지 색상과 M~3XL(스키마 기준) 사이즈로 구성되어 여름 나들이, 휴가룩, 캠핑, 데일리룩 등에 활용하기 좋습니다. 다만 판매 페이지의 상품고시상 제조국·세탁방법 등 상세 정보는 ''상품상세설명 참조''로만 표기되어 있어 구체적인 소재 혼용률이나 취급 주의사항은 확인이 어려우며, 수집된 리뷰 데이터가 없어 실사용자 평가는 반영되지 않았습니다.', '{"색상":["화이트","그레이","블랙","블루"],"사이즈":["M(95/66)","L(100/77)","XL(105/88)","2XL(110/99)","3XL"],"구성":"상하세트(셋업)","소매기장":"반팔","하의기장":"반바지","핏":"와이드핏","넥라인":"카라(collar)","소재":"시어서커(요철 직조) 원단, 아이스쿨 냉감 원단","기능성":["쿨링/냉감","통기성"],"시즌":"여름","성별":"남성","브랜드":"Conquer dream","제조국":null,"세탁방법":null,"용도":["일상복"],"무료배송여부":null}', 'JEEP SPIRIT 남성 시어서커 냉감 반팔 반바지 셋업으로, 여름철 통기성과 시원한 촉감을 강조한 아이스쿨 원단을 사용한 상하 세트 트레이닝복입니다. 카라 넥라인에 전면 지퍼 여밈, 박시하고 여유로운 와이드핏 실루엣이 특징이며, 상의 밑단 지퍼 포켓 조임끈과 반바지의 스트링 밴딩·사선 포켓·뒷주머니 등 디테일이 돋보입니다. 화이트&그레이 마블(타이다이)톤, 블랙 솔리드, 라이트블루 마블톤 등 4가지 색상과 M~3XL(스키마 기준) 사이즈로 구성되어 여름 나들이, 휴가룩, 캠핑, 데일리룩 등에 활용하기 좋습니다. 다만 판매 페이지의 상품고시상 제조국·세탁방법 등 상세 정보는 ''상품상세설명 참조''로만 표기되어 있어 구체적인 소재 혼용률이나 취급 주의사항은 확인이 어려우며, 수집된 리뷰 데이터가 없어 실사용자 평가는 반영되지 않았습니다.', 'ON_SALE', NOW(), NOW()),
(9371969848, (SELECT id FROM brand WHERE name = '더블에이' LIMIT 1), (SELECT id FROM category WHERE name = '문구/사무용품 > 문구용품' LIMIT 1), '연필 샤프 지우개 복사지 더블에이 박스 A4 80g 2500매', 47740, 42490, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9371969848/B.webp?660810170', 0, '더블에이(Double A) A4 80g 복사용지로, 500매 낱장 팩 5개가 모인 1BOX(총 2500매) 구성의 대용량 사무용 복사지입니다. 규격은 A4(210mm x 297mm)이며 복사기, 팩스, 잉크젯 및 레이저프린터에 모두 사용 가능하고 양면 인쇄를 지원합니다. 사무실 상비용품이나 대량 인쇄, 가정용 프린터, 학교·학원 인쇄물 등에 적합하며, 우수한 백색도와 매끄러운 표면으로 선명한 인쇄 품질을 제공하는 것이 특징입니다. 다만 상품 등록 정보에 브랜드/제조국 등 일부 고시 항목이 ''상세설명참조''로만 표기되어 있어 구체적인 원산지 정보는 상세페이지 확인이 필요하며, 수집된 리뷰 데이터가 없어 실사용자 평가는 확인되지 않았습니다.', '{"브랜드":"더블에이","하위유형":"용지/복사용지","색상":null,"사이즈":"A4 (210mm x 297mm)","소재":"종이","용량중량":"80g","수량입수":"2500매(1BOX, 500매x5팩)","심굵기":"해당없음","필기구색상수":"해당없음","캐릭터테마":null,"용도":"사무용","제조국":null,"구성세트여부":"벌크/대용량","인쇄커스텀가능여부":"기본형","판매구성":null,"태그":null}', '더블에이(Double A) A4 80g 복사용지로, 500매 낱장 팩 5개가 모인 1BOX(총 2500매) 구성의 대용량 사무용 복사지입니다. 규격은 A4(210mm x 297mm)이며 복사기, 팩스, 잉크젯 및 레이저프린터에 모두 사용 가능하고 양면 인쇄를 지원합니다. 사무실 상비용품이나 대량 인쇄, 가정용 프린터, 학교·학원 인쇄물 등에 적합하며, 우수한 백색도와 매끄러운 표면으로 선명한 인쇄 품질을 제공하는 것이 특징입니다. 다만 상품 등록 정보에 브랜드/제조국 등 일부 고시 항목이 ''상세설명참조''로만 표기되어 있어 구체적인 원산지 정보는 상세페이지 확인이 필요하며, 수집된 리뷰 데이터가 없어 실사용자 평가는 확인되지 않았습니다.', 'ON_SALE', NOW(), NOW()),
(9381716646, (SELECT id FROM brand WHERE name = 'LG전자' LIMIT 1), (SELECT id FROM category WHERE name = '모니터 > TV 모니터' LIMIT 1), 'LG전자 27U411A 모니터 케이제이샵', 188000, 188000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9381716646/B.webp?146410789', 0, 'LG전자 27U411A는 27인치(67~78cm) FHD(1920x1080) 해상도의 IPS 패널 평면 모니터로, 120Hz 주사율과 HDR10을 지원해 사무·재택근무는 물론 가벼운 게임용으로도 활용할 수 있다. 블랙 톤의 슬림 베젤과 미니멀한 스탠드형 받침대로 깔끔한 인상을 주며, 제조국은 중국이고 에너지소비효율등급은 해당없음 항목으로 표기되어 있다. 다만 해당 상품은 수집된 리뷰 데이터가 없어 실사용자의 구체적인 장단점 평가는 확인되지 않았다.', '{"화면크기":"27~31인치","해상도":"FHD(1920x1080)","브랜드":"LG전자","제품유형":"PC모니터","패널타입":"IPS","화면주사율":"120Hz","곡률":"평면","튜너내장여부":null,"에너지소비효율등급":"해당없음","제조국":"중국","정격전압":"100-240 Vac, 50/60 Hz","소비전력":"9W","크기(가로x세로x깊이)":"스탠드 포함 시 4.2kg / 스탠드 제외 시 611.6 x 357.7 x 37.5mm","중량":"4.2kg (스탠드 포함)","스탠드거치방식":"스탠드형","연결단자":["HDMI"],"스피커내장여부":null,"HDR지원":"HDR10","색상":"블랙","모델명":"27U411A","KC인증정보":"R-R-LGE-27U411A (전자파 적합등록)","AS책임자및전화번호":"1544-7777","품질보증기준":"결함·하자 등에 따른 소비자피해에 대해서는 소비자 분쟁해결기준(소비자기본법 제 16조)에 따라 보상 가능","동일모델출시년월":"2025-08","구성품":null}', 'LG전자 27U411A는 27인치(67~78cm) FHD(1920x1080) 해상도의 IPS 패널 평면 모니터로, 120Hz 주사율과 HDR10을 지원해 사무·재택근무는 물론 가벼운 게임용으로도 활용할 수 있다. 블랙 톤의 슬림 베젤과 미니멀한 스탠드형 받침대로 깔끔한 인상을 주며, 제조국은 중국이고 에너지소비효율등급은 해당없음 항목으로 표기되어 있다. 다만 해당 상품은 수집된 리뷰 데이터가 없어 실사용자의 구체적인 장단점 평가는 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9399484206, (SELECT id FROM brand WHERE name = 'Generalidea' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 남성의류 > 니트/스웨터' LIMIT 1), '(매장정품)GENERALIDEA 에어리 에센셜 하프 가디건 [PINK] / WBD2L04527WBD2L04527PI', 42500, 42500, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/pd/v2/4/8/4/2/0/6/xGQXF/9399484206_B.webp', 0, '브랜드 남성의류 니트/스웨터 카테고리의 GENERALIDEA 에어리 에센셜 하프 가디건으로, 브이넥에 반팔 소매를 갖춘 핑크 컬러 크롭 니트 카디건이다. S/M/L 사이즈로 운영되며 현재 L 사이즈는 품절이고 M·S는 구매 가능한 일부품절 상태다. 목선에는 블랙 스트링 리본 디테일과 우드톤 단추 4개가 포인트를 주고, 왼쪽 가슴 로고 자수와 리브 밑단·커프 마감으로 슬림한 크롭 실루엣을 완성해 봄여름 데일리룩이나 오피스 캐주얼, 데이트룩에 포인트 아이템으로 활용하기 좋다. 정가 대비 26% 할인된 가격에 판매 중이나, 소재·제조국·세탁방법 등 상세 고시 정보는 상품상세페이지 참조로만 표기되어 있어 구매 전 실제 소재 구성과 사이즈를 꼼꼼히 확인할 필요가 있고, 현재 수집된 리뷰 데이터가 없어 실착 후기를 통한 검증은 어렵다는 점이 아쉬운 부분이다.', '{"색상":["핑크"],"사이즈":["S","M","L"],"소재":null,"넥라인":"브이넥","소매기장":"반팔","핏":"슬림핏","성별":"남성","브랜드":"Generalidea","제조국":null,"세탁방법":null,"제조자수입자":null,"모델명":"WBD2L04527PI","할인율":"26%","품절여부":"일부품절"}', '브랜드 남성의류 니트/스웨터 카테고리의 GENERALIDEA 에어리 에센셜 하프 가디건으로, 브이넥에 반팔 소매를 갖춘 핑크 컬러 크롭 니트 카디건이다. S/M/L 사이즈로 운영되며 현재 L 사이즈는 품절이고 M·S는 구매 가능한 일부품절 상태다. 목선에는 블랙 스트링 리본 디테일과 우드톤 단추 4개가 포인트를 주고, 왼쪽 가슴 로고 자수와 리브 밑단·커프 마감으로 슬림한 크롭 실루엣을 완성해 봄여름 데일리룩이나 오피스 캐주얼, 데이트룩에 포인트 아이템으로 활용하기 좋다. 정가 대비 26% 할인된 가격에 판매 중이나, 소재·제조국·세탁방법 등 상세 고시 정보는 상품상세페이지 참조로만 표기되어 있어 구매 전 실제 소재 구성과 사이즈를 꼼꼼히 확인할 필요가 있고, 현재 수집된 리뷰 데이터가 없어 실착 후기를 통한 검증은 어렵다는 점이 아쉬운 부분이다.', 'ON_SALE', NOW(), NOW()),
(9406970347, (SELECT id FROM brand WHERE name = '핀버튼 키링' LIMIT 1), (SELECT id FROM category WHERE name = '패션잡화 > 브로치' LIMIT 1), 'DIY 재료 메탈 핀버튼 키링 제작 원형 58MM 100개입', 62300, 51630, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9406970347/B.webp?895818430', 0, '58mm 원형 메탈 핀버튼 키링 제작용 DIY 재료 100개입 세트로, 인쇄면이 없는 무지 은색 금속 소재이며 뒷면 배지핀과 키링 체인·연결고리가 함께 구성되어 있어 원하는 이미지를 인쇄해 배지나 키링으로 자유롭게 완성할 수 있다. 공방·동아리 굿즈, 단체 기념품, 이벤트용 대량 제작에 적합한 공용 DIY 소재이며, 제조국·품명·A/S 정보 등 상세 고시 항목은 모두 상세페이지 참조로 안내되어 있어 구매 전 반드시 상세 설명을 확인해야 하고, 수집된 리뷰가 없어 실사용 후기 기반의 장단점은 확인되지 않는다.', '{"색상":"실버","디자인모티브":null,"소재":"메탈/합금","부착방식":"배지핀(버튼형)","사이즈":"58mm","판매단위":"대량(50개+)","용도":["DIY 제작재료","굿즈/이벤트용"],"성별":"공용","브랜드":"핀버튼 키링","제조국":"상세설명참조","인증허가사항":"상세페이지 참조","품명및모델명":"상세페이지 참조","제조자수입자":"상세페이지 참조","AS책임자연락처":"상세페이지 참조"}', '58mm 원형 메탈 핀버튼 키링 제작용 DIY 재료 100개입 세트로, 인쇄면이 없는 무지 은색 금속 소재이며 뒷면 배지핀과 키링 체인·연결고리가 함께 구성되어 있어 원하는 이미지를 인쇄해 배지나 키링으로 자유롭게 완성할 수 있다. 공방·동아리 굿즈, 단체 기념품, 이벤트용 대량 제작에 적합한 공용 DIY 소재이며, 제조국·품명·A/S 정보 등 상세 고시 항목은 모두 상세페이지 참조로 안내되어 있어 구매 전 반드시 상세 설명을 확인해야 하고, 수집된 리뷰가 없어 실사용 후기 기반의 장단점은 확인되지 않는다.', 'ON_SALE', NOW(), NOW()),
(9407131239, (SELECT id FROM brand WHERE name = '11번가 판매자 76151342' LIMIT 1), (SELECT id FROM category WHERE name = '거실가구 > 테이블' LIMIT 1), '노트북 테이블 높이조절 스탠딩 침대테이블 리프트업 사이드테이블 다용도 작업대', 406800, 333580, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9407131239/B.jpg?189205195', 0, '거실가구 테이블 카테고리의 리프트업테이블로, 화이트·월넛·실버·블랙 등 상판/프레임 색상 조합을 옵션으로 선택할 수 있는 높이조절형 사이드테이블입니다. 상판 크기는 옵션에 따라 약 47~65 x 48~70cm, 전체 높이는 100~108cm 범위이며 가스 리프트로 높낮이를, 상판 각도를 3단계로 조절할 수 있어 침대 옆이나 소파 옆에서 노트북 작업, 독서, 재택근무용 스탠딩 데스크로 활용하기 좋습니다. 무소음 캐스터가 달려 있어 좁은 공간에서도 자유롭게 이동시킬 수 있고, 상판 하단 수납 트레이와 펜꽂이로 소품 정리도 가능합니다. 다만 해외 구매대행 상품으로 국내 재고를 보유하지 않아 배송 기간이 길어질 수 있고, 상품 크기·중량 조건에 따라 화물택배로 전환되어 착불 배송비가 추가로 발생할 수 있다는 점은 구매 전 유의해야 합니다.', '{"테이블유형":"리프트업테이블","색상":["화이트","월넛","실버","블랙"],"사이즈":"상판 47~65 x 48~70cm, 전체 높이 100~108cm (옵션별 상이)","소재":"혼합소재","상판재질":"MDF","높이조절여부":"높이조절가능","접이식여부":"이동식","브랜드":null,"제조국":null,"구성품":null,"조립여부":null,"스타일":"모던","형태":"사각형","KC인증정보":null,"품질보증기준":null,"배송설치비용":"가로+세로+높이 합 160cm 이상, 중량 20kg 초과, 한 변 100cm 이상 등 조건 해당 시 화물택배로 이관되어 착불 배송비 발생 가능","옵션태그":["JT 01","JT 02","JT 05","호두패널 블랙알루미늄홀더","화이트 패널 화이트 올 알루미늄 홀더","호두 패널 실버 올 알루미늄 거치대","09D 핸드 리프트 맞춤 일주일","09C 1 핸드 리프트 맞춤 일주일"]}', '거실가구 테이블 카테고리의 리프트업테이블로, 화이트·월넛·실버·블랙 등 상판/프레임 색상 조합을 옵션으로 선택할 수 있는 높이조절형 사이드테이블입니다. 상판 크기는 옵션에 따라 약 47~65 x 48~70cm, 전체 높이는 100~108cm 범위이며 가스 리프트로 높낮이를, 상판 각도를 3단계로 조절할 수 있어 침대 옆이나 소파 옆에서 노트북 작업, 독서, 재택근무용 스탠딩 데스크로 활용하기 좋습니다. 무소음 캐스터가 달려 있어 좁은 공간에서도 자유롭게 이동시킬 수 있고, 상판 하단 수납 트레이와 펜꽂이로 소품 정리도 가능합니다. 다만 해외 구매대행 상품으로 국내 재고를 보유하지 않아 배송 기간이 길어질 수 있고, 상품 크기·중량 조건에 따라 화물택배로 전환되어 착불 배송비가 추가로 발생할 수 있다는 점은 구매 전 유의해야 합니다.', 'ON_SALE', NOW(), NOW())
