(9418301489, (SELECT id FROM brand WHERE name = '밸런스56' LIMIT 1), (SELECT id FROM category WHERE name = '남성의류 > 조끼/베스트' LIMIT 1), '아이스팩 얼음조끼 냉감 통풍 망사 쿨조끼 여름 등산 배달 택배 작업용', 18900, 17900, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/dl/v2/3/0/1/4/8/9/JZsqW/9418301489_235166538.webp', 0, '블루 컬러 폴리에스터 메쉬 소재의 남성용 여름 아이스팩 얼음조끼(냉감 쿨조끼)로, 라운드넥 민소매에 전면 4개·후면 4개 총 8개의 아이스팩 전용 벨크로 포켓이 있어 아이스팩(별도구매)을 넣어 야외작업현장, 더운 주방, 배달/퀵, 등산/레저, 운전 시 졸음 및 더위 예방용으로 착용하는 다용도 냉감 작업복이다. 촘촘한 다이아몬드 메쉬 원단으로 통풍이 잘 되고 가벼우며 사이즈는 67x61cm 단일 규격, 색상은 블루 단일 옵션만 제공된다. 수집된 리뷰 데이터가 없어 실사용자 평가 기반 장단점은 확인되지 않았다.', '{"색상":["블루"],"사이즈":null,"소재":"폴리에스터","핏":null,"넥라인":"라운드넥","용도스타일":["등산/아웃도어","작업복","배달/퀵","다용도수납(멀티포켓)"],"성별":"남성","브랜드":"밸런스56","제조국":"중국","세탁방법":null,"계절감":"여름","포켓구성":"8포켓(앞면 4개, 뒷면 4개) 아이스팩 전용 벨크로 수납 포켓, 아이스팩은 별도 구매"}', '블루 컬러 폴리에스터 메쉬 소재의 남성용 여름 아이스팩 얼음조끼(냉감 쿨조끼)로, 라운드넥 민소매에 전면 4개·후면 4개 총 8개의 아이스팩 전용 벨크로 포켓이 있어 아이스팩(별도구매)을 넣어 야외작업현장, 더운 주방, 배달/퀵, 등산/레저, 운전 시 졸음 및 더위 예방용으로 착용하는 다용도 냉감 작업복이다. 촘촘한 다이아몬드 메쉬 원단으로 통풍이 잘 되고 가벼우며 사이즈는 67x61cm 단일 규격, 색상은 블루 단일 옵션만 제공된다. 수집된 리뷰 데이터가 없어 실사용자 평가 기반 장단점은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9420646927, (SELECT id FROM brand WHERE name = '현대농산' LIMIT 1), (SELECT id FROM category WHERE name = '곡물 > 잡곡/혼합곡' LIMIT 1), '균형 혼합 18곡 4kg (2kgX2봉) 잡곡', 10100, 9390, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9420646927/B.webp?681624082', 0, '현대농산 균형혼합18곡 4kg(2kg x 2봉) 잡곡은 국내산 현미·찹쌀·발아현미·보리류와 미국산 밀쌀·늘보리·기장·수수, 호주산 병아리콩, 캐나다산 완두콩 등 18가지 곡물을 균형 있게 배합한 혼합곡으로, 백미에 7:3 비율로 섞어 30분 정도 불린 뒤 밥을 지으면 되는 간편한 밥용 잡곡이다. 스탠드형 지퍼백 파우치 2봉으로 소포장되어 있어 보관과 사용이 편리하며, 잡곡밥을 자주 해 먹는 가정이나 매번 여러 잡곡을 따로 섞는 번거로움을 줄이고 싶은 소비자, 명절 선물용으로도 적합하다. 실제 후기에서는 곡물이 골고루 섞여 맛이 좋고 지퍼백 소포장이 편리하며 배송이 빠르고 가격이 합리적이라는 긍정 평가가 확인되나, 개봉 후 빠르게 소비하고 밀폐용기에 담아 냉장 보관해야 하며 포장지 상단의 통기용 타공으로 인해 미개봉 상태에서도 변질될 수 있다는 점은 주의가 필요하다.', '{"곡물종류":"혼합곡","중량":null,"원산지구분":null,"원산지국가":"국내외(현미/찹쌀/보리 등 국내산, 밀쌀/보리 미국산, 병아리콩 호주산, 완두콩 캐나다산)","브랜드":"현대농산","가공형태":null,"포장형태":"파우치","포장수량구성":"2kg x 2봉","혼합곡가짓수":"18곡","수확연도":"2025년산","GMO여부":"해당없음","보관방법":"냉장보관","용도":["밥용"],"옵션구성":{"axes":["선택"],"esm_mode":"single_axis","items":[{"label":"균형 혼합 18곡 4kg (2kgX2봉) 잡곡","add_price":0,"stock_qty":98262}]}}', '현대농산 균형혼합18곡 4kg(2kg x 2봉) 잡곡은 국내산 현미·찹쌀·발아현미·보리류와 미국산 밀쌀·늘보리·기장·수수, 호주산 병아리콩, 캐나다산 완두콩 등 18가지 곡물을 균형 있게 배합한 혼합곡으로, 백미에 7:3 비율로 섞어 30분 정도 불린 뒤 밥을 지으면 되는 간편한 밥용 잡곡이다. 스탠드형 지퍼백 파우치 2봉으로 소포장되어 있어 보관과 사용이 편리하며, 잡곡밥을 자주 해 먹는 가정이나 매번 여러 잡곡을 따로 섞는 번거로움을 줄이고 싶은 소비자, 명절 선물용으로도 적합하다. 실제 후기에서는 곡물이 골고루 섞여 맛이 좋고 지퍼백 소포장이 편리하며 배송이 빠르고 가격이 합리적이라는 긍정 평가가 확인되나, 개봉 후 빠르게 소비하고 밀폐용기에 담아 냉장 보관해야 하며 포장지 상단의 통기용 타공으로 인해 미개봉 상태에서도 변질될 수 있다는 점은 주의가 필요하다.', 'ON_SALE', NOW(), NOW()),
(9427228771, (SELECT id FROM brand WHERE name = '키플링' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 여성가방 > 숄더백' LIMIT 1), '[매장정품] 키플링 숄더백 크로스백 타이스 KMABT26 3종 택1', 73900, 73900, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/pd/v2/2/2/8/7/7/1/QHDKB/9427228771_B.webp', 0, '키플링 숄더백 크로스백 타이스로, 여성용 인조가죽(레더룩) 소재의 호보형 숄더백이다. 전면에 스터드 버튼 플랩 포켓이 있고 탈부착 가능한 링 고리 숄더스트랩과 매듭 장식 참이 포인트이며, 출근룩·데일리룩에 어울리는 미니멀한 디자인이다. 상세페이지에는 블랙, 머스타드, 네이비 3가지 색상 스와치가 노출되나 실제 옵션 코드(mypb, snpb)가 어떤 색상에 대응하는지 상품 정보에 명시되어 있지 않아 색상·사이즈·제조국 등 상세 스펙은 상품상세페이지 참조로만 안내되어 있고, 현재 수집된 리뷰가 없어 실사용 장단점은 확인되지 않는다.', '{"브랜드":"키플링","색상":null,"사이즈":null,"소재":["인조가죽"],"가방형태":"숄더백","스트랩타입":"탈부착스트랩","개폐방식":null,"제조국":null,"세탁방법":null,"제조자수입자":null,"품질보증기준":null,"AS책임자":null,"성별":"여성","시즌":null,"판매상태":"판매중"}', '키플링 숄더백 크로스백 타이스로, 여성용 인조가죽(레더룩) 소재의 호보형 숄더백이다. 전면에 스터드 버튼 플랩 포켓이 있고 탈부착 가능한 링 고리 숄더스트랩과 매듭 장식 참이 포인트이며, 출근룩·데일리룩에 어울리는 미니멀한 디자인이다. 상세페이지에는 블랙, 머스타드, 네이비 3가지 색상 스와치가 노출되나 실제 옵션 코드(mypb, snpb)가 어떤 색상에 대응하는지 상품 정보에 명시되어 있지 않아 색상·사이즈·제조국 등 상세 스펙은 상품상세페이지 참조로만 안내되어 있고, 현재 수집된 리뷰가 없어 실사용 장단점은 확인되지 않는다.', 'ON_SALE', NOW(), NOW()),
(9428730756, (SELECT id FROM brand WHERE name = '마키타' LIMIT 1), (SELECT id FROM category WHERE name = '공구 > 전동공구' LIMIT 1), '배터리 BL1850B 18v x 5.0 리튬이온 마끼다 공구 전동공구 전동드릴 임팩트렌치 임팩드라이버 전동해머', 236700, 234340, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9428730756/B.webp?879109524', 0, '마키타(Makita) 정품 호환 18V 5.0Ah 리튬이온 배터리 BL1850B로, 충전식(배터리) 전원방식의 전동공구용 예비 배터리를 찾는 사용자에게 적합하다. 블랙 바디에 옐로우 포인트의 충전 단자, 잔량 확인용 LED 인디케이터가 특징이며 상세페이지에는 급속 충전 시스템과 배터리 보호회로, 내구성을 강조하는 인포그래픽과 용량별(1.5Ah~6.0Ah) 호환성 비교표가 제공된다. 다만 제조국과 KC인증 여부, 제조자/수입자 정보가 상세설명 참조로만 표기되어 상세페이지를 직접 확인해야 하며, 수집된 리뷰 데이터가 없어 실사용자 평가는 확인되지 않는다.', '{"브랜드":"마키타","상품유형":null,"전원방식":"충전식(배터리)","전압":"18V","구성형태":null,"색상":"블랙","세트구성수량":null,"규격사이즈":"18V 5.0Ah","모델명":"BL1850B","제조국":"상세설명참조","제조자수입자":null,"KC인증정보":"상세설명참조","AS정보":null,"용도":[],"소재":null,"옵션구성":null,"모음전여부":"단일상품"}', '마키타(Makita) 정품 호환 18V 5.0Ah 리튬이온 배터리 BL1850B로, 충전식(배터리) 전원방식의 전동공구용 예비 배터리를 찾는 사용자에게 적합하다. 블랙 바디에 옐로우 포인트의 충전 단자, 잔량 확인용 LED 인디케이터가 특징이며 상세페이지에는 급속 충전 시스템과 배터리 보호회로, 내구성을 강조하는 인포그래픽과 용량별(1.5Ah~6.0Ah) 호환성 비교표가 제공된다. 다만 제조국과 KC인증 여부, 제조자/수입자 정보가 상세설명 참조로만 표기되어 상세페이지를 직접 확인해야 하며, 수집된 리뷰 데이터가 없어 실사용자 평가는 확인되지 않는다.', 'ON_SALE', NOW(), NOW()),
(9429202578, (SELECT id FROM brand WHERE name = 'Conquer dream' LIMIT 1), (SELECT id FROM category WHERE name = '남성의류 > 점퍼' LIMIT 1), 'JEEP SPIRIT 남성 여름 자외선차단 후드 바람막이 경량 자켓', 73500, 73000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/dl/v2/2/0/2/5/7/8/nMYhH/9429202578_235137141.webp', 0, 'JEEP SPIRIT 남성 여름 자외선차단 후드 바람막이로, 폴리에스터(스판덱스 혼방) 소재의 레귤러핏 바람막이점퍼다. 카키그레이·네이비그레이 투톤 컬러블록 디자인에 후드 조임끈, 전면 지퍼 여밈, 양쪽 사선 지퍼 포켓, 소매/밑단 밴딩 마감을 갖췄고 옆구리 통기 펀칭 홀로 여름철 방풍·UV차단·경량 착용감을 강조한다. 사이즈는 XL~5XL까지 구성되어 있다. 캠핑·야외활동, 드라이브·여행, 등산·하이킹, 야외스포츠, 여행 사진 촬영 등 아웃도어 상황에 적합한 캐주얼 자켓이며, 현재 수집된 리뷰 데이터가 없어 실사용 장단점은 확인되지 않았다.', '{"색상":["카키","네이비"],"사이즈":["XL","2XL","3XL","4XL","5XL"],"점퍼종류":"바람막이점퍼","소재":"폴리에스터","핏":"레귤러핏","넥라인":"후드","여밈방식":"집업(지퍼)","충전재":"없음","기능성":["방풍","UV차단","경량"],"SPF지수":null,"성별":"남성","브랜드":"Conquer dream","제조국":null,"세탁방법":null,"계절감":"여름","제조자수입자":null,"품질보증기준":null,"AS책임자연락처":null,"KC인증정보":null,"제조연월":null,"모음전여부":"옵션상품"}', 'JEEP SPIRIT 남성 여름 자외선차단 후드 바람막이로, 폴리에스터(스판덱스 혼방) 소재의 레귤러핏 바람막이점퍼다. 카키그레이·네이비그레이 투톤 컬러블록 디자인에 후드 조임끈, 전면 지퍼 여밈, 양쪽 사선 지퍼 포켓, 소매/밑단 밴딩 마감을 갖췄고 옆구리 통기 펀칭 홀로 여름철 방풍·UV차단·경량 착용감을 강조한다. 사이즈는 XL~5XL까지 구성되어 있다. 캠핑·야외활동, 드라이브·여행, 등산·하이킹, 야외스포츠, 여행 사진 촬영 등 아웃도어 상황에 적합한 캐주얼 자켓이며, 현재 수집된 리뷰 데이터가 없어 실사용 장단점은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9429359597, (SELECT id FROM brand WHERE name = '해리네점빵수입' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 잡화/소품 > 머플러' LIMIT 1), '응원 반다나 페이즐리 손수건 3컬러 스포츠 등산 단체복', 1470, 1310, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9429359597/B.webp?984460461', 0, '해리네점빵수입의 응원 반다나 페이즐리 손수건으로 레드, 카키, 그린 3가지 컬러 중 선택 가능하며 테두리 물방울 패턴과 중앙 대형 페이즐리 문양이 대비되는 디자인이다. 헤어밴드, 목 스카프, 손목 밴드 등 다양하게 연출할 수 있어 등산이나 단체 응원, 유니폼용으로 활용하기 좋고 저렴한 가격에 여러 장 구성해 단체복으로 맞추기도 편하다. 다만 상품고시에 소재·치수·제조국 등 상세 정보가 ''상세설명참조''로만 표기되어 있어 실제 원단 두께나 정확한 사이즈, 세탁 방법을 구매 전 파악하기 어렵다는 점은 아쉽다.', '{"색상":["레드","카키","그린"],"사이즈":null,"종류":"반다나","소재":null,"브랜드":"해리네점빵수입","제조국":null,"세탁방법":null,"구성수량":null,"패턴":"페이즐리","성별":"공용","사용목적":["패션","단체복/유니폼","스포츠/등산"]}', '해리네점빵수입의 응원 반다나 페이즐리 손수건으로 레드, 카키, 그린 3가지 컬러 중 선택 가능하며 테두리 물방울 패턴과 중앙 대형 페이즐리 문양이 대비되는 디자인이다. 헤어밴드, 목 스카프, 손목 밴드 등 다양하게 연출할 수 있어 등산이나 단체 응원, 유니폼용으로 활용하기 좋고 저렴한 가격에 여러 장 구성해 단체복으로 맞추기도 편하다. 다만 상품고시에 소재·치수·제조국 등 상세 정보가 ''상세설명참조''로만 표기되어 있어 실제 원단 두께나 정확한 사이즈, 세탁 방법을 구매 전 파악하기 어렵다는 점은 아쉽다.', 'ON_SALE', NOW(), NOW()),
