(9434440907, (SELECT id FROM brand WHERE name = '혼마' LIMIT 1), (SELECT id FROM category WHERE name = '골프 > 골프클럽' LIMIT 1), '[혼마]혼마 26년 SX-002 파크골프채 ( 4스타 )정품', 1873600, 1742450, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9434440907/B.webp?797127761', 0, '혼마(HONMA) 브랜드의 파크골프채로, 모델명 SX-002, 2026년(26년) 신제품, 4스타 등급의 정품 단품 구성이다. 골드 톤 헤드에 블랙 테두리, HONMA 로고와 별 4개 각인, TWIN WEIGHT 시스템 표기가 특징이며 우드톤 샤프트와 퀄팅 패턴의 전용 헤드커버가 함께 제공되어 고급스러운 외관을 갖췄다. 파크골프를 즐기는 이용객이나 선물용으로 적합하며, 안정감 있는 스트레이트 라인 설계와 와이드 스윗스팟을 강조하는 상세페이지 설명이 확인된다. 다만 색상, 사이즈, 샤프트 강도, 소재 등 세부 규격은 상품고시에 ''상세페이지 참조''로만 표기되어 있어 구매 전 정확한 스펙 확인이 필요하고, 수집된 리뷰 데이터가 없어 실사용자 평가 기반의 장단점은 파악되지 않는다.', '{"클럽종류":"파크골프채","골프종류":"파크골프","브랜드":"혼마","성별":null,"색상":null,"사이즈":null,"샤프트강도":null,"손잡이방향":null,"소재":null,"세트구성":"단품","모델명":"SX-002","출시년도":"2026","제조국":"일본","KC인증정보":null,"품질보증기준":null,"정품여부":"정품","가격대":null}', '혼마(HONMA) 브랜드의 파크골프채로, 모델명 SX-002, 2026년(26년) 신제품, 4스타 등급의 정품 단품 구성이다. 골드 톤 헤드에 블랙 테두리, HONMA 로고와 별 4개 각인, TWIN WEIGHT 시스템 표기가 특징이며 우드톤 샤프트와 퀄팅 패턴의 전용 헤드커버가 함께 제공되어 고급스러운 외관을 갖췄다. 파크골프를 즐기는 이용객이나 선물용으로 적합하며, 안정감 있는 스트레이트 라인 설계와 와이드 스윗스팟을 강조하는 상세페이지 설명이 확인된다. 다만 색상, 사이즈, 샤프트 강도, 소재 등 세부 규격은 상품고시에 ''상세페이지 참조''로만 표기되어 있어 구매 전 정확한 스펙 확인이 필요하고, 수집된 리뷰 데이터가 없어 실사용자 평가 기반의 장단점은 파악되지 않는다.', 'ON_SALE', NOW(), NOW()),
(9434825492, (SELECT id FROM brand WHERE name = 'LG전자' LIMIT 1), (SELECT id FROM category WHERE name = '모니터 > 일반 모니터' LIMIT 1), 'LG전자 27U411A 68~69cm', 190000, 180120, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9434825492/B.webp?35312502', 0, 'LG전자 27U411A는 27인치(68.5cm) FHD(1920x1080) 해상도의 IPS 패널 평면형 일반 모니터로, 16:9 화면비에 HDR10을 지원하며 D-Sub와 HDMI2.0 단자를 갖추고 틸트 조절과 VESA 마운트(100x100mm)를 지원하는 무광 블랙 색상의 슬림한 사각 스탠드 디자인이다. 스피커는 내장되어 있지 않고 AMD FreeSync·NVIDIA G-SYNC 등 가변주사율 기술은 지원하지 않는 일반 사무용·홈오피스용 모니터로, sRGB 99% 색영역을 갖춰 포토샵 등 기본적인 색보정·그래픽 작업에도 활용할 수 있다. 제조국은 중국이며 LG전자 정품 온라인 스토어를 통해 판매되고 LG전자 서비스센터(1544-7777)에서 정식 A/S를 받을 수 있다. 리뷰 데이터가 수집되지 않아 실사용 장단점은 확인되지 않았다.', '{"브랜드":"LG전자","화면크기":"27인치","해상도":"FHD(1920x1080)","패널타입":"IPS","주사율":"120Hz","용도":null,"곡률":"평면(플랫)","화면비율":"16:9","스피커내장여부":"미내장","HDR지원":"HDR10","가변주사율기술":"미지원","무결점등급":null,"색상":"블랙","모델명":"27U411A","제조국":"중국","에너지소비효율등급":"상세페이지참조","정격전압소비전력":"100-240Vac, 50/60Hz / 소비전력(On mode) 9W, Sleep 0.5W이하, DC Off 0.3W이하","크기무게":"611.6 x 458.2 x 220 mm(스탠드 포함) / 611.6 x 357.7 x 37.5 mm(스탠드 제외), 무게 4.2kg(스탠드 포함)/3.3kg(스탠드 제외)","동일모델출시년월":"2025년 8월","품질보증기준":"결함·하자 등에 따른 소비자피해에 대해서는 소비자분쟁해결기준(소비자기본법 제16조)에 따라 보상 가능","AS책임자전화번호":"LG전자 서비스센터 / 1544-7777","KC인증정보":"R-R-LGE-27U411A(전자파적합등록)","연결단자":["HDMI","VGA(D-SUB)"],"스탠드기능":["틸트","VESA마운트"],"옵션구성":null}', 'LG전자 27U411A는 27인치(68.5cm) FHD(1920x1080) 해상도의 IPS 패널 평면형 일반 모니터로, 16:9 화면비에 HDR10을 지원하며 D-Sub와 HDMI2.0 단자를 갖추고 틸트 조절과 VESA 마운트(100x100mm)를 지원하는 무광 블랙 색상의 슬림한 사각 스탠드 디자인이다. 스피커는 내장되어 있지 않고 AMD FreeSync·NVIDIA G-SYNC 등 가변주사율 기술은 지원하지 않는 일반 사무용·홈오피스용 모니터로, sRGB 99% 색영역을 갖춰 포토샵 등 기본적인 색보정·그래픽 작업에도 활용할 수 있다. 제조국은 중국이며 LG전자 정품 온라인 스토어를 통해 판매되고 LG전자 서비스센터(1544-7777)에서 정식 A/S를 받을 수 있다. 리뷰 데이터가 수집되지 않아 실사용 장단점은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9443665466, (SELECT id FROM brand WHERE name = '슈즈팩토리' LIMIT 1), (SELECT id FROM category WHERE name = '남성신발 > 스니커즈' LIMIT 1), '콤파니 키높이 남성 독일군 스니커즈 펀칭 캐주얼화 국산 단화 운동화 남자신발', 37800, 36800, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9443665466/B.webp?608598975', 0, '남성 캐주얼 스니커즈로 화이트/베이지 톤의 펀칭 메쉬 갑피에 블랙 또는 카키 컬러의 사이드 스트라이프와 스웨이드 포인트가 더해진 독일군 스니커즈(저먼 트레이너) 스타일 단화이다. 레이스업(끈) 여밈에 두툼한 화이트 컵솔을 적용했으며, 키높이 밑창 설계로 자연스러운 신장 보정 효과를 노린 제품이다. 브랜드는 슈즈팩토리이며 국산(한국 제조)으로 표기되어 있으나, 상품고시에는 색상·치수·소재 등 상세 정보가 ''상품상세설명 참조''로만 안내되어 있어 실제 옵션별 색상/사이즈 구성과 소재 배합은 상세페이지 확인이 필요하다. 가벼운 산책이나 데일리 캐주얼룩에 어울리는 라이프스타일 스니커즈로, 현재 수집된 데이터 기준으로는 리뷰가 없어 실사용 만족도나 사이즈감, 내구성 등에 대한 구매자 피드백은 확인되지 않았다.', '{"색상":null,"사이즈":null,"브랜드":"슈즈팩토리","제조국":"한국","소재":"메쉬","스타일":"캐주얼","여밈방식":"레이스업(끈)","굽높이유형":"키높이","방수여부":null,"성별":"남성","빅사이즈여부":null,"미끄럼방지":[]}', '남성 캐주얼 스니커즈로 화이트/베이지 톤의 펀칭 메쉬 갑피에 블랙 또는 카키 컬러의 사이드 스트라이프와 스웨이드 포인트가 더해진 독일군 스니커즈(저먼 트레이너) 스타일 단화이다. 레이스업(끈) 여밈에 두툼한 화이트 컵솔을 적용했으며, 키높이 밑창 설계로 자연스러운 신장 보정 효과를 노린 제품이다. 브랜드는 슈즈팩토리이며 국산(한국 제조)으로 표기되어 있으나, 상품고시에는 색상·치수·소재 등 상세 정보가 ''상품상세설명 참조''로만 안내되어 있어 실제 옵션별 색상/사이즈 구성과 소재 배합은 상세페이지 확인이 필요하다. 가벼운 산책이나 데일리 캐주얼룩에 어울리는 라이프스타일 스니커즈로, 현재 수집된 데이터 기준으로는 리뷰가 없어 실사용 만족도나 사이즈감, 내구성 등에 대한 구매자 피드백은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9446314995, (SELECT id FROM brand WHERE name = '11번가 판매자 70553898' LIMIT 1), (SELECT id FROM category WHERE name = '낚시 > 낚싯대' LIMIT 1), '원터치 민물 낚시 미끼 밑밥 붕어 중층 내림 바닥', 8380, 7970, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9446314995/B.jpg?599964645', 0, '민물 중층내림낚시에서 떡밥과 옥수수 등 서로 다른 미끼를 한 통에 깔끔하게 나눠 담을 수 있는 흰색 PP 재질의 2구 분리형 원터치 미끼그릇이다. 칸마다 독립된 힌지 뚜껑이 있어 한 손으로 톡 열고 닫을 수 있고 먼지와 벌레, 흙으로부터 미끼를 보호해 붕어 대상 노지·좌대 낚시에서 미끼 교체 시간을 단축해준다. 가로13cm x 세로11.5cm x 높이5.2cm의 휴대하기 좋은 크기이며 중국산 제조로 브랜드 표기는 없다. 수집된 리뷰가 없어 실사용자의 장단점 평가는 확인되지 않았다.', '{"낚싯대종류":null,"사용방식":null,"사용수역":"민물","대상어종":["붕어"],"길이":null,"절수":null,"액션(경도)":null,"릴시트타입":"해당없음","색상":"화이트","소재":"합성수지","브랜드":"기타","제조국":"중국","세트구성":null,"모델명":"원터치 떡밥그릇","옵션구성":null,"KC인증정보":null,"AS책임자":null}', '민물 중층내림낚시에서 떡밥과 옥수수 등 서로 다른 미끼를 한 통에 깔끔하게 나눠 담을 수 있는 흰색 PP 재질의 2구 분리형 원터치 미끼그릇이다. 칸마다 독립된 힌지 뚜껑이 있어 한 손으로 톡 열고 닫을 수 있고 먼지와 벌레, 흙으로부터 미끼를 보호해 붕어 대상 노지·좌대 낚시에서 미끼 교체 시간을 단축해준다. 가로13cm x 세로11.5cm x 높이5.2cm의 휴대하기 좋은 크기이며 중국산 제조로 브랜드 표기는 없다. 수집된 리뷰가 없어 실사용자의 장단점 평가는 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9449999488, (SELECT id FROM brand WHERE name = '11번가 판매자 75581613' LIMIT 1), (SELECT id FROM category WHERE name = '기저귀 > 일회용기저귀' LIMIT 1), '디펜드 A플러스 일자형 30매 6P 시니어 속기저귀', 64350, 63710, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9449999488/B.webp?229241897', 0, '디펜드 A+ 에이플러스 일자형 속기저귀 30매 6팩(총 180매) 구성의 성인용 흡수패드로, 제품 사이즈 20x53cm에 흡수량 450ml의 빠른 흡수력을 갖춰 시니어 요양 및 실금 케어, 특히 누워 지내는 시간이 많은 분에게 적합하다. 겉기저귀(팬티형·밴드형)와 함께 사용하는 속기저귀 타입으로 옆 샘 방지 설계가 특징이며, 통기성을 강조한 소재로 장시간 착용 시 편안함을 고려했다. 다만 해당 상품은 판매 페이지 고시정보에 제조국·제조자 등 상세정보가 ''상품상세정보에 별도표기''로만 안내되어 있어 정확한 원산지와 제조사 확인이 어렵고, 수집된 리뷰가 없어 실사용자의 흡수력·착용감에 대한 검증된 후기는 확인되지 않는다.', '{"브랜드":"기타","기저귀타입":"속기저귀","사이즈":null,"단계":null,"사용연령":null,"체중범위":null,"매수":"30매 6P","팩수":"6팩","세트구성":"묶음/조합","색상":null,"소재":null,"제조국":null,"제조사수입자":null,"중량":null,"KC인증정보":null,"특징태그":["흡수력강화","통기성"],"사은품여부":"사은품없음","판매상태":"판매중"}', '디펜드 A+ 에이플러스 일자형 속기저귀 30매 6팩(총 180매) 구성의 성인용 흡수패드로, 제품 사이즈 20x53cm에 흡수량 450ml의 빠른 흡수력을 갖춰 시니어 요양 및 실금 케어, 특히 누워 지내는 시간이 많은 분에게 적합하다. 겉기저귀(팬티형·밴드형)와 함께 사용하는 속기저귀 타입으로 옆 샘 방지 설계가 특징이며, 통기성을 강조한 소재로 장시간 착용 시 편안함을 고려했다. 다만 해당 상품은 판매 페이지 고시정보에 제조국·제조자 등 상세정보가 ''상품상세정보에 별도표기''로만 안내되어 있어 정확한 원산지와 제조사 확인이 어렵고, 수집된 리뷰가 없어 실사용자의 흡수력·착용감에 대한 검증된 후기는 확인되지 않는다.', 'ON_SALE', NOW(), NOW()),
(9455286006, (SELECT id FROM brand WHERE name = 'Conquer dream' LIMIT 1), (SELECT id FROM category WHERE name = '남성의류 > 셔츠/남방' LIMIT 1), 'JEEP SPIRIT 남성 여름 반팔 워크셔츠 밀리터리 캐주얼 포켓 셔츠', 62000, 62000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9455286006/B.webp?777291535', 0, 'JEEP SPIRIT 남성 여름 반팔 워크셔츠로, 밀리터리 캐주얼 감성의 무지(솔리드) 포켓 셔츠다. 가슴 양쪽에 뚜껑 달린 플랩 포켓과 어깨 견장 디테일, 가죽풍 브랜드 패치가 특징이며 각진 셔츠칼라와 반팔 소매, 밑단 사이드 슬릿으로 활동성과 캐주얼한 아웃도어 무드를 살렸다. 색상은 베이지, 네이비, 카키그린 3가지가 제공되며 여름철 캐주얼룩이나 야외활동, 워크웨어 스타일링에 적합하다. 리뷰 데이터가 수집되지 않아 실사용자 평가는 확인되지 않았고, 제품 상세페이지에 소재·치수·제조국 등 상품고시 정보가 ''상품상세설명 참조''로만 표기되어 구체적인 원단 성분과 정확한 실측 사이즈를 상세페이지에서 추가로 확인해야 한다는 점은 구매 시 유의할 부분이다.', '{"색상":["베이지","네이비","카키"],"사이즈":null,"패턴":"솔리드(무지)","소재":null,"핏":null,"소매기장":"반팔","넥라인":"셔츠칼라","스타일":"작업복","브랜드":"Conquer dream","제조국":null,"세탁방법":null,"제조연월":null,"품질보증기준":null,"AS책임자및전화번호":null,"제조자수입자":null,"모델명":null,"성별":"남성","옵션구성":{"axes":["색상","사이즈"],"items":[]},"제품태그":["밀리터리","워크셔츠","포켓셔츠","캐주얼","여름"]}', 'JEEP SPIRIT 남성 여름 반팔 워크셔츠로, 밀리터리 캐주얼 감성의 무지(솔리드) 포켓 셔츠다. 가슴 양쪽에 뚜껑 달린 플랩 포켓과 어깨 견장 디테일, 가죽풍 브랜드 패치가 특징이며 각진 셔츠칼라와 반팔 소매, 밑단 사이드 슬릿으로 활동성과 캐주얼한 아웃도어 무드를 살렸다. 색상은 베이지, 네이비, 카키그린 3가지가 제공되며 여름철 캐주얼룩이나 야외활동, 워크웨어 스타일링에 적합하다. 리뷰 데이터가 수집되지 않아 실사용자 평가는 확인되지 않았고, 제품 상세페이지에 소재·치수·제조국 등 상품고시 정보가 ''상품상세설명 참조''로만 표기되어 구체적인 원단 성분과 정확한 실측 사이즈를 상세페이지에서 추가로 확인해야 한다는 점은 구매 시 유의할 부분이다.', 'ON_SALE', NOW(), NOW()),
(9463511551, (SELECT id FROM brand WHERE name = '가니' LIMIT 1), (SELECT id FROM category WHERE name = '수입명품 > 여성의류' LIMIT 1), '[GANNI] A1050030 151 여성 반팔티', 159000, 130230, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9463511551/B.webp?95098088', 0, '가니(GANNI) 화이트 컬러의 여성용 코튼 반팔 티셔츠로, 블랙 배색 립 카라와 소매단이 포인트인 레귤러 라운드넥 핏이다. 가슴에는 레드 컬러의 아치형 GANNI 칼리지 로고와 레드 리본을 목에 두른 그레이톤 새끼 고양이 일러스트, 그 아래 ''Have a nice day!'' 문구가 프린트되어 있어 캐주얼하면서도 위트 있는 무드를 연출한다. 브랜드국은 덴마크, 제조국은 포르투갈이며 병행수입 상품이다. 옵션은 S/XS 사이즈로 구성되어 있으나 S 사이즈는 품절 상태이고 XS만 재고가 남아 있어 사이즈 선택 폭이 매우 제한적이라는 점은 단점으로 꼽힌다. 데일리룩이나 캐주얼한 주말 코디에 매치하기 좋은 여름용 반팔 아이템이다.', '{"브랜드":"가니","색상":"화이트","사이즈":["S","XS"],"소재":["코튼"],"충전재":null,"제조국":"포르투갈","세탁방법":null,"품목":"블라우스/셔츠","핏":null,"넥라인":"라운드넥","소매기장":"반팔","성별":"여성","시즌":"여름","정품감정옵션":null,"모델번호":"A1050030 151"}', '가니(GANNI) 화이트 컬러의 여성용 코튼 반팔 티셔츠로, 블랙 배색 립 카라와 소매단이 포인트인 레귤러 라운드넥 핏이다. 가슴에는 레드 컬러의 아치형 GANNI 칼리지 로고와 레드 리본을 목에 두른 그레이톤 새끼 고양이 일러스트, 그 아래 ''Have a nice day!'' 문구가 프린트되어 있어 캐주얼하면서도 위트 있는 무드를 연출한다. 브랜드국은 덴마크, 제조국은 포르투갈이며 병행수입 상품이다. 옵션은 S/XS 사이즈로 구성되어 있으나 S 사이즈는 품절 상태이고 XS만 재고가 남아 있어 사이즈 선택 폭이 매우 제한적이라는 점은 단점으로 꼽힌다. 데일리룩이나 캐주얼한 주말 코디에 매치하기 좋은 여름용 반팔 아이템이다.', 'ON_SALE', NOW(), NOW()),
(9465702884, (SELECT id FROM brand WHERE name = '파스쿠찌' LIMIT 1), (SELECT id FROM category WHERE name = 'e쿠폰/상품권 > 카페/음료' LIMIT 1), '파스쿠찌 파스쿠찌 모바일금액권 5만원권 (잔액관리형)', 50000, 40000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/dl/v2/7/0/2/8/8/4/RqgQY/9465702884_235099902.webp', 0, '파스쿠찌 모바일 금액권 5만원권(잔액관리형)은 정가 5만원 상품을 20% 할인된 4만원에 구매할 수 있는 e쿠폰/상품권 카테고리의 금액형 기프티콘으로, 기프티콘사가 발행처이며 SK플래닛(주) 신용으로 지급보증 없이 발행된다. 유효기간은 93일이며 프로모션 상품 특성상 기간 연장이 불가하고, 만료 전에는 100% 환불, 만료 후에는 90% 환불이 가능해 생일이나 답례 선물용으로 부담 없이 활용하기 좋다. 카드 디자인은 PASCUCCI와 아티스트 MULGA의 협업 일러스트로, 선글라스와 콧수염 캐릭터 위에 아이스크림 스쿱이 담긴 양동이 그래픽과 큼직한 금액 표기가 특징이다. 실제 구매 후기에서는 할인가로 저렴하게 구매했다는 점, 선물 받은 사람이 만족했다는 점, 발급(배송)이 빠르다는 점, 박물관 강의처럼 외부 일정 중 인근 파스쿠찌 매장에서 편리하게 사용한다는 실사용 경험이 긍정적으로 언급된다. 다만 본 상품은 SMS로 발송되지 않고 11번가 앱의 e쿠폰함에서만 확인·사용해야 하므로 ', '{"브랜드":"파스쿠찌","상품유형":"금액권","권종금액":"50000원","잔액관리형여부":"잔액관리형","발행처":"기프티콘","교환상품명":null,"유효기간":"93일 (프로모션 상품으로 기간연장 불가, 만료 후 90% 환불)","사용가능매장":null,"환불조건":{"만료전":"구매가격 기준 100% 환불(11번가 APP 직접 신청)","만료후":"90% 환불(온라인 고객센터)","부분사용시":"표시금액의 60%(1만원 이하는 80%) 이상 사용 시 잔액에 대해 유효기간 경과 전까지 환불 요청 가능, 경과 시 잔액의 90% 환불"},"배송형태":null,"할인율":"20%","구성수량":null,"옵션":null,"고객상담전화번호":"1800-0133(유료)"}', '파스쿠찌 모바일 금액권 5만원권(잔액관리형)은 정가 5만원 상품을 20% 할인된 4만원에 구매할 수 있는 e쿠폰/상품권 카테고리의 금액형 기프티콘으로, 기프티콘사가 발행처이며 SK플래닛(주) 신용으로 지급보증 없이 발행된다. 유효기간은 93일이며 프로모션 상품 특성상 기간 연장이 불가하고, 만료 전에는 100% 환불, 만료 후에는 90% 환불이 가능해 생일이나 답례 선물용으로 부담 없이 활용하기 좋다. 카드 디자인은 PASCUCCI와 아티스트 MULGA의 협업 일러스트로, 선글라스와 콧수염 캐릭터 위에 아이스크림 스쿱이 담긴 양동이 그래픽과 큼직한 금액 표기가 특징이다. 실제 구매 후기에서는 할인가로 저렴하게 구매했다는 점, 선물 받은 사람이 만족했다는 점, 발급(배송)이 빠르다는 점, 박물관 강의처럼 외부 일정 중 인근 파스쿠찌 매장에서 편리하게 사용한다는 실사용 경험이 긍정적으로 언급된다. 다만 본 상품은 SMS로 발송되지 않고 11번가 앱의 e쿠폰함에서만 확인·사용해야 하므로 문자 발송 상품으로 오인하면 혼동될 수 있고, 이용 가능 매장 안내가 상세 페이지의 별도 고시 정보를 확인해야 하는 등 사용 전 확인 절차가 다소 번거로울 수 있다.', 'ON_SALE', NOW(), NOW()),
