(9468979902, (SELECT id FROM brand WHERE name = 'exponeta' LIMIT 1), (SELECT id FROM category WHERE name = '여성가방 > 비치백' LIMIT 1), '메쉬 비치백 대형 DD-12845비치가방 수영복가방 메쉬백 메쉬비치백 물놀이가', 14700, 14560, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9468979902/B.webp?324430057', 0, '블랙 메쉬 소재의 대형 토트형 비치백으로, 가로 40cm x 세로 36cm x 폭 22cm의 넉넉한 용량과 그물 형태의 시스루 디자인이 특징이다. 이중 손잡이로 어깨에 메기 편하며, 전면에 슬리퍼·휴대폰·선글라스·선크림 등을 꽂을 수 있는 다수의 외부 포켓과 지퍼 없는 와이드 오픈 입구를 갖춰 해수욕장, 수영장, 여름 바캉스 물놀이 짐을 한 번에 담아 다니기 좋다. 폴리에스터(메쉬) 소재라 모래나 물기에 강하고 통기성이 좋지만, 원단이 그물망이라 작은 소지품이 비쳐 보이는 개방형 구조이며 방수 기능은 별도로 명시되어 있지 않아 완전한 방수를 기대하기는 어렵다. 리뷰 데이터가 수집되지 않아 실사용 만족도나 내구성에 대한 구매자 평가는 확인되지 않았다.', '{"색상":"블랙","사이즈":"대","형태":"토트백","소재":"폴리에스터","무늬":"무지","방수여부":null,"포켓개수":"4-7개","용도":["수영장","바닷가","물놀이","바캉스"],"브랜드":"exponeta","제조국":"중국","제조자수입자":null,"품명모델명":"메쉬 비치백","세탁방법":null,"품질보증기준":null,"성별":"여성","손잡이형태":"이중손잡이"}', '블랙 메쉬 소재의 대형 토트형 비치백으로, 가로 40cm x 세로 36cm x 폭 22cm의 넉넉한 용량과 그물 형태의 시스루 디자인이 특징이다. 이중 손잡이로 어깨에 메기 편하며, 전면에 슬리퍼·휴대폰·선글라스·선크림 등을 꽂을 수 있는 다수의 외부 포켓과 지퍼 없는 와이드 오픈 입구를 갖춰 해수욕장, 수영장, 여름 바캉스 물놀이 짐을 한 번에 담아 다니기 좋다. 폴리에스터(메쉬) 소재라 모래나 물기에 강하고 통기성이 좋지만, 원단이 그물망이라 작은 소지품이 비쳐 보이는 개방형 구조이며 방수 기능은 별도로 명시되어 있지 않아 완전한 방수를 기대하기는 어렵다. 리뷰 데이터가 수집되지 않아 실사용 만족도나 내구성에 대한 구매자 평가는 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9470141344, (SELECT id FROM brand WHERE name = '11번가 판매자 76431407' LIMIT 1), (SELECT id FROM category WHERE name = '문구/사무용품 > 문구용품' LIMIT 1), '산도깨비 에어컨세정제 330ml 곰팡이제거제', 5110, 5110, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9470141344/B.webp?291391446', 0, '산도깨비 에어컨세정제 330ml 곰팡이제거제는 벽걸이형 에어컨 실내기·실외기 필터에 분사해 먼지와 곰팡이 냄새를 제거하는 생활화학 세정 스프레이로, 트리거 노즐이 달려 있어 손쉽게 원하는 부위에 분사할 수 있고 상세페이지에는 분사 전후 필터 비교컷과 문 닫기-분사-방치-환기의 4단계 사용법 인포그래픽, 안전확인대상 생활화학제품 표시사항 및 화학물질 확인결과서가 함께 제공되어 여름철 에어컨 위생 관리와 실외기 청소, 곰팡이 냄새 제거 용도로 사용하기 적합하다. 제품 이미지에는 동일 제품 2개가 나란히 놓여 있어 세트 구성으로 판매되는 것으로 보이며, 수집된 리뷰 데이터가 없어 실사용 만족도나 세정력·잔향 등에 대한 장단점은 확인되지 않았다는 한계가 있다.', '{"브랜드":"기타","하위유형":"사무용품(기타)","색상":null,"사이즈":null,"소재":null,"용량중량":"330ml","수량입수":"2개","심굵기":"해당없음","필기구색상수":"해당없음","캐릭터테마":null,"용도":"기타","제조국":null,"구성세트여부":"세트","인쇄커스텀가능여부":null,"판매구성":null,"태그":["에어컨세정제","곰팡이제거제"]}', '산도깨비 에어컨세정제 330ml 곰팡이제거제는 벽걸이형 에어컨 실내기·실외기 필터에 분사해 먼지와 곰팡이 냄새를 제거하는 생활화학 세정 스프레이로, 트리거 노즐이 달려 있어 손쉽게 원하는 부위에 분사할 수 있고 상세페이지에는 분사 전후 필터 비교컷과 문 닫기-분사-방치-환기의 4단계 사용법 인포그래픽, 안전확인대상 생활화학제품 표시사항 및 화학물질 확인결과서가 함께 제공되어 여름철 에어컨 위생 관리와 실외기 청소, 곰팡이 냄새 제거 용도로 사용하기 적합하다. 제품 이미지에는 동일 제품 2개가 나란히 놓여 있어 세트 구성으로 판매되는 것으로 보이며, 수집된 리뷰 데이터가 없어 실사용 만족도나 세정력·잔향 등에 대한 장단점은 확인되지 않았다는 한계가 있다.', 'ON_SALE', NOW(), NOW()),
(9470438123, (SELECT id FROM brand WHERE name = '화신' LIMIT 1), (SELECT id FROM category WHERE name = '공구 > 절삭공구' LIMIT 1), '다목적 만능 화신 P-220 가위', 14730, 14730, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9470438123/B.jpg?665434586', 0, '화신 P-220 다목적 만능 가위는 빨간색 플라스틱 손잡이와 검정 코팅 스틸 블레이드로 구성된 수동식 절삭공구로, 손잡이 끝의 와이어 잠금 고리로 미사용시 날을 고정할 수 있고 미끄럼 방지 그립이 적용되어 있다. 별도 전원이나 배터리 없이 사용하는 휴대용 다용도 가위로 원예·전지 작업, 포장끈이나 노끈 절단 등 가정 및 작업현장에서 다목적으로 활용할 수 있다. 다만 제조국·A/S 책임자·인증정보 등 상품고시 항목이 상세설명 참조로만 표기되어 있어 구매 전 상세페이지에서 추가 확인이 필요하며, 수집된 리뷰가 없어 실제 사용자 평가나 내구성·절삭력에 대한 검증된 후기는 확인되지 않는다.', '{"브랜드":"화신","제조국":null,"세부유형":"가위","동력방식":"수동","전압":"해당없음","정격전력":null,"배터리포함여부":"해당없음","날크기":null,"적용소재":["다목적"],"구성품":null,"중량":null,"색상":"레드","사이즈":null,"안전인증":["해당없음/확인필요"],"AS책임자":null,"품질보증기준":null,"모델명":"P-220","판매구성":"단일상품"}', '화신 P-220 다목적 만능 가위는 빨간색 플라스틱 손잡이와 검정 코팅 스틸 블레이드로 구성된 수동식 절삭공구로, 손잡이 끝의 와이어 잠금 고리로 미사용시 날을 고정할 수 있고 미끄럼 방지 그립이 적용되어 있다. 별도 전원이나 배터리 없이 사용하는 휴대용 다용도 가위로 원예·전지 작업, 포장끈이나 노끈 절단 등 가정 및 작업현장에서 다목적으로 활용할 수 있다. 다만 제조국·A/S 책임자·인증정보 등 상품고시 항목이 상세설명 참조로만 표기되어 있어 구매 전 상세페이지에서 추가 확인이 필요하며, 수집된 리뷰가 없어 실제 사용자 평가나 내구성·절삭력에 대한 검증된 후기는 확인되지 않는다.', 'ON_SALE', NOW(), NOW()),
(9470646527, (SELECT id FROM brand WHERE name = '삼성전자' LIMIT 1), (SELECT id FROM category WHERE name = '모니터 > 일반 모니터' LIMIT 1), '삼성전자 오디세이 G5 G55C S32CG550 80cm(32인치) IPS 165Hz QHD 게이밍 모니터 LS32CG550EKXKR', 323000, 323000, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9470646527/B.webp?576217130', 0, '삼성전자 오디세이 G5(S32CG550, LS32CG550EKXKR)는 32~33인치대 QHD(2560x1440) 해상도의 IPS 패널을 탑재한 1000R 커브드 게이밍 모니터로, 165Hz 주사율과 AMD FreeSync 가변주사율, HDR10을 지원해 빠른 전환이 많은 FPS·경쟁 게임과 몰입감 있는 영화 감상에 적합하다. 무광 블랙 톤에 얇은 베젤과 X자형 스탠드로 깔끔한 데스크 셋업을 완성하며, HDMI·DisplayPort·DVI·D-Sub 등 다양한 연결단자와 VESA 마운트를 지원해 확장성도 갖췄다. 다만 현재 수집된 리뷰 데이터가 없어 실제 사용자 만족도나 구체적인 단점(예: 스탠드 높이조절 불가, 색보정 이슈 등)은 확인되지 않았다.', '{"브랜드":"삼성전자","화면크기":"32~33인치","해상도":"QHD(2560x1440)","패널타입":"IPS","주사율":"165Hz","용도":"게이밍","곡률":"커브드","화면비율":"16:9","스피커내장여부":null,"HDR지원":"HDR10","가변주사율기술":"AMD FreeSync","무결점등급":null,"색상":"블랙","모델명":"LS32CG550EKXKR (오디세이 G5 S32CG550)","제조국":null,"에너지소비효율등급":null,"정격전압소비전력":null,"크기무게":null,"동일모델출시년월":null,"품질보증기준":null,"AS책임자전화번호":null,"KC인증정보":null,"연결단자":["HDMI","DisplayPort","DVI","VGA(D-SUB)"],"스탠드기능":["VESA마운트"],"옵션구성":null}', '삼성전자 오디세이 G5(S32CG550, LS32CG550EKXKR)는 32~33인치대 QHD(2560x1440) 해상도의 IPS 패널을 탑재한 1000R 커브드 게이밍 모니터로, 165Hz 주사율과 AMD FreeSync 가변주사율, HDR10을 지원해 빠른 전환이 많은 FPS·경쟁 게임과 몰입감 있는 영화 감상에 적합하다. 무광 블랙 톤에 얇은 베젤과 X자형 스탠드로 깔끔한 데스크 셋업을 완성하며, HDMI·DisplayPort·DVI·D-Sub 등 다양한 연결단자와 VESA 마운트를 지원해 확장성도 갖췄다. 다만 현재 수집된 리뷰 데이터가 없어 실제 사용자 만족도나 구체적인 단점(예: 스탠드 높이조절 불가, 색보정 이슈 등)은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9474920548, (SELECT id FROM brand WHERE name = '몽블랑' LIMIT 1), (SELECT id FROM category WHERE name = '지갑/벨트 > 여성벨트' LIMIT 1), '몽블랑 6S 114412 홀스슈 리버서블 레더 벨트 블랙 브라운', 411500, 360930, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9474920548/B.webp?986362902', 0, '몽블랑 6S 114412 홀스슈 리버서블 레더 벨트로, 블랙과 브라운 양면을 뒤집어 사용할 수 있는 캐주얼벨트이며 프리사이즈(OS) 단일 옵션으로 제공된다. 은색 사각 프레임의 핀 버클을 사용하고 표면은 무지 패턴의 매끈한 가죽 질감으로, 그레이 셔츠와 블랙 슬랙스 등 비즈니스 캐주얼 룩에 두루 매치하기 좋아 데일리 착용이나 선물용으로 적합하다. 다만 상세페이지에 소재·제조국 등 구체 정보가 별도표기로만 안내되어 있고 수집된 리뷰가 없어 실착용 장단점은 확인되지 않았다.', '{"색상":["블랙","브라운"],"사이즈":"프리사이즈","폭":null,"소재":null,"스타일":"캐주얼벨트","버클타입":"일반(핀)버클","패턴":"무지","성별":"남녀공용","브랜드":"몽블랑","제조국":null,"용도":["캐주얼용"],"세탁방법":null}', '몽블랑 6S 114412 홀스슈 리버서블 레더 벨트로, 블랙과 브라운 양면을 뒤집어 사용할 수 있는 캐주얼벨트이며 프리사이즈(OS) 단일 옵션으로 제공된다. 은색 사각 프레임의 핀 버클을 사용하고 표면은 무지 패턴의 매끈한 가죽 질감으로, 그레이 셔츠와 블랙 슬랙스 등 비즈니스 캐주얼 룩에 두루 매치하기 좋아 데일리 착용이나 선물용으로 적합하다. 다만 상세페이지에 소재·제조국 등 구체 정보가 별도표기로만 안내되어 있고 수집된 리뷰가 없어 실착용 장단점은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9475376971, (SELECT id FROM brand WHERE name = 'K2 Safety' LIMIT 1), (SELECT id FROM category WHERE name = '여성가방 > 파우치' LIMIT 1), '안전벨트 등산 배낭 휴대폰 소지품 수납 용품 다목적 파우치', 22160, 19730, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9475376971/B.webp?365734338', 0, 'K2 Safety 베이직 파우치(모델명 IUA21907)는 블랙 색상의 폴리에스터 소재 다목적 파우치로, 가로 10cm x 세로 4.5cm x 높이 19cm의 세로형 사이즈이다. 지퍼로 여닫는 메인 수납공간과 별도 지퍼가 달린 전면 메쉬 보조 포켓 두 개를 갖춰 휴대폰과 소지품을 나누어 수납하기 좋고, 상단 카라비너 고리와 후면 벨크로 밴드로 등산 배낭이나 안전벨트, 멜빵고리에 탈부착하여 휴대하기 편리하다. 무지 패턴의 심플한 디자인으로 등산, 배낭용, 벨트 착용 등 다양한 상황에 다용도로 활용할 수 있다. 리뷰 데이터가 수집되지 않아 실사용 장단점은 확인되지 않았다.', '{"색상":"블랙","사이즈":null,"치수":"가로 10cm x 세로 4.5cm x 높이 19cm","종류":"파우치","용도":["휴대용","다용도수납"],"소재":"폴리에스터","잠금방식":"지퍼","스트랩유무":"탈부착가능","패턴":"무지","브랜드":"K2 Safety","제조국":null,"세탁방법":null,"구성수량":"1개","성별":"공용"}', 'K2 Safety 베이직 파우치(모델명 IUA21907)는 블랙 색상의 폴리에스터 소재 다목적 파우치로, 가로 10cm x 세로 4.5cm x 높이 19cm의 세로형 사이즈이다. 지퍼로 여닫는 메인 수납공간과 별도 지퍼가 달린 전면 메쉬 보조 포켓 두 개를 갖춰 휴대폰과 소지품을 나누어 수납하기 좋고, 상단 카라비너 고리와 후면 벨크로 밴드로 등산 배낭이나 안전벨트, 멜빵고리에 탈부착하여 휴대하기 편리하다. 무지 패턴의 심플한 디자인으로 등산, 배낭용, 벨트 착용 등 다양한 상황에 다용도로 활용할 수 있다. 리뷰 데이터가 수집되지 않아 실사용 장단점은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9475930875, (SELECT id FROM brand WHERE name = '이미스' LIMIT 1), (SELECT id FROM category WHERE name = '여성가방 > 클러치백' LIMIT 1), '이미스 PAISLEY 미니 POUCH-네이비', 35600, 35600, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/pd/v2/9/3/0/8/7/5/GuSBP/9475930875_B.webp', 0, '이미스(emis)에서 나온 네이비 컬러의 페이즐리 패턴 미니 파우치형 클러치백으로, 상단 은색 지퍼로 여미고 탈부착 가능한 리스트릿 손잡이가 달려 있어 짧은 외출이나 데일리하게 손에 들기 좋은 사이즈이다. 5만원 미만의 가격대로 부담 없이 구매할 수 있으며 현재 재고가 있는 상태이다. 다만 상품고시에 소재, 제조국, 세탁관리방법 등 상세 정보가 ''상세페이지 참조''로만 표기되어 있어 구매 전 실측 사이즈나 소재 정보를 추가로 확인할 필요가 있고, 등록된 리뷰가 없어 실제 사용자 평가나 내구성, 마감 품질에 대한 근거는 아직 확인되지 않는다.', '{"브랜드":"이미스","색상":["네이비"],"사이즈":null,"실측사이즈":null,"소재":null,"세부종류":"파우치","패턴":null,"개폐방식":"지퍼","휴대방식":"리스트릿포함","성별":"여성","스타일태그":[],"제조국":null,"모델명":"m10371718775","품질보증기준":null,"세탁관리방법":null,"AS책임자및전화번호":null,"가격대":"5만원미만","재고상태":"재고있음"}', '이미스(emis)에서 나온 네이비 컬러의 페이즐리 패턴 미니 파우치형 클러치백으로, 상단 은색 지퍼로 여미고 탈부착 가능한 리스트릿 손잡이가 달려 있어 짧은 외출이나 데일리하게 손에 들기 좋은 사이즈이다. 5만원 미만의 가격대로 부담 없이 구매할 수 있으며 현재 재고가 있는 상태이다. 다만 상품고시에 소재, 제조국, 세탁관리방법 등 상세 정보가 ''상세페이지 참조''로만 표기되어 있어 구매 전 실측 사이즈나 소재 정보를 추가로 확인할 필요가 있고, 등록된 리뷰가 없어 실제 사용자 평가나 내구성, 마감 품질에 대한 근거는 아직 확인되지 않는다.', 'ON_SALE', NOW(), NOW()),
(9476771114, (SELECT id FROM brand WHERE name = '지벤' LIMIT 1), (SELECT id FROM category WHERE name = '남성신발 > 기능화' LIMIT 1), '지벤 천연소가죽 메쉬 다이얼 현장안전화 ZB171S', 184340, 184240, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9476771114/B.webp?282581726', 0, '지벤 ZB171S는 남성용 안전화/작업화로, 천연소가죽과 메쉬 소재를 조합한 네이비 색상의 갑피에 BOA 다이얼 시스템을 적용해 끈 없이 빠르게 조일 수 있는 현장안전화이다. 240mm부터 290mm까지 다양한 사이즈로 구성되어 있으며, SYMPATEX 방수시트 안감을 적용해 방수 기능을 갖췄고 지그재그 반사 스티치와 보강된 토캡 디자인으로 시인성과 내구성을 함께 고려했다. 건설현장이나 작업 현장에서 착용하기 적합한 제품이며, 현재 확보된 리뷰 데이터가 없어 실사용자 만족도나 구체적인 단점은 확인되지 않았다.', '{"색상":"네이비","사이즈":["240","245","250","255","260","265","270","275","280","285","290"],"기능화용도":"안전화/작업화","소재":"소가죽","성별":"남성","브랜드":"지벤","제조국":"기타","안전인증":null,"밑창기능":["방수"],"잠금방식":"다이얼(보아시스템)","굽높이":null,"중량":null,"관리방법":null,"품질보증기준":null,"제조자수입자":null,"AS책임자":null}', '지벤 ZB171S는 남성용 안전화/작업화로, 천연소가죽과 메쉬 소재를 조합한 네이비 색상의 갑피에 BOA 다이얼 시스템을 적용해 끈 없이 빠르게 조일 수 있는 현장안전화이다. 240mm부터 290mm까지 다양한 사이즈로 구성되어 있으며, SYMPATEX 방수시트 안감을 적용해 방수 기능을 갖췄고 지그재그 반사 스티치와 보강된 토캡 디자인으로 시인성과 내구성을 함께 고려했다. 건설현장이나 작업 현장에서 착용하기 적합한 제품이며, 현재 확보된 리뷰 데이터가 없어 실사용자 만족도나 구체적인 단점은 확인되지 않았다.', 'ON_SALE', NOW(), NOW()),
(9478751477, (SELECT id FROM brand WHERE name = '지샥(G-SHOCK)' LIMIT 1), (SELECT id FROM category WHERE name = '브랜드 시계 > 브랜드 남성시계' LIMIT 1), '[지샥] GA-2100-1A1DR 지얄오크 올블랙 방수 전자시계', 150150, 142350, 100, 'https://cdn.011st.com/11dims/resize/792x792/quality/75/11src/product/9478751477/B.webp?62822463', 0, '카시오 지샥(G-SHOCK) GA-2100-1A1DR 지얄오크 올블랙 남성용 전자시계로, 무광 블랙 컬러의 팔각형 카본 코어 가드 케이스에 레진(실리콘) 밴드를 채용한 아날로그+디지털 콤비네이션 디스플레이 패션시계이다. 케이스 사이즈는 48.5×45.4×11.8mm, 중량 51g이며 20기압 방수와 스톱워치·알람·충격방지 기능을 갖춰 캐주얼룩이나 스트릿 코디, 야외활동, 일상 착용에 두루 어울린다. 일본에서 제조되며 지코스모 정품 보증서가 제공되어 전국 카시오 공식 서비스센터에서 A/S를 받을 수 있다는 점이 장점이다. 다만 리뷰 데이터가 수집되지 않아 실제 착용 만족도나 구체적인 단점은 확인되지 않았다.', '{"브랜드":"지샥(G-SHOCK)","시계종류":"패션시계","성별":"남성","무브먼트":"쿼츠","디스플레이타입":"아날로그+디지털(콤비네이션)","밴드재질":"실리콘/레진","케이스재질":"카본","색상":["블랙"],"케이스사이즈":"48.5 × 45.4 × 11.8mm","방수등급":"20기압","기능":["스톱워치","알람","충격방지"],"제조국":"일본","보증서제공여부":"Y","중량":"51g","세트구성":null}', '카시오 지샥(G-SHOCK) GA-2100-1A1DR 지얄오크 올블랙 남성용 전자시계로, 무광 블랙 컬러의 팔각형 카본 코어 가드 케이스에 레진(실리콘) 밴드를 채용한 아날로그+디지털 콤비네이션 디스플레이 패션시계이다. 케이스 사이즈는 48.5×45.4×11.8mm, 중량 51g이며 20기압 방수와 스톱워치·알람·충격방지 기능을 갖춰 캐주얼룩이나 스트릿 코디, 야외활동, 일상 착용에 두루 어울린다. 일본에서 제조되며 지코스모 정품 보증서가 제공되어 전국 카시오 공식 서비스센터에서 A/S를 받을 수 있다는 점이 장점이다. 다만 리뷰 데이터가 수집되지 않아 실제 착용 만족도나 구체적인 단점은 확인되지 않았다.', 'ON_SALE', NOW(), NOW())
